    def test_serializers_financeiros_nao_acessam_relacoes_por_lazy_load_direto(self):
        raiz_caixa = Path(__file__).resolve().parent
        padrao_relacao_direta = re.compile(
            r"\.("
            r"cliente|evento|contrato_operacional|divida|credor_cadastro|"
            r"receita_operacional|despesa_operacional|custo_fixo|"
            r"pagamento_custo_servico|pagamento_custo_extra|"
            r"pagamento_parcela_divida|investimento|"
            r"financiamento_movimentacao|divida_financeira|obrigacao|alocacoes"
            r")\b",
        )
        padrao_getattr_relacao_direta = re.compile(
            r"getattr\([^,\n]+,\s*['\"]("
            r"cliente|evento|contrato_operacional|divida|credor_cadastro|"
            r"receita_operacional|despesa_operacional|custo_fixo|"
            r"pagamento_custo_servico|pagamento_custo_extra|"
            r"pagamento_parcela_divida|investimento|"
            r"financiamento_movimentacao|divida_financeira|obrigacao|alocacoes"
            r")['\"]"
        )
        violacoes = []

        for arquivo in raiz_caixa.glob("serializers_*.py"):
            for numero_linha, linha in enumerate(
                arquivo.read_text(encoding="utf-8").splitlines(),
                start=1,
            ):
                for relacao in padrao_relacao_direta.finditer(linha):
                    violacoes.append(
                        f"{arquivo.name}:{numero_linha}:{relacao.group(0)}"
                    )
                for relacao in padrao_getattr_relacao_direta.finditer(linha):
                    violacoes.append(
                        f"{arquivo.name}:{numero_linha}:getattr({relacao.group(1)})"
                    )

        self.assertEqual(
            violacoes,
            [],
            "Use relacao_carregada/select_related para publicar campos de relacoes.",
        )

