        despesa = DespesaOperacional.objects.create(
            evento=evento,
            descricao="Despesa montador sem lazy",
            categoria="outros",
            valor_previsto=Decimal("20.00"),
            data_vencimento=date(2026, 5, 6),
        )
        divida = DividaFinanceira.objects.create(
            descricao="Divida montador sem lazy",
            credor="Banco Montador",
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 5),
            valor_contratado=Decimal("50.00"),
            quantidade_parcelas=1,
        )
        parcela = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 7),
            data_vencimento_atual=date(2026, 5, 7),
            valor_principal=Decimal("50.00"),
        )

        receita_sem_relacoes = ReceitaOperacional.objects.get(pk=receita.pk)
        despesa_sem_relacoes = DespesaOperacional.objects.get(pk=despesa.pk)
        parcela_sem_relacoes = ParcelaDivida.objects.get(pk=parcela.pk)
        receita_com_relacoes = ReceitaOperacional.objects.select_related(
            "cliente",
            "evento",
        ).get(pk=receita.pk)
        despesa_com_relacoes = DespesaOperacional.objects.select_related(
            "evento",
        ).get(pk=despesa.pk)
        parcela_com_relacoes = ParcelaDivida.objects.select_related("divida").get(
            pk=parcela.pk,
        )

        with CaptureQueriesContext(connection) as queries_sem_relacoes:
            movimento_receita = montar_movimento_receita_mes(receita_sem_relacoes)
            conta_despesa = montar_conta_despesa_mes(despesa_sem_relacoes)
            conta_parcela = montar_conta_parcela_mes(parcela_sem_relacoes)
            contexto_dashboard = montar_movimentacoes_dashboard(
                [receita_sem_relacoes],
                [despesa_sem_relacoes],
                [],
                [],
                [parcela_sem_relacoes],
            )

        with CaptureQueriesContext(connection) as queries_com_relacoes:
            movimento_receita_com_relacoes = montar_movimento_receita_mes(
                receita_com_relacoes,
            )
            conta_despesa_com_relacoes = montar_conta_despesa_mes(
                despesa_com_relacoes,
            )
            conta_parcela_com_relacoes = montar_conta_parcela_mes(
                parcela_com_relacoes,
            )

        self.assertEqual(len(queries_sem_relacoes), 0)
        self.assertEqual(movimento_receita["referencia"], "")
        self.assertEqual(conta_despesa["referencia"], "")
        self.assertEqual(conta_parcela["descricao"], "")
        self.assertEqual(conta_parcela["referencia"], "Parcela 1/1")
        self.assertEqual(contexto_dashboard["movimentacoes"][0]["referencia"], "")
        self.assertEqual(contexto_dashboard["movimentacoes"][1]["referencia"], "")
        self.assertEqual(contexto_dashboard["movimentacoes"][2]["referencia"], "Parcela 1/1")
        self.assertEqual(len(queries_com_relacoes), 0)
        self.assertEqual(
            movimento_receita_com_relacoes["referencia"],
            "Cliente Montador Sem Lazy / Evento Montador Sem Lazy",
        )
        self.assertEqual(
            conta_despesa_com_relacoes["referencia"],
            "Evento Montador Sem Lazy",
        )
        self.assertEqual(
            conta_parcela_com_relacoes["descricao"],
            "Divida montador sem lazy",
        )
        self.assertEqual(
            conta_parcela_com_relacoes["referencia"],
            "Banco Montador / Parcela 1/1",
        )

