    def test_resumo_financeiro_mes_calcula_saldos_e_falta_cobrir(self):
        resumo = calcular_resumo_financeiro_mes(
            {
                "receita_prevista": Decimal("500.00"),
                "receita_recebida": Decimal("250.00"),
                "receita_pendente_recebimento": Decimal("300.00"),
                "receita_aberta": Decimal("300.00"),
            },
            {
                "divida_prevista": Decimal("400.00"),
                "divida_paga": Decimal("150.00"),
                "divida_pendente_pagamento": Decimal("220.00"),
                "divida_aberta": Decimal("220.00"),
            },
        )

        self.assertEqual(resumo["saldo_previsto"], Decimal("100.00"))
        self.assertEqual(resumo["saldo_realizado"], Decimal("100.00"))
        self.assertEqual(resumo["saldo_aberto"], Decimal("80.00"))
        self.assertEqual(resumo["falta_cobrir"], Decimal("120.00"))
        self.assertEqual(resumo["resultado_financeiro"], Decimal("100.00"))
        self.assertEqual(resumo["resultado_financeiro_projetado"], Decimal("100.00"))
        self.assertEqual(resumo["resultado_financeiro_realizado"], Decimal("100.00"))
        self.assertEqual(resumo["resultado_financeiro_pendente"], Decimal("80.00"))
        self.assertEqual(resumo["deficit_caixa"], Decimal("120.00"))

        resumo_sem_caixa_disponivel = calcular_resumo_financeiro_mes(
            {
                "receita_prevista": Decimal("100.00"),
                "receita_recebida": Decimal("50.00"),
                "receita_pendente_recebimento": Decimal("60.00"),
                "receita_aberta": Decimal("60.00"),
            },
            {
                "divida_prevista": Decimal("300.00"),
                "divida_paga": Decimal("100.00"),
                "divida_pendente_pagamento": Decimal("180.00"),
                "divida_aberta": Decimal("180.00"),
            },
        )

        self.assertEqual(resumo_sem_caixa_disponivel["saldo_realizado"], Decimal("-50.00"))
        self.assertEqual(resumo_sem_caixa_disponivel["falta_cobrir"], Decimal("180.00"))

