    def test_filtros_dashboard_financial_overview_normalizam_params_do_frontend(self):
        from .views_dashboard import filtros_dashboard_financial_overview

        factory = RequestFactory()
        request_manual = factory.get(
            "/api/dashboard/financial-overview/",
            {
                "period": "semester",
                "startDate": "2026-05-01",
                "endDate": "2026-05-31",
                "eventId": "12",
                "clientId": "34",
                "status": "recebido",
            },
        )
        filtros_manual = filtros_dashboard_financial_overview(request_manual)

        self.assertEqual(
            filtros_manual,
            {
                "data_inicial": "2026-05-01",
                "data_final": "2026-05-31",
                "evento": "12",
                "cliente": "34",
                "status": "recebido",
                "periodo_rapido": "",
            },
        )

        request_periodo = factory.get(
            "/api/dashboard/financial-overview/",
            {
                "period": "current-month",
                "eventId": "15",
                "clientId": "99",
                "status": "pendente",
            },
        )
        filtros_periodo = filtros_dashboard_financial_overview(request_periodo)

        self.assertEqual(filtros_periodo["data_inicial"], "")
        self.assertEqual(filtros_periodo["data_final"], "")
        self.assertEqual(filtros_periodo["evento"], "15")
        self.assertEqual(filtros_periodo["cliente"], "99")
        self.assertEqual(filtros_periodo["status"], "pendente")
        self.assertEqual(filtros_periodo["periodo_rapido"], "mes_atual")

        request_invalidos = factory.get(
            "/api/dashboard/financial-overview/",
            {
                "period": "fora-do-contrato",
                "quickPeriod": "tambem-invalido",
                "startDate": "2026-05-31",
                "endDate": "2026-05-01",
                "eventId": "abc",
                "clientId": "34x",
                "status": "qualquer",
            },
        )
        filtros_invalidos = filtros_dashboard_financial_overview(request_invalidos)

        self.assertEqual(filtros_invalidos["data_inicial"], "2026-05-01")
        self.assertEqual(filtros_invalidos["data_final"], "2026-05-31")
        self.assertEqual(filtros_invalidos["evento"], "")
        self.assertEqual(filtros_invalidos["cliente"], "")
        self.assertEqual(filtros_invalidos["status"], "")
        self.assertEqual(filtros_invalidos["periodo_rapido"], "")

