class RecalculoExclusaoTests(TestCase):
    def setUp(self):
        self.cliente = Cliente.objects.create(
            nome_razao_social="Cliente Recalculo",
            tipo_pessoa="PJ",
            cpf_cnpj="10.000.000/0001-10",
        )
        self.evento = Evento.objects.create(
            cliente=self.cliente,
            numero="EVT-RECALC-001",
            nome_evento="Evento Recalculo",
            data_inicio=date(2026, 5, 20),
            data_fim=date(2026, 5, 20),
        )
        criar_entrada_caixa_teste(data=date(2026, 5, 1))

    def test_excluir_receita_recalcula_realizado_do_evento(self):
        receita = ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita recebida",
            valor_previsto=Decimal("100.00"),
            valor_recebido=Decimal("100.00"),
            data_vencimento=date(2026, 5, 20),
        )
        self.evento.refresh_from_db()
        self.assertEqual(self.evento.valor_total_realizado, Decimal("100.00"))

        with self.captureOnCommitCallbacks(execute=True):
            ReceitaOperacional.objects.filter(pk=receita.pk).delete()

        self.evento.refresh_from_db()
        self.assertEqual(self.evento.valor_total_realizado, Decimal("0.00"))
        self.assertEqual(self.evento.lucro_realizado, Decimal("0.00"))

    def test_excluir_despesa_recalcula_realizado_do_evento(self):
        despesa = DespesaOperacional.objects.create(
            evento=self.evento,
            descricao="Despesa paga",
            categoria="material",
            valor_previsto=Decimal("80.00"),
            valor_pago=Decimal("80.00"),
            data_vencimento=date(2026, 5, 20),
        )
        self.evento.refresh_from_db()
        self.assertEqual(self.evento.custo_total_realizado, Decimal("80.00"))

        with self.captureOnCommitCallbacks(execute=True):
            DespesaOperacional.objects.filter(pk=despesa.pk).delete()

        self.evento.refresh_from_db()
        self.assertEqual(self.evento.custo_total_realizado, Decimal("0.00"))
        self.assertEqual(self.evento.lucro_realizado, Decimal("0.00"))

    def test_excluir_pagamento_parcela_em_massa_recalcula_parcela(self):
        data_vencimento_futura = timezone.localdate() + timedelta(days=10)
        divida = DividaFinanceira.objects.create(
            descricao="Divida Recalculo",
            credor="Banco Recalculo",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        parcela = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=data_vencimento_futura,
            data_vencimento_atual=data_vencimento_futura,
            valor_principal=Decimal("100.00"),
        )
        pagamento = PagamentoParcelaDivida.objects.create(
            parcela=parcela,
            data_pagamento=date(2026, 5, 10),
            valor_pagamento=Decimal("100.00"),
            forma_pagamento="pix",
        )
        parcela.refresh_from_db()
        self.assertEqual(parcela.valor_pago, Decimal("100.00"))

        with self.captureOnCommitCallbacks(execute=True):
            PagamentoParcelaDivida.objects.filter(pk=pagamento.pk).delete()

        parcela.refresh_from_db()
        self.assertEqual(parcela.valor_pago, Decimal("0.00"))
        self.assertEqual(parcela.status, "aberta")

    def test_excluir_parcela_em_massa_atualiza_status_da_divida(self):
        divida = DividaFinanceira.objects.create(
            descricao="Divida Sem Parcelas",
            credor="Banco Recalculo",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        parcela = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 20),
            data_vencimento_atual=date(2026, 5, 20),
            valor_principal=Decimal("100.00"),
        )
        PagamentoParcelaDivida.objects.create(
            parcela=parcela,
            data_pagamento=date(2026, 5, 10),
            valor_pagamento=Decimal("100.00"),
            forma_pagamento="pix",
        )
        divida.refresh_from_db()
        self.assertEqual(divida.status, "quitada")

        with self.captureOnCommitCallbacks(execute=True):
            ParcelaDivida.objects.filter(pk=parcela.pk).delete()

        divida.refresh_from_db()
        self.assertEqual(divida.status, "ativa")


