        custo_servico.alimentacao_quitada = True
        custo_servico.transporte_quitado = True
        custo_servico.motivo_baixa = "Acordo por valor menor."
        custo_servico.save()
        custo_servico.refresh_from_db()

        self.assertEqual(custo_servico.saldo_diarias, Decimal("0.00"))
        self.assertEqual(custo_servico.saldo_alimentacao, Decimal("0.00"))
        self.assertEqual(custo_servico.saldo_transporte, Decimal("0.00"))
        self.assertEqual(custo_servico.saldo_geral, Decimal("0.00"))
        self.assertEqual(
            DespesaOperacional.objects.get(evento=evento, categoria="mao_obra").status,
            "pago",
        )
        self.assertEqual(
            DespesaOperacional.objects.get(evento=evento, categoria="alimentacao").status,
            "pago",
        )
        self.assertEqual(
            DespesaOperacional.objects.get(evento=evento, categoria="transporte").status,
            "pago",
        )

        custo_extra = EventoCustoExtra.objects.create(
            evento=evento,
            categoria="material",
            descricao="Extra fechado menor",
            valor_previsto=Decimal("120.00"),
            data_vencimento=date(2026, 5, 10),
        )
        PagamentoEventoCustoExtra.objects.create(
            custo_extra=custo_extra,
            valor_pagamento=Decimal("90.00"),
            data_pagamento=date(2026, 5, 10),
        )
        custo_extra.refresh_from_db()
        aplicar_baixa_custo_extra(
            custo_extra,
            "Acordo por valor menor.",
            usuario=None,
        )
        custo_extra.refresh_from_db()

        despesa_extra = DespesaOperacional.objects.get(
            evento=evento,
            descricao="Custo extra: Extra fechado menor",
        )
        self.assertEqual(custo_extra.saldo_a_pagar, Decimal("0.00"))
        self.assertEqual(despesa_extra.valor_pago, Decimal("90.00"))
        self.assertEqual(despesa_extra.status, "pago")


