        item.refresh_from_db()
        receita = ReceitaOperacional.objects.get(evento=evento)
        custo_evento = EventoCustoServico.objects.get(evento=evento, servico=self.servico)
        despesa_mao_obra = DespesaOperacional.objects.get(
            evento=evento,
            origem=DespesaOperacional.ORIGEM_CUSTO_SERVICO,
            origem_custo_servico_tipo="diarias",
        )
        obrigacao_receita = ObrigacaoFinanceira.objects.get(receita_operacional=receita)
        obrigacao_custo = ObrigacaoFinanceira.objects.get(
            evento_custo_servico=custo_evento,
            detalhe_origem="diarias",
        )

        self.assertNotEqual(self.orcamento.total_venda, valor_venda_original)
        self.assertNotEqual(item.custo_servico_total, custo_servico_original)
        self.assertEqual(evento.valor_total_previsto, self.orcamento.total_venda)
        self.assertEqual(
            evento.custo_total_previsto,
            self.orcamento.subtotal_custos + self.orcamento.total_impostos,
        )
        self.assertEqual(receita.valor_previsto, self.orcamento.total_venda)
        self.assertEqual(obrigacao_receita.valor_previsto, self.orcamento.total_venda)
        self.assertEqual(custo_evento.valor_diarias, item.custo_servico_total)
        self.assertEqual(custo_evento.valor_alimentacao, item.gasto_alimentacao_total)
        self.assertEqual(custo_evento.valor_transporte, item.gasto_transporte_total)
        self.assertEqual(despesa_mao_obra.valor_previsto, item.custo_servico_total)
        self.assertEqual(obrigacao_custo.valor_previsto, item.custo_servico_total)

