    def test_editar_custo_servico_previsto_atualiza_custo_previsto_evento(self):
        OrcamentoItem.objects.create(
            orcamento=self.orcamento,
            servico=self.servico,
            horas_por_dia=8,
            quantidade_dias=1,
            quantidade_pessoas=1,
        )
        evento = self.orcamento.aprovar_e_gerar_evento()
        custo_evento = EventoCustoServico.objects.get(evento=evento, servico=self.servico)

        custo_evento.valor_diarias = Decimal("250.00")
        custo_evento.save()

        evento.refresh_from_db()
        despesa_mao_obra = DespesaOperacional.objects.get(
            evento=evento,
            origem=DespesaOperacional.ORIGEM_CUSTO_SERVICO,
            origem_custo_servico_tipo="diarias",
        )
        obrigacao_custo = ObrigacaoFinanceira.objects.get(
            evento_custo_servico=custo_evento,
            detalhe_origem="diarias",
        )
        custo_previsto_operacional = sum(
            (despesa.valor_previsto for despesa in evento.despesas.all()),
            Decimal("0.00"),
        )

        self.assertEqual(despesa_mao_obra.valor_previsto, Decimal("250.00"))
        self.assertEqual(
            EventoCustoServico.objects.filter(
                evento=evento,
                servico=self.servico,
            ).count(),
            1,
        )
        self.assertEqual(obrigacao_custo.valor_previsto, Decimal("250.00"))
        self.assertEqual(evento.custo_total_previsto, custo_previsto_operacional)
        self.assertEqual(
            evento.lucro_previsto,
            evento.valor_total_previsto - evento.custo_total_previsto,
        )

        saida = StringIO()
        call_command(
            "verificar_integridade_valores_editaveis",
            "--escopo=orcamento",
            f"--object-id={self.orcamento.id}",
            "--falhar-com-inconsistencia",
            stdout=saida,
        )

        self.assertIn("Nenhuma inconsistencia de valores editaveis encontrada.", saida.getvalue())

    def test_editar_custo_servico_adota_despesa_reservada_herdada_como_manual(self):
        OrcamentoItem.objects.create(
            orcamento=self.orcamento,
            servico=self.servico,
            horas_por_dia=8,
            quantidade_dias=1,
            quantidade_pessoas=1,
        )
        evento = self.orcamento.aprovar_e_gerar_evento()
        custo_evento = EventoCustoServico.objects.get(evento=evento, servico=self.servico)
        descricao = DespesaOperacional.CUSTOS_SERVICO_DERIVADOS["mao_obra"][0]
        despesa = DespesaOperacional.objects.get(
            evento=evento,
            categoria="mao_obra",
            origem=DespesaOperacional.ORIGEM_CUSTO_SERVICO,
            origem_custo_servico_tipo="diarias",
        )

        DespesaOperacional.objects.filter(pk=despesa.pk).update(
            origem=DespesaOperacional.ORIGEM_MANUAL,
            origem_custo_servico_tipo="",
            valor_previsto=Decimal("111.00"),
            valor_pago=Decimal("0.00"),
            status="pendente",
        )

        custo_evento.valor_diarias = Decimal("250.00")
        custo_evento.save()

        despesa.refresh_from_db()
        evento.refresh_from_db()

        self.assertEqual(despesa.origem, DespesaOperacional.ORIGEM_CUSTO_SERVICO)
        self.assertEqual(despesa.origem_custo_servico_tipo, "diarias")
        self.assertEqual(despesa.valor_previsto, Decimal("250.00"))
        self.assertFalse(
            DespesaOperacional.objects.filter(
                evento=evento,
                categoria="mao_obra",
                origem=DespesaOperacional.ORIGEM_MANUAL,
                descricao=descricao,
            ).exists()
        )
        self.assertEqual(
            DespesaOperacional.objects.filter(
                evento=evento,
                categoria="mao_obra",
                descricao=descricao,
            ).count(),
            1,
        )
        custo_previsto_operacional = sum(
            (despesa.valor_previsto for despesa in evento.despesas.all()),
            Decimal("0.00"),
        )
        self.assertEqual(evento.custo_total_previsto, custo_previsto_operacional)

