    @override_settings(
        CSRF_TRUSTED_ORIGINS=["http://localhost:3000"],
        CORS_ALLOWED_ORIGINS=["http://localhost:3000"],
    )
    def test_api_auth_csrf_mantem_contrato_para_frontend(self):
        client = Client(enforce_csrf_checks=True)
        url = reverse("caixa:api_auth_csrf")

        response = client.get(url, HTTP_ORIGIN="http://localhost:3000")
        payload = response.json()
        csrf_cookie = response.cookies.get(settings.CSRF_COOKIE_NAME)
        second_response = client.get(url, HTTP_ORIGIN="http://localhost:3000")
        post_response = client.post(
            url,
            HTTP_ORIGIN="http://localhost:3000",
            HTTP_X_CSRFTOKEN=payload["csrfToken"],
        )

        self.assertEqual(url, "/api/auth/csrf/")
        self.assertEqual(response.status_code, 200)
        self.assertEqual(response["Content-Type"], "application/json")
        self.assertEqual(set(payload), {"csrfToken"})
        self.assertIsInstance(payload["csrfToken"], str)
        self.assertTrue(payload["csrfToken"])
        self.assertIn("no-store", response["Cache-Control"])
        self.assertIsNotNone(csrf_cookie)
