    @override_settings(
        CSRF_TRUSTED_ORIGINS=["http://localhost:3000"],
        CORS_ALLOWED_ORIGINS=["http://localhost:3000"],
        AXES_ENABLED=False,
    )
    def test_api_auth_login_aplica_limite_de_requisicoes_configurado(self):
        client = Client(enforce_csrf_checks=True)
        User.objects.create_user(
            username="api-auth-throttle",
            password="senha-segura",
        )
        url = reverse("caixa:api_auth_login")
        throttle_rates = rest_framework_settings_with_throttle_rates(
            anon="1000/minute",
            user="1000/minute",
            auth_login="1/minute",
        )["DEFAULT_THROTTLE_RATES"]

        cache.clear()
        try:
            with patch.object(SimpleRateThrottle, "THROTTLE_RATES", throttle_rates):
                csrf_token = self._auth_csrf_token(client)
                primeira_resposta = client.post(
                    url,
                    data='{"username":"api-auth-throttle","password":"senha-errada"}',
                    content_type="application/json",
                    HTTP_ORIGIN=self.auth_frontend_origin,
                    HTTP_X_CSRFTOKEN=csrf_token,
                )
                segunda_resposta = client.post(
                    url,
                    data='{"username":"api-auth-throttle","password":"senha-errada"}',
                    content_type="application/json",
                    HTTP_ORIGIN=self.auth_frontend_origin,
                    HTTP_X_CSRFTOKEN=csrf_token,
                )
        finally:
            cache.clear()

        self.assertEqual(primeira_resposta.status_code, 401)
        self.assertEqual(segunda_resposta.status_code, 429)
        self.assertTrue(segunda_resposta.json()["detail"])
        self.assertIn("Retry-After", segunda_resposta.headers)
        self._assert_json_no_store(segunda_resposta)

    @override_settings(
        CSRF_TRUSTED_ORIGINS=["http://localhost:3000"],
        CORS_ALLOWED_ORIGINS=["http://localhost:3000"],
    )
    def test_api_auth_login_exige_json_e_respostas_nao_sao_cacheaveis(self):
        client = Client(enforce_csrf_checks=True)
        csrf_response = client.get(
            reverse("caixa:api_auth_csrf"),
            HTTP_ORIGIN="http://localhost:3000",
        )
        csrf_token = csrf_response.json()["csrfToken"]

        response = client.post(
            reverse("caixa:api_auth_login"),
            data="username=usuario&password=senha",
            content_type="application/x-www-form-urlencoded",
            HTTP_ORIGIN="http://localhost:3000",
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        self.assertEqual(response.status_code, 415)
        self.assertEqual(response.json(), {"detail": "Content-Type deve ser application/json."})
        self.assertIn("no-store", csrf_response["Cache-Control"])
        self.assertIn("no-store", response["Cache-Control"])

        invalid_json_response = client.post(
            reverse("caixa:api_auth_login"),
            data='{"username":',
            content_type="application/json",
            HTTP_ORIGIN="http://localhost:3000",
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        self.assertEqual(invalid_json_response.status_code, 400)
        self.assertEqual(invalid_json_response.json(), {"detail": "JSON invalido."})
        self.assertIn("no-store", invalid_json_response["Cache-Control"])

        missing_credentials_response = client.post(
            reverse("caixa:api_auth_login"),
            data='{"username":"","password":""}',
            content_type="application/json",
            HTTP_ORIGIN="http://localhost:3000",
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        self.assertEqual(missing_credentials_response.status_code, 400)
        self.assertEqual(
            missing_credentials_response.json(),
            {"detail": "Informe usuario e senha."},
        )
        self.assertIn("no-store", missing_credentials_response["Cache-Control"])

    @override_settings(
        CSRF_TRUSTED_ORIGINS=["http://localhost:3000"],
        CORS_ALLOWED_ORIGINS=["http://localhost:3000"],
    )
    def test_api_auth_login_preserva_csrf_405_erros_e_payload_nao_dict(self):
        User.objects.create_user(
            username="api-auth-paridade-erros",
            password="senha-segura",
        )
        login_url = reverse("caixa:api_auth_login")
        client_sem_csrf = Client(enforce_csrf_checks=True)
        response_sem_csrf = client_sem_csrf.post(
            login_url,
            data='{"username":"api-auth-paridade-erros","password":"senha-segura"}',
            content_type="application/json",
            HTTP_ORIGIN=self.auth_frontend_origin,
        )

        client = Client(enforce_csrf_checks=True)
        csrf_token = self._auth_csrf_token(client)

        for metodo in ["get", "put", "patch", "delete"]:
            with self.subTest(metodo=metodo):
                if metodo == "get":
                    response_metodo = client.get(
                        login_url,
                        HTTP_ORIGIN=self.auth_frontend_origin,
                    )
                else:
                    response_metodo = getattr(client, metodo)(
                        login_url,
                        data="{}",
                        content_type="application/json",
                        HTTP_ORIGIN=self.auth_frontend_origin,
                        HTTP_X_CSRFTOKEN=csrf_token,
                    )

                self.assertEqual(response_metodo.status_code, 405)
                self.assertEqual(response_metodo["Allow"], "POST")

        content_type_response = client.post(
            login_url,
            data="username=api-auth-paridade-erros&password=senha-segura",
            content_type="application/x-www-form-urlencoded",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        invalid_json_response = client.post(
            login_url,
            data='{"username":',
            content_type="application/json",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        non_dict_response = client.post(
            login_url,
            data='["api-auth-paridade-erros", "senha-segura"]',
            content_type="application/json",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        missing_credentials_response = client.post(
            login_url,
            data='{"username":"","password":""}',
            content_type="application/json",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        invalid_credentials_response = client.post(
            login_url,
            data='{"username":"api-auth-paridade-erros","password":"senha-errada"}',
            content_type="application/json",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        self.assertEqual(response_sem_csrf.status_code, 403)
        self.assertIn("text/html", response_sem_csrf["Content-Type"])
        self.assertEqual(content_type_response.status_code, 415)
        self.assertEqual(
            content_type_response.json(),
            {"detail": "Content-Type deve ser application/json."},
        )
        self._assert_json_no_store(content_type_response)
        self.assertEqual(invalid_json_response.status_code, 400)
        self.assertEqual(invalid_json_response.json(), {"detail": "JSON invalido."})
        self._assert_json_no_store(invalid_json_response)
        self.assertEqual(non_dict_response.status_code, 400)
        self.assertEqual(non_dict_response.json(), {"detail": "JSON invalido."})
        self._assert_json_no_store(non_dict_response)
        self.assertEqual(missing_credentials_response.status_code, 400)
        self.assertEqual(
            missing_credentials_response.json(),
            {"detail": "Informe usuario e senha."},
        )
        self._assert_json_no_store(missing_credentials_response)
        self.assertEqual(invalid_credentials_response.status_code, 401)
        self.assertEqual(
            invalid_credentials_response.json(),
            {"detail": "Usuario ou senha invalidos."},
        )
        self._assert_json_no_store(invalid_credentials_response)

