        self.assertIn(settings.CSRF_COOKIE_NAME, response.cookies)
        self.assertTrue(response.cookies[settings.CSRF_COOKIE_NAME].value)
        self.assertIn(settings.SESSION_COOKIE_NAME, client.cookies)
        self.assertEqual(str(usuario.pk), client.session["_auth_user_id"])
        self.assertNotIn("password", response.content.decode("utf-8").lower())

