    @override_settings(
        CSRF_TRUSTED_ORIGINS=["http://localhost:3000"],
        CORS_ALLOWED_ORIGINS=["http://localhost:3000"],
    )
    def test_api_auth_logout_preserva_csrf_405_anonimo_e_body_ignorado(self):
        logout_url = reverse("caixa:api_auth_logout")
        client_sem_csrf = Client(enforce_csrf_checks=True)
        usuario_sem_csrf = User.objects.create_user(
            username="api-auth-logout-sem-csrf",
            password="senha-segura",
        )
        client_sem_csrf.force_login(usuario_sem_csrf)
        response_sem_csrf = client_sem_csrf.post(
            logout_url,
            HTTP_ORIGIN=self.auth_frontend_origin,
        )

        client = Client(enforce_csrf_checks=True)
        csrf_token = self._auth_csrf_token(client)

        for metodo in ["get", "put", "patch", "delete"]:
            with self.subTest(metodo=metodo):
                if metodo == "get":
                    response_metodo = client.get(
                        logout_url,
                        HTTP_ORIGIN=self.auth_frontend_origin,
                    )
                else:
                    response_metodo = getattr(client, metodo)(
                        logout_url,
                        data="{}",
                        content_type="application/json",
                        HTTP_ORIGIN=self.auth_frontend_origin,
                        HTTP_X_CSRFTOKEN=csrf_token,
                    )

                self.assertEqual(response_metodo.status_code, 405)
                self.assertEqual(response_metodo["Allow"], "POST")

        response_anonimo = client.post(
            logout_url,
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        client_body_ignorado = Client(enforce_csrf_checks=True)
        csrf_token_body_ignorado = self._auth_csrf_token(client_body_ignorado)
        response_form = client_body_ignorado.post(
            logout_url,
            data="payload=ignorado",
            content_type="application/x-www-form-urlencoded",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token_body_ignorado,
        )

        self.assertEqual(response_sem_csrf.status_code, 403)
        self.assertIn("text/html", response_sem_csrf["Content-Type"])
        self.assertEqual(response_anonimo.status_code, 200)
        self.assertEqual(set(response_anonimo.json()), {"authenticated", "csrfToken"})
        self.assertFalse(response_anonimo.json()["authenticated"])
        self.assertIsInstance(response_anonimo.json()["csrfToken"], str)
        self.assertTrue(response_anonimo.json()["csrfToken"])
        self._assert_json_no_store(response_anonimo)
        self.assertIn(settings.CSRF_COOKIE_NAME, response_anonimo.cookies)
        self.assertEqual(response_form.status_code, 200)
        self.assertEqual(set(response_form.json()), {"authenticated", "csrfToken"})
        self.assertFalse(response_form.json()["authenticated"])
        self._assert_json_no_store(response_form)

    @override_settings(
        CSRF_TRUSTED_ORIGINS=["http://localhost:3000"],
        CORS_ALLOWED_ORIGINS=["http://localhost:3000"],
    )
    def test_api_auth_logout_autenticado_expira_sessao_e_ignora_json_invalido(self):
        client = Client(enforce_csrf_checks=True)
        User.objects.create_user(
            username="api-auth-logout-autenticado",
            password="senha-segura",
        )
        csrf_token = self._auth_csrf_token(client)
        login_response = client.post(
            reverse("caixa:api_auth_login"),
            data='{"username":"api-auth-logout-autenticado","password":"senha-segura"}',
            content_type="application/json",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        logout_response = client.post(
            reverse("caixa:api_auth_logout"),
            data='{"payload":',
            content_type="application/json",
            HTTP_ORIGIN=self.auth_frontend_origin,
            HTTP_X_CSRFTOKEN=login_response.json()["csrfToken"],
        )
        session_response = client.get(
            reverse("caixa:api_auth_session"),
            HTTP_ORIGIN=self.auth_frontend_origin,
        )

        self.assertEqual(login_response.status_code, 200)
        self.assertEqual(logout_response.status_code, 200)
        self.assertEqual(set(logout_response.json()), {"authenticated", "csrfToken"})
        self.assertFalse(logout_response.json()["authenticated"])
        self.assertIsInstance(logout_response.json()["csrfToken"], str)
        self.assertTrue(logout_response.json()["csrfToken"])
        self._assert_json_no_store(logout_response)
        self.assertIn(settings.SESSION_COOKIE_NAME, logout_response.cookies)
        session_cookie = logout_response.cookies[settings.SESSION_COOKIE_NAME]
        self.assertEqual(session_cookie.value, "")
        self.assertEqual(str(session_cookie["max-age"]), "0")
        self.assertIn(settings.CSRF_COOKIE_NAME, logout_response.cookies)
        self.assertTrue(logout_response.cookies[settings.CSRF_COOKIE_NAME].value)
        self.assertEqual(session_response.status_code, 200)
        self.assertEqual(session_response.json(), {"authenticated": False})

