    def test_apis_financeiras_exigem_permissoes_das_telas(self):
        usuario = User.objects.create_user(
            "api-financeiras-sem-permissao",
            password="senha",
        )
        self.client.force_login(usuario)

        response_fci = self.client.get(reverse("caixa:api_investimentos"))
        response_fcf = self.client.get(reverse("caixa:api_financiamentos"))
        response_credores_fcf = self.client.get(
            reverse("caixa:api_credores_financiamentos")
        )

        self.assertEqual(response_fci.status_code, 403)
        self.assertEqual(response_fcf.status_code, 403)
        self.assertEqual(response_credores_fcf.status_code, 403)
        self.assertEqual(response_fci["Content-Type"], "application/json")
        self.assertEqual(response_fcf["Content-Type"], "application/json")
        self.assertEqual(response_credores_fcf["Content-Type"], "application/json")
        self.assertEqual(response_fci.json(), {"detail": "Permission denied."})
        self.assertEqual(response_fcf.json(), {"detail": "Permission denied."})
        self.assertEqual(
            response_credores_fcf.json(),
            {"detail": "Permission denied."},
        )
        self.assertIn("no-store", response_fci["Cache-Control"])
        self.assertIn("no-store", response_fcf["Cache-Control"])
        self.assertIn("no-store", response_credores_fcf["Cache-Control"])

        usuario.user_permissions.add(
            Permission.objects.get(codename="view_investimento"),
            Permission.objects.get(codename="view_parceladivida"),
        )

        response_fci = self.client.get(reverse("caixa:api_investimentos"))
        response_fcf = self.client.get(reverse("caixa:api_financiamentos"))
        response_credores_fcf = self.client.get(
            reverse("caixa:api_credores_financiamentos")
        )

        self.assertEqual(response_fci.status_code, 200)
        self.assertEqual(response_fcf.status_code, 200)
        self.assertEqual(response_credores_fcf.status_code, 403)
        self.assertEqual(response_fci["Content-Type"], "application/json")
        self.assertEqual(response_fcf["Content-Type"], "application/json")
        self.assertEqual(response_credores_fcf["Content-Type"], "application/json")
        self.assertIn("no-store", response_fci["Cache-Control"])
        self.assertIn("no-store", response_fcf["Cache-Control"])
        self.assertEqual(
            response_credores_fcf.json(),
            {"detail": "Permission denied."},
        )
        self.assertIn("no-store", response_credores_fcf["Cache-Control"])

        usuario.user_permissions.add(
            Permission.objects.get(codename="view_credor"),
        )

        response_credores_fcf = self.client.get(
            reverse("caixa:api_credores_financiamentos")
        )

        self.assertEqual(response_credores_fcf.status_code, 200)
        self.assertEqual(response_credores_fcf["Content-Type"], "application/json")
        self.assertIn("no-store", response_credores_fcf["Cache-Control"])

