    @override_settings(
        NEXT_FRONTEND_URL="https://app.rhremoto.test",
        NEXT_FRONTEND_LEGACY_REDIRECTS_ENABLED=False,
        NEXT_FRONTEND_LEGACY_REDIRECT_SURFACES=[],
    )
    def test_comando_validar_redirects_next_legado_aprova_candidato_unitario(self):
        saida = StringIO()

        call_command(
            "validar_redirects_next_legado",
            "--surface",
            "receitas_lista",
            "--exigir-unitario",
            "--json",
            stdout=saida,
        )
        payload = json.loads(saida.getvalue())

        self.assertTrue(payload["ready"])
        self.assertEqual(payload["source"], "argument")
        self.assertFalse(payload["redirectsEnabled"])
        self.assertEqual(payload["candidateSurfaces"], ["receitas_lista"])
        self.assertEqual(payload["surfaces"][0]["djangoUrl"], "/receitas/")
        self.assertEqual(
            payload["surfaces"][0]["nextUrl"],
            "https://app.rhremoto.test/receitas",
        )
        self.assertTrue(payload["surfaces"][0]["redirectEligible"])
        self.assertTrue(payload["activation"]["readyToActivate"])
        self.assertEqual(
            payload["activation"]["recommendedSurfacesValue"],
            "receitas_lista",
        )
        self.assertEqual(
            payload["activation"]["recommendedEnvironment"],
            {
                "NEXT_FRONTEND_URL": "https://app.rhremoto.test",
                "NEXT_FRONTEND_LEGACY_REDIRECTS_ENABLED": "True",
                "NEXT_FRONTEND_LEGACY_REDIRECT_SURFACES": "receitas_lista",
            },
        )
        self.assertEqual(
            payload["activation"]["rollbackEnvironment"],
            {
                "NEXT_FRONTEND_LEGACY_REDIRECTS_ENABLED": "False",
                "NEXT_FRONTEND_LEGACY_REDIRECT_SURFACES": "",
            },
        )
        self.assertEqual(payload["executionRecord"]["format"], "markdown")
        self.assertIn(
            "Registro PM-06.1104 - canario de redirect Next legado",
            payload["executionRecord"]["markdown"],
        )
        self.assertIn(
            "validateCandidate: python manage.py validar_redirects_next_legado --surface=receitas_lista --exigir-unitario --falhar --json",
            payload["executionRecord"]["markdown"],
        )
        self.assertIn(
            "NEXT_FRONTEND_LEGACY_REDIRECTS_ENABLED=False",
            payload["executionRecord"]["markdown"],
        )

