    @override_settings(NEXT_FRONTEND_URL="https://app.rhremoto.test")
    def test_comando_validar_redirects_next_legado_salva_evidencias(self):
        with TemporaryDirectory() as temp_dir:
            saida = StringIO()

            call_command(
                "validar_redirects_next_legado",
                "--surface",
                "receitas_lista",
                f"--diretorio-evidencias={temp_dir}",
                "--exigir-arquivos-evidencia",
                "--json",
                stdout=saida,
            )
            payload = json.loads(saida.getvalue())
            json_path = Path(temp_dir) / "pm06-redirect-next-legado.json"
            record_path = Path(temp_dir) / "pm06-redirect-next-legado.md"
            payload_salvo = json.loads(json_path.read_text(encoding="utf-8"))
            registro_salvo = record_path.read_text(encoding="utf-8")

            self.assertTrue(payload["ready"])
            self.assertEqual(payload["outputEvidenceFiles"]["json"], str(json_path))
            self.assertEqual(payload["outputEvidenceFiles"]["record"], str(record_path))
            self.assertTrue(json_path.exists())
            self.assertTrue(record_path.exists())
            self.assertEqual(payload_salvo["ready"], payload["ready"])
            self.assertIn("Registro PM-06.1104", registro_salvo)
            self.assertIn(f"json: {json_path}", registro_salvo)
            self.assertIn(f"registro: {record_path}", registro_salvo)

