@override_settings(STORAGES=TEST_STATICFILES_STORAGES)
class SegurancaTests(TestCase):
    def _assert_json_no_store(self, response):
        self.assertEqual(response["Content-Type"], "application/json")
        self.assertIn("no-store", response["Cache-Control"])

    def _csrf_client_for(self, user):
        client = Client(enforce_csrf_checks=True)
        client.force_login(user)
        csrf_token = "a" * 32
        client.cookies[settings.CSRF_COOKIE_NAME] = csrf_token
        return client, {"HTTP_X_CSRFTOKEN": csrf_token}

    def _assert_backup_manual_payload_shape(self, payload):
        self.assertEqual(
            set(payload),
            {
                "created",
                "criado",
                "message",
                "mensagem",
                "removedCount",
                "removidos",
                "backup",
            },
        )
        self.assertEqual(payload["created"], payload["criado"])
        self.assertEqual(payload["message"], payload["mensagem"])
        self.assertEqual(payload["removedCount"], payload["removidos"])

    def _assert_backup_payload_shape(self, backup):
        self.assertEqual(
            set(backup),
            {
                "name",
                "nome",
                "sizeMb",
                "tamanho_mb",
                "createdAt",
                "criado_em",
                "downloadPath",
            },
        )
        self.assertEqual(backup["name"], backup["nome"])
        self.assertEqual(backup["sizeMb"], round(backup["tamanho_mb"], 4))
        self.assertTrue(backup["createdAt"])
        self.assertTrue(backup["downloadPath"].startswith("/backups/"))
        self.assertTrue(backup["downloadPath"].endswith("/download/"))

    def test_login_usa_logo_otimizado_e_csp_restritiva(self):
        response = self.client.get(reverse("caixa:login"), secure=True)

        self.assertContains(response, "logoAzulT-192.png")
        self.assertContains(response, 'fetchpriority="high"')

        csp = response.headers["Content-Security-Policy"]
        self.assertIn("script-src 'self'", csp)
        self.assertIn("require-trusted-types-for 'script'", csp)
        self.assertIn("trusted-types default rhremoto", csp)
        self.assertNotIn("unsafe-inline", csp)
        self.assertEqual(response.headers["Cross-Origin-Opener-Policy"], "same-origin")
        self.assertEqual(response.headers["Cross-Origin-Resource-Policy"], "same-origin")
        self.assertEqual(response.headers["X-Permitted-Cross-Domain-Policies"], "none")
        self.assertIn("geolocation=()", response.headers["Permissions-Policy"])

    def test_admin_fica_fora_da_csp_para_nao_quebrar_scripts_do_django(self):
        response = self.client.get("/admin/")

        self.assertNotIn("Content-Security-Policy", response.headers)

    def test_service_worker_responde_com_escopo_e_cache_control(self):
        response = self.client.get("/sw.js", secure=True)

        self.assertEqual(response.status_code, 200)
        self.assertEqual(response.headers["Service-Worker-Allowed"], "/")
        self.assertIn("no-cache", response.headers["Cache-Control"])

    def test_pwa_registra_service_worker_com_trusted_script_url(self):
        script = (
            Path(__file__).resolve().parent
            / "static"
            / "caixa"
            / "js"
            / "pwa.js"
        ).read_text(encoding="utf-8")

        self.assertIn('trustedTypes.createPolicy("rhremoto"', script)
        self.assertIn('createScriptURL("/sw.js")', script)
        self.assertIn("navigator.serviceWorker.register(serviceWorkerUrl()", script)
        self.assertNotIn('navigator.serviceWorker.register("/sw.js"', script)

    def test_api_throttle_global_limita_requisicoes_anonimas(self):
        throttle_rates = rest_framework_settings_with_throttle_rates(
            anon="1/minute",
            user="1000/minute",
            auth_login="1000/minute",
        )["DEFAULT_THROTTLE_RATES"]

        cache.clear()
        try:
            with patch.object(SimpleRateThrottle, "THROTTLE_RATES", throttle_rates):
                primeira_resposta = self.client.get(reverse("caixa:api_auth_session"))
                segunda_resposta = self.client.get(reverse("caixa:api_auth_session"))
        finally:
            cache.clear()

        self.assertEqual(primeira_resposta.status_code, 200)
        self.assertEqual(segunda_resposta.status_code, 429)
        self.assertTrue(segunda_resposta.json()["detail"])
        self.assertIn("Retry-After", segunda_resposta.headers)
        self._assert_json_no_store(segunda_resposta)

