    @override_settings(SECURE_SSL_REDIRECT=False)
    def test_api_backup_criar_manual_ignora_body_content_type_e_json(self):
        superuser = User.objects.create_superuser(
            "backup-manual-body-super",
            "backup-manual-body-super@example.com",
            "senha",
        )
        client, csrf_headers = self._csrf_client_for(superuser)
        url = reverse("caixa:api_backup_criar_manual")
        resultado = {
            "criado": True,
            "arquivo": "",
            "caminho": None,
            "removidos": 0,
            "mensagem": "Backup criado: mock",
        }
        expected_payload = {
            "created": True,
            "criado": True,
            "message": "Backup criado: mock",
            "mensagem": "Backup criado: mock",
            "removedCount": 0,
            "removidos": 0,
            "backup": None,
        }
        request_variants = [
            ("content-type-invalido", "payload=ignorado", "text/plain"),
            ("json-invalido", "{", "application/json"),
            ("json-valido-ignorado", json.dumps({"force": False}), "application/json"),
        ]

        with patch(
            "caixa.views_backups.criar_backup_banco",
            return_value=resultado,
        ) as criar_backup:
            for nome, data, content_type in request_variants:
                with self.subTest(nome=nome):
                    response = client.post(
                        url,
                        data=data,
                        content_type=content_type,
                        **csrf_headers,
                    )

                    self.assertEqual(response.status_code, 201)
                    self.assertEqual(response.json(), expected_payload)
                    self._assert_json_no_store(response)

        self.assertEqual(criar_backup.call_count, len(request_variants))
        for call in criar_backup.call_args_list:
            self.assertEqual(call.kwargs, {"force": True})

    @override_settings(SECURE_SSL_REDIRECT=False)
    def test_api_backup_criar_manual_preserva_metodos_nao_permitidos(self):
        superuser = User.objects.create_superuser(
            "backup-manual-method-super",
            "backup-manual-method-super@example.com",
            "senha",
        )
        self.client.force_login(superuser)
        url = reverse("caixa:api_backup_criar_manual")

        with patch("caixa.views_backups.criar_backup_banco") as criar_backup:
            for metodo in ["get", "put", "patch", "delete"]:
                with self.subTest(metodo=metodo):
                    if metodo == "get":
                        response = self.client.get(url)
                    else:
                        response = getattr(self.client, metodo)(
                            url,
                            data="{}",
                            content_type="application/json",
                        )

                    self.assertEqual(response.status_code, 405)
                    self.assertEqual(response["Allow"], "POST")
                    self.assertIn("text/html", response["Content-Type"])
                    self.assertEqual(response.content, b"")
                    self.assertIn("no-store", response["Cache-Control"])

        criar_backup.assert_not_called()

