    @override_settings(SECURE_SSL_REDIRECT=False)
    def test_api_backups_preserva_shape_filtros_de_arquivo_aliases_e_ordenacao(self):
        superuser = User.objects.create_superuser(
            "backup-api-shape-super",
            "backup-api-shape-super@example.com",
            "senha",
        )
        self.client.force_login(superuser)

        with TemporaryDirectory() as temp_dir:
            base_dir = Path(temp_dir)
            backup_dir = base_dir / "backups" / "db"
            backup_dir.mkdir(parents=True)
            backup_antigo = backup_dir / "backup_banco_2026-05_20260501_010203_000001.json"
            backup_recente = backup_dir / "backup_banco_2026-06_20260601_010203_000001.json"
            metadata = backup_dir / "backup_banco_2026-06_20260601_010203_000001.meta.json"
            fora_do_padrao = backup_dir / "outro.json"
            diretorio_compativel = backup_dir / "backup_banco_2026-07_20260701_010203_000001.json"
            backup_antigo.write_text("[]", encoding="utf-8")
            backup_recente.write_text("[1,2,3]", encoding="utf-8")
            metadata.write_text("{}", encoding="utf-8")
            fora_do_padrao.write_text("{}", encoding="utf-8")
            diretorio_compativel.mkdir()
            antigo_mtime = 1_700_000_000
            recente_mtime = 1_800_000_000
            backup_antigo.touch()
            backup_recente.touch()
            os.utime(backup_antigo, (antigo_mtime, antigo_mtime))
            os.utime(backup_recente, (recente_mtime, recente_mtime))

            with override_settings(BASE_DIR=base_dir):
                response = self.client.get(reverse("caixa:api_backups"))

        self.assertEqual(response.status_code, 200)
        self._assert_json_no_store(response)
        payload = response.json()
        self.assertEqual(set(payload), {"backups"})
        self.assertEqual(
            [backup["name"] for backup in payload["backups"]],
            [
                "backup_banco_2026-06_20260601_010203_000001.json",
                "backup_banco_2026-05_20260501_010203_000001.json",
            ],
        )
        primeiro = payload["backups"][0]
        segundo = payload["backups"][1]
        self.assertEqual(
            set(primeiro),
            {
                "name",
                "nome",
                "sizeMb",
                "tamanho_mb",
                "createdAt",
                "criado_em",
                "downloadPath",
            },
        )
        self.assertEqual(primeiro["name"], primeiro["nome"])
        self.assertEqual(segundo["name"], segundo["nome"])
        self.assertEqual(primeiro["criado_em"], float(recente_mtime))
        self.assertEqual(segundo["criado_em"], float(antigo_mtime))
        self.assertEqual(primeiro["sizeMb"], round(primeiro["tamanho_mb"], 4))
        self.assertEqual(segundo["sizeMb"], round(segundo["tamanho_mb"], 4))
        self.assertTrue(primeiro["createdAt"])
        self.assertTrue(segundo["createdAt"])
        self.assertEqual(
            primeiro["downloadPath"],
            "/backups/backup_banco_2026-06_20260601_010203_000001.json/download/",
        )
        self.assertEqual(
            segundo["downloadPath"],
            "/backups/backup_banco_2026-05_20260501_010203_000001.json/download/",
        )

    @override_settings(SECURE_SSL_REDIRECT=False)
    def test_superusuario_cria_backup_manual_pela_api(self):
        superuser = User.objects.create_superuser(
            "backup-manual-api-super",
            "backup-manual-api-super@example.com",
            "senha",
        )
        self.client.force_login(superuser)

        with TemporaryDirectory() as temp_dir:
            base_dir = Path(temp_dir)

            with override_settings(BASE_DIR=base_dir):
                response = self.client.post(reverse("caixa:api_backup_criar_manual"))

                self.assertEqual(response.status_code, 201)
                payload = response.json()
                self._assert_backup_manual_payload_shape(payload)
                self.assertTrue(payload["created"])
                self.assertTrue(payload["criado"])
                self.assertEqual(payload["message"], payload["mensagem"])
                self.assertTrue(payload["message"].startswith("Backup criado:"))
                self.assertEqual(payload["removedCount"], 0)
                self.assertEqual(payload["removidos"], 0)
                self.assertIsNotNone(payload["backup"])
                self._assert_backup_payload_shape(payload["backup"])
                self.assertTrue(payload["backup"]["name"].startswith("backup_banco_"))
                self.assertEqual(payload["backup"]["name"], payload["backup"]["nome"])
                self.assertTrue(payload["backup"]["downloadPath"].startswith("/backups/"))
                self.assertEqual(len(listar_backups_disponiveis()), 1)

                backup_dir = base_dir / "backups" / "db"
                backup_files = [
                    path
                    for path in backup_dir.glob("backup_banco_*.json")
                    if not path.name.endswith(".meta.json")
                ]
                self.assertEqual(len(backup_files), 1)
                backup_file = backup_files[0]
                metadata_file = backup_file.with_name(f"{backup_file.stem}.meta.json")
                self.assertTrue(metadata_file.exists())
                metadata = json.loads(metadata_file.read_text(encoding="utf-8"))
                self.assertEqual(
                    set(metadata),
                    {
                        "arquivo",
                        "criado_em",
                        "mes_referencia",
                        "sha256",
                        "tamanho_bytes",
                    },
                )
                self.assertEqual(metadata["arquivo"], backup_file.name)
                self.assertEqual(metadata["tamanho_bytes"], backup_file.stat().st_size)
                self.assertEqual(
                    metadata["sha256"],
                    hashlib.sha256(backup_file.read_bytes()).hexdigest(),
                )
                self.assertTrue(metadata["criado_em"])
                self.assertRegex(metadata["mes_referencia"], r"^\d{4}-\d{2}$")

    @override_settings(SECURE_SSL_REDIRECT=False)
    def test_api_backup_criar_manual_preserva_limpeza_de_backups_antigos(self):
        superuser = User.objects.create_superuser(
            "backup-manual-cleanup-super",
            "backup-manual-cleanup-super@example.com",
            "senha",
        )
        self.client.force_login(superuser)

        with TemporaryDirectory() as temp_dir:
            base_dir = Path(temp_dir)
            backup_dir = base_dir / "backups" / "db"
            backup_dir.mkdir(parents=True)

            for indice in range(3):
                backup = backup_dir / (
                    f"backup_banco_2026-0{indice + 1}_"
                    f"20260{indice + 1}01_010203_00000{indice + 1}.json"
                )
                backup.write_text("[]", encoding="utf-8")
                backup.with_name(f"{backup.stem}.meta.json").write_text(
                    "{}",
                    encoding="utf-8",
                )
                timestamp = 1_700_000_000 + indice
                os.utime(backup, (timestamp, timestamp))

            with override_settings(BASE_DIR=base_dir):
                response = self.client.post(reverse("caixa:api_backup_criar_manual"))

                self.assertEqual(response.status_code, 201)
                payload = response.json()
                self._assert_backup_manual_payload_shape(payload)
                self.assertEqual(payload["removedCount"], 1)
                self.assertEqual(payload["removidos"], 1)
                backups = listar_backups_disponiveis()

            self.assertEqual(len(backups), 3)
            nomes = [backup["nome"] for backup in backups]
            self.assertIn(payload["backup"]["name"], nomes)
            self.assertNotIn(
                "backup_banco_2026-01_20260101_010203_000001.json",
                nomes,
            )
            self.assertFalse(
                (
                    backup_dir
                    / "backup_banco_2026-01_20260101_010203_000001.meta.json"
                ).exists()
            )

