    def test_comando_backup_mensal_continua_criando_e_evitando_duplicado(self):
        with TemporaryDirectory() as temp_dir:
            base_dir = Path(temp_dir)

            with override_settings(BASE_DIR=base_dir):
                saida_criacao = StringIO()
                call_command("backup_banco_mensal", stdout=saida_criacao)

                self.assertIn("Backup criado", saida_criacao.getvalue())
