    def test_admin_ajax_parcelas_publica_aliases_semanticos_para_pagamento(self):
        usuario = User.objects.create_user(
            username="staff-com-permissao-parcela",
            password="senha-segura",
            is_staff=True,
        )
        usuario.user_permissions.add(
            Permission.objects.get(
                content_type__app_label="caixa",
                codename="view_pagamentoparceladivida",
            )
        )
        self.client.force_login(usuario)

        divida = DividaFinanceira.objects.create(
            descricao="Divida Admin Alias",
            credor="Fornecedor Admin Alias",
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
            dia_vencimento=10,
        )
        parcela = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
            valor_pago=Decimal("30.00"),
        )
        parcela_sem_saldo = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=2,
            data_vencimento_original=date(2026, 7, 10),
            data_vencimento_atual=date(2026, 7, 10),
            valor_principal=Decimal("100.00"),
        )
        ParcelaDivida.objects.filter(pk=parcela_sem_saldo.pk).update(
            status="aberta",
            valor_pago=Decimal("100.00"),
        )

        response = self.client.get(
            reverse("admin:caixa_pagamentoparceladivida_parcelas_por_divida"),
            {"divida_id": str(divida.id)},
            secure=True,
        )
        payload = response.json()

        self.assertEqual(response.status_code, 200)
        self.assertEqual(len(payload["parcelas"]), 1)
        self.assertEqual(parcela.contas_pendentes, Decimal("70.00"))
        self.assertEqual(payload["parcelas"][0]["id"], parcela.id)
        self.assertEqual(payload["parcelas"][0]["installmentLabel"], "1/1")
        self.assertEqual(payload["parcelas"][0]["dueDate"], "2026-06-10")
        self.assertEqual(payload["parcelas"][0]["pendingPaymentAmount"], "70.00")
        self.assertEqual(payload["parcelas"][0]["pendingAccountsAmount"], "70.00")
        self.assertEqual(payload["parcelas"][0]["valor_pendente_pagamento"], "70.00")
        self.assertEqual(payload["parcelas"][0]["saldo_em_aberto"], "70.00")
        self.assertNotIn(
            parcela_sem_saldo.id,
            {parcela["id"] for parcela in payload["parcelas"]},
        )


