    def _rotas_obrigacoes_financeiras(self):
        return (
            "api_obrigacoes_financeiras",
            "api_payment_obligations",
        )

    def _normalizar_payload_obrigacoes_para_comparacao(self, payload):
        normalizado = json.loads(json.dumps(payload, sort_keys=True))
        normalizado["meta"]["generatedAt"] = "<generated>"
        if "paymentQueue" in normalizado:
            normalizado["paymentQueue"]["generatedAt"] = "<generated>"
        return normalizado

