    def _criar_cenario_lancamentos_financeiros_api(self, sufixo="PM26"):
        codigo_documento = sum(ord(caractere) for caractere in sufixo) % 10000
        cliente = Cliente.objects.create(
            nome_razao_social=f"Cliente Ledger API {sufixo}",
            tipo_pessoa="PJ",
            cpf_cnpj=f"99.888.777/{codigo_documento:04d}-26",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero=f"EVT-LEDGER-{sufixo}",
            nome_evento=f"Evento Ledger API {sufixo}",
            data_inicio=date(2026, 5, 20),
            data_fim=date(2026, 5, 22),
        )
        receita = ReceitaOperacional.objects.create(
            evento=evento,
            cliente=cliente,
            descricao=f"Receita Ledger API {sufixo}",
            valor_previsto=Decimal("100.00"),
            valor_recebido=Decimal("0.00"),
            data_vencimento=date(2026, 5, 20),
        )
        despesa = DespesaOperacional.objects.create(
            evento=evento,
            descricao=f"Despesa Ledger API {sufixo}",
            categoria="material",
            valor_previsto=Decimal("40.00"),
            valor_pago=Decimal("0.00"),
            data_vencimento=date(2026, 5, 21),
        )
        investimento = Investimento.objects.create(
            evento=evento,
            descricao=f"Investimento Ledger API {sufixo}",
            categoria="software",
            tipo_fluxo="saida",
            valor_previsto=Decimal("70.00"),
            valor_realizado=Decimal("0.00"),
            data_prevista=date(2026, 5, 22),
        )
        financiamento = FinanciamentoMovimentacao.objects.create(
            evento=evento,
            descricao=f"Financiamento Ledger API {sufixo}",
            categoria="aporte_socio",
            tipo_fluxo="entrada",
            valor_previsto=Decimal("120.00"),
            valor_realizado=Decimal("0.00"),
            data_prevista=date(2026, 5, 23),
        )
        lancamento_receita = LancamentoFinanceiro.objects.create(
            tipo="entrada",
            fluxo=LancamentoFinanceiro.FLUXO_FCO,
            natureza=LancamentoFinanceiro.NATUREZA_RECEITA_OPERACIONAL,
            valor=Decimal("100.00"),
            data_lancamento=date(2026, 5, 20),
            descricao=f"Receita Ledger API {sufixo}",
            status="realizado",
            cliente=cliente,
            evento=evento,
            receita_operacional=receita,
        )
        lancamento_despesa = LancamentoFinanceiro.objects.create(
            tipo="saida",
            fluxo=LancamentoFinanceiro.FLUXO_FCO,
            natureza=LancamentoFinanceiro.NATUREZA_DESPESA_OPERACIONAL,
            valor=Decimal("40.00"),
            data_lancamento=date(2026, 5, 21),
            descricao=f"Despesa Ledger API {sufixo}",
            status="realizado",
            cliente=cliente,
            evento=evento,
            despesa_operacional=despesa,
        )
        lancamento_investimento = LancamentoFinanceiro.objects.create(
            tipo="saida",
            fluxo=LancamentoFinanceiro.FLUXO_FCI,
            natureza=LancamentoFinanceiro.NATUREZA_INVESTIMENTO,
            valor=Decimal("70.00"),
            data_lancamento=date(2026, 5, 22),
            descricao=f"Investimento Ledger API {sufixo}",
            status="realizado",
            cliente=cliente,
            evento=evento,
            investimento=investimento,
        )
        lancamento_financiamento = LancamentoFinanceiro.objects.create(
            tipo="entrada",
            fluxo=LancamentoFinanceiro.FLUXO_FCF,
            natureza=LancamentoFinanceiro.NATUREZA_FINANCIAMENTO,
            valor=Decimal("120.00"),
            data_lancamento=date(2026, 5, 22),
            descricao=f"Financiamento Ledger API {sufixo}",
            status="realizado",
            cliente=cliente,
            evento=evento,
            financiamento_movimentacao=financiamento,
        )
        return SimpleNamespace(
            cliente=cliente,
            evento=evento,
            receita=receita,
            despesa=despesa,
            investimento=investimento,
            financiamento=financiamento,
            lancamento_receita=lancamento_receita,
            lancamento_despesa=lancamento_despesa,
            lancamento_investimento=lancamento_investimento,
            lancamento_financiamento=lancamento_financiamento,
        )

    def _csrf_token(self, client):
        response = client.get(reverse("caixa:api_auth_csrf"))
        self.assertEqual(response.status_code, 200, response.content[:200])
        return response.json()["csrfToken"]

