                "settlementReason",
                "notes",
                "isActive",
                "isRecurring",
                "monthsCount",
                "parentId",
                "generatedAutomatically",
                "recordType",
                "recordTypeLabel",
                "isOverdue",
                "createdAt",
                "updatedAt",
