    def _csv_export_rows(self, response):
        content = response.content.decode("utf-8-sig")
        return [line.split(";") for line in content.splitlines()]

    def _assert_exportacao_obrigacoes_csv_response(self, response, filename):
        self.assertEqual(response.status_code, 200, response.content[:200])
        self.assertEqual(response["Content-Type"], "text/csv; charset=utf-8")
        self.assertEqual(
            response["Content-Disposition"],
            f'attachment; filename="{filename}"',
        )
        self.assertIn("no-store", response["Cache-Control"])
        content = response.content.decode("utf-8")
        self.assertTrue(content.startswith("\ufeff"))
        self.assertIn(";", content.splitlines()[0])
        self.assertIn("\r\n", content)
        return content

    def test_api_clientes_get_preserva_auth_permissao_shape_aliases_e_headers(self):
        cliente_alvo = Cliente.objects.create(
            nome_razao_social="Cliente Canonico API",
            nome_fantasia="Canonico",
            tipo_pessoa="PJ",
            cpf_cnpj="12.345.678/0001-91",
            telefone="(85) 98888-0000",
            email="canonico@example.com",
            responsavel="Ana API",
            endereco="Rua Canonica, 10",
            observacoes="Cliente usado no contrato GET.",
            ativo=True,
        )
        Cliente.objects.create(
            nome_razao_social="Cliente Oculto API",
            tipo_pessoa="PF",
            cpf_cnpj="123.456.789-10",
            ativo=False,
        )
        url = reverse("caixa:api_clientes")

        resposta_nao_autenticada = Client().get(url, secure=True)
        usuario_sem_permissao = User.objects.create_user(
            username="api-clientes-get-sem-permissao",
            password="senha-segura",
        )
        client_sem_permissao = Client()
        client_sem_permissao.force_login(usuario_sem_permissao)
        resposta_sem_permissao = client_sem_permissao.get(url, secure=True)
        resposta = self.client.get(
            url,
            {"search": "Canonico", "personType": "PJ", "active": "sim"},
            secure=True,
        )

        self.assertEqual(resposta_nao_autenticada.status_code, 401)
        self.assertEqual(
            resposta_nao_autenticada.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(resposta_nao_autenticada)
        self.assertEqual(resposta_sem_permissao.status_code, 403)
