    def test_api_servicos_post_preserva_auth_permissao_e_erros_de_payload(self):
        url = reverse("caixa:api_servicos")
        client_anonimo = Client(enforce_csrf_checks=True)
        token_anonimo = self._csrf_token(client_anonimo)
        resposta_nao_autenticada = client_anonimo.post(
            url,
            data=json.dumps(self._servico_payload_api()),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_anonimo,
        )

        usuario_sem_permissao = User.objects.create_user(
            username="api-servicos-post-sem-permissao",
            password="senha-segura",
        )
        client_sem_permissao = Client(enforce_csrf_checks=True)
        client_sem_permissao.force_login(usuario_sem_permissao)
        token_sem_permissao = self._csrf_token(client_sem_permissao)
        resposta_sem_permissao = client_sem_permissao.post(
            url,
            data=json.dumps(self._servico_payload_api()),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_sem_permissao,
        )

        client_com_permissao = Client(enforce_csrf_checks=True)
        usuario_com_permissao = self._usuario_com_permissoes_caixa(
            "api-servicos-post-erros",
            "add_servico",
        )
        client_com_permissao.force_login(usuario_com_permissao)
        token_com_permissao = self._csrf_token(client_com_permissao)
        resposta_content_type = client_com_permissao.post(
            url,
            data="name=Servico",
            content_type="application/x-www-form-urlencoded",
            HTTP_X_CSRFTOKEN=token_com_permissao,
        )
        resposta_json_invalido = client_com_permissao.post(
            url,
            data='{"name":',
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_com_permissao,
        )
        resposta_validacao_texto = client_com_permissao.post(
            url,
            data=json.dumps(self._servico_payload_api(name="", code="")),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_com_permissao,
        )
        resposta_validacao_valores = client_com_permissao.post(
            url,
            data=json.dumps(
                self._servico_payload_api(
                    dailyRate="-1.00",
                    baseHours=0,
                    overtimePercent="-0.10",
                )
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_com_permissao,
        )

        self.assertEqual(resposta_nao_autenticada.status_code, 401)
        self.assertEqual(
            resposta_nao_autenticada.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(resposta_nao_autenticada)
        self.assertEqual(resposta_sem_permissao.status_code, 403)
        self.assertEqual(resposta_sem_permissao.json(), {"detail": "Permission denied."})
        self._assert_json_no_store(resposta_sem_permissao)
        self.assertEqual(resposta_content_type.status_code, 415)
        self.assertEqual(
            resposta_content_type.json(),
            {"detail": "Content-Type deve ser application/json."},
        )
        self._assert_json_no_store(resposta_content_type)
        self.assertEqual(resposta_json_invalido.status_code, 400)
        self.assertEqual(resposta_json_invalido.json(), {"detail": "JSON invalido."})
        self._assert_json_no_store(resposta_json_invalido)
        self.assertEqual(resposta_validacao_texto.status_code, 400)
        self.assertEqual(set(resposta_validacao_texto.json()), {"errors"})
        self.assertIn("nome", resposta_validacao_texto.json()["errors"])
        self.assertIn("codigo", resposta_validacao_texto.json()["errors"])
        self._assert_json_no_store(resposta_validacao_texto)
        self.assertEqual(resposta_validacao_valores.status_code, 400)
        self.assertEqual(
            set(resposta_validacao_valores.json()["errors"]),
            {"diaria_padrao", "horas_base_diaria", "percentual_hora_extra"},
        )
        self._assert_json_no_store(resposta_validacao_valores)

    def test_api_servicos_post_preserva_duplicidade_e_criacao_com_sucesso(self):
        url = reverse("caixa:api_servicos")
        client = Client(enforce_csrf_checks=True)
        usuario = self._usuario_com_permissoes_caixa(
            "api-servicos-post-sucesso",
            "add_servico",
        )
        client.force_login(usuario)
        csrf_token = self._csrf_token(client)
        Servico.objects.create(
            nome="Servico Existente API",
            codigo="servico-existente-api",
            diaria_padrao=Decimal("100.00"),
        )

        resposta_nome_duplicado = client.post(
            url,
            data=json.dumps(
                self._servico_payload_api(
                    name="Servico Existente API",
                    code="servico-novo-api",
                )
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        resposta_codigo_duplicado = client.post(
            url,
            data=json.dumps(
                self._servico_payload_api(
                    name="Servico Novo API",
                    code="servico-existente-api",
                )
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        resposta_sucesso = client.post(
            url,
            data=json.dumps(
                self._servico_payload_api(
                    name="Servico Criado PM40",
                    code="servico-criado-pm40",
                    dailyRate="180.00",
                    baseHours=6,
                    overtimePercent="1.75",
                    usesSpecialRule=True,
                    isActive=False,
                )
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        self.assertEqual(resposta_nome_duplicado.status_code, 400)
        self.assertEqual(
            resposta_nome_duplicado.json(),
            {"errors": {"nome": ["Ja existe um servico com este nome."]}},
        )
        self._assert_json_no_store(resposta_nome_duplicado)
        self.assertEqual(resposta_codigo_duplicado.status_code, 400)
        self.assertEqual(
            resposta_codigo_duplicado.json(),
            {"errors": {"codigo": ["Ja existe um servico com este codigo."]}},
        )
        self._assert_json_no_store(resposta_codigo_duplicado)
        self.assertEqual(resposta_sucesso.status_code, 201)
        self._assert_json_no_store(resposta_sucesso)
        payload = resposta_sucesso.json()["data"]
        servico = Servico.objects.get(codigo="servico-criado-pm40")
        self.assertEqual(set(payload), {"service", "message"})
        self.assertEqual(payload["message"], "Servico cadastrado com sucesso.")
        self._assert_servico_api_fields(payload["service"], servico)
        self.assertEqual(servico.nome, "Servico Criado PM40")
        self.assertEqual(servico.diaria_padrao, Decimal("180.00"))
        self.assertEqual(servico.horas_base_diaria, 6)
        self.assertEqual(servico.percentual_hora_extra, Decimal("1.75"))
        self.assertTrue(servico.usa_regra_especial)
        self.assertFalse(servico.ativo)

