        client = Client(enforce_csrf_checks=True)
        usuario = self._usuario_com_permissoes_caixa(
            "api-servico-detalhe-put-ci",
            "change_servico",
        )
        client.force_login(usuario)
        csrf_token = self._csrf_token(client)

        resposta_nome_duplicado = client.put(
            url,
            data=json.dumps(
                self._servico_payload_api(
                    name="montagem",
                    code="servico-alvo-ci-nome",
                )
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        resposta_codigo_duplicado = client.put(
            url,
            data=json.dumps(
                self._servico_payload_api(
                    name="Servico Alvo Codigo CI",
                    code="SRV-01",
                )
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        resposta_sucesso = client.put(
            url,
            data=json.dumps(
                self._servico_payload_api(
                    name="Servico Alvo Atualizado CI",
                    code="SERVICO-ATUALIZADO-CI",
                )
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        servico.refresh_from_db()

        self.assertEqual(resposta_nome_duplicado.status_code, 400)
        self.assertEqual(
            resposta_nome_duplicado.json(),
            {"errors": {"nome": ["Ja existe um servico com este nome."]}},
        )
        self._assert_json_no_store(resposta_nome_duplicado)
        self.assertEqual(resposta_codigo_duplicado.status_code, 400)
        self.assertEqual(
            resposta_codigo_duplicado.json(),
            {"errors": {"codigo": ["Ja existe um servico com este codigo."]}},
        )
        self._assert_json_no_store(resposta_codigo_duplicado)
        self.assertEqual(resposta_sucesso.status_code, 200)
        self.assertEqual(servico.nome, "Servico Alvo Atualizado CI")
        self.assertEqual(servico.codigo, "servico-atualizado-ci")
        self.assertEqual(resposta_sucesso.json()["data"]["service"]["code"], "servico-atualizado-ci")

