    def test_api_custos_fixos_criacao_csrf_autenticacao_e_permissao(self):
        url = reverse("caixa:api_custos_fixos")
        payload = self._custo_fixo_payload_api()
        usuario_add = self._usuario_com_permissoes_caixa(
            "custos-fixos-add",
            "add_custofixo",
        )
        usuario_sem_add = self._usuario_com_permissoes_caixa(
            "custos-fixos-sem-add",
            "view_custofixo",
        )
        cliente_sem_csrf = Client(enforce_csrf_checks=True)
        cliente_sem_csrf.force_login(usuario_add)

        resposta_sem_csrf = cliente_sem_csrf.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
        )

        cliente_anonimo = Client(enforce_csrf_checks=True)
        token_anonimo = self._csrf_token(cliente_anonimo)
        resposta_anonimo = cliente_anonimo.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_anonimo,
        )

        cliente_sem_add = Client(enforce_csrf_checks=True)
        cliente_sem_add.force_login(usuario_sem_add)
        token_sem_add = self._csrf_token(cliente_sem_add)
        resposta_sem_add = cliente_sem_add.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_sem_add,
        )

        self.assertEqual(resposta_sem_csrf.status_code, 403)
        self.assertEqual(CustoFixo.objects.count(), 0)
        self.assertEqual(resposta_anonimo.status_code, 401)
        self.assertEqual(
            resposta_anonimo.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(resposta_anonimo)
        self.assertEqual(resposta_sem_add.status_code, 403)
        self.assertEqual(
            resposta_sem_add.json(),
            {"detail": "Permission denied."},
        )
        self._assert_json_no_store(resposta_sem_add)
        self.assertEqual(CustoFixo.objects.count(), 0)

    def test_api_custos_fixos_criacao_erros_de_payload_preservam_contrato(self):
        url = reverse("caixa:api_custos_fixos")
        usuario_add = self._usuario_com_permissoes_caixa(
            "custos-fixos-validacao",
            "add_custofixo",
        )
        client = Client()
        client.force_login(usuario_add)

        resposta_content_type = client.post(
            url,
            data="sem-json",
            content_type="text/plain",
        )
        resposta_json_invalido = client.post(
            url,
            data="{",
            content_type="application/json",
        )
        resposta_nao_dict = client.post(
            url,
            data=json.dumps(["lista"]),
            content_type="application/json",
        )

        self.assertEqual(resposta_content_type.status_code, 415)
        self.assertEqual(
            resposta_content_type.json(),
            {"detail": "Content-Type deve ser application/json."},
        )
        self._assert_json_no_store(resposta_content_type)
        self.assertEqual(resposta_json_invalido.status_code, 400)
        self.assertEqual(resposta_json_invalido.json(), {"detail": "JSON invalido."})
        self._assert_json_no_store(resposta_json_invalido)
        self.assertEqual(resposta_nao_dict.status_code, 400)
        self.assertEqual(resposta_nao_dict.json(), {"detail": "JSON invalido."})
        self._assert_json_no_store(resposta_nao_dict)

        casos = [
            ("valor_previsto_negativo", {"plannedAmount": "-1.00"}, "valor_previsto"),
            ("valor_pago_negativo", {"paidAmount": "-1.00"}, "valor_pago"),
            (
                "valor_pago_maior_que_previsto",
                {"plannedAmount": "100.00", "paidAmount": "101.00"},
                "valor_pago",
            ),
            ("data_vencimento_ausente", {"dueDate": ""}, "data_vencimento"),
            ("data_vencimento_invalida", {"dueDate": "nao-e-data"}, "data_vencimento"),
            ("quantidade_meses_invalida", {"monthsCount": "0"}, "quantidade_meses"),
            (
                "baixa_manual_sem_motivo",
                {"manuallySettled": True, "settlementReason": ""},
                "motivo_baixa",
            ),
            ("categoria_invalida", {"category": "invalida"}, "categoria"),
            ("status_invalido", {"status": "invalido"}, "status"),
        ]

        for nome, overrides, campo in casos:
            with self.subTest(nome=nome):
                resposta = client.post(
                    url,
                    data=json.dumps(self._custo_fixo_payload_api(**overrides)),
                    content_type="application/json",
                )

                self.assertEqual(resposta.status_code, 400, resposta.content[:200])
                self._assert_json_no_store(resposta)
                payload = resposta.json()
                self.assertEqual(set(payload), {"errors"})
                self.assertIn(campo, payload["errors"])

    def test_api_custos_fixos_criacao_sucesso_preserva_shape_recorrencia_e_sincronizacoes(self):
        criar_entrada_caixa_teste(valor=Decimal("1000.00"), data=date(2026, 6, 1))
        url = reverse("caixa:api_custos_fixos")
