    def test_api_custos_por_evento_agrupa_orcamentos_aprovados_por_evento(self):
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Agrupamento Evento API",
            tipo_pessoa="PJ",
            cpf_cnpj="12.345.678/0001-88",
        )
        configuracao = ConfiguracaoFinanceira.objects.create(
            nome="Config Agrupamento Evento API",
            valor_alimentacao=Decimal("20.00"),
            valor_transporte=Decimal("14.00"),
            margem_lucro=Decimal("0.30"),
            aliquota_imposto=Decimal("0.06"),
            data_inicio_vigencia=date(2026, 1, 1),
        )
        servico_limpeza = Servico.objects.create(
            nome="Limpeza Agrupamento API",
            codigo="limpeza-agrupamento-api",
            diaria_padrao=Decimal("100.00"),
            horas_base_diaria=8,
            percentual_hora_extra=Decimal("1.50"),
        )
        servico_seguranca = Servico.objects.create(
            nome="Seguranca Agrupamento API",
            codigo="seguranca-agrupamento-api",
            diaria_padrao=Decimal("120.00"),
            horas_base_diaria=8,
            percentual_hora_extra=Decimal("1.50"),
        )

        def aprovar_orcamento(numero, descricao_extra):
            orcamento = Orcamento.objects.create(
                cliente=cliente,
                configuracao_financeira=configuracao,
                numero=numero,
                nome_evento="Evento Compartilhado Agrupamento",
                data_evento=date(2026, 5, 20),
                status="enviado",
            )
            OrcamentoItem.objects.create(
                orcamento=orcamento,
                servico=servico_limpeza,
                horas_por_dia=8,
                quantidade_dias=1,
                quantidade_pessoas=1,
            )
            OrcamentoItem.objects.create(
                orcamento=orcamento,
                servico=servico_seguranca,
                horas_por_dia=8,
                quantidade_dias=1,
                quantidade_pessoas=1,
            )
            OrcamentoCustoExtra.objects.create(
                orcamento=orcamento,
                categoria="logistica",
                descricao=descricao_extra,
                valor_previsto=Decimal("50.00"),
                data_vencimento=date(2026, 5, 20),
            )
            return orcamento.aprovar_e_gerar_evento()

        evento_a = aprovar_orcamento("AGRUP-001", "Extra exclusivo A")
        evento_b = aprovar_orcamento("AGRUP-002", "Extra exclusivo B")

        self.assertEqual(Orcamento.objects.filter(status="aprovado").count(), 2)
        self.assertEqual(Evento.objects.count(), 2)
        self.assertEqual(EventoCustoServico.objects.count(), 4)
        self.assertEqual(EventoCustoExtra.objects.count(), 2)

        response = self.client.get(
            reverse("caixa:api_custos_por_evento"),
            {"period": "all"},
            secure=True,
        )

        self.assertEqual(response.status_code, 200, response.content[:200])
        payload = response.json()["data"]
        grupos = payload["groups"]
        grupos_por_evento = {grupo["eventId"]: grupo for grupo in grupos}

        self.assertEqual(payload["summary"]["eventsCount"], 2)
        self.assertEqual(len(grupos), 2)
        self.assertEqual(set(grupos_por_evento), {evento_a.id, evento_b.id})

        for evento, descricao_extra in [
            (evento_a, "Extra exclusivo A"),
            (evento_b, "Extra exclusivo B"),
        ]:
            grupo = grupos_por_evento[evento.id]
            itens_servico = [
                item for item in grupo["items"] if item["source"] == "custo_servico"
            ]
            itens_extra = [
                item for item in grupo["items"] if item["source"] == "custo_extra"
            ]
            descricoes_extra = [
                detalhe["description"]
                for categoria in grupo["extraCostBreakdown"]
                for detalhe in categoria["items"]
            ]

            self.assertEqual(len(itens_servico), 2)
            self.assertEqual(len(itens_extra), 1)
            self.assertEqual(
                sorted(item["description"] for item in itens_servico),
                ["Limpeza Agrupamento API", "Seguranca Agrupamento API"],
            )
            self.assertEqual(descricoes_extra, [descricao_extra])

