    def test_api_criar_custo_extra_evento_requer_csrf_em_cliente_real(self):
        client = Client(enforce_csrf_checks=True)
        usuario = User.objects.create_user("api-extra-csrf", password="senha")
        usuario.user_permissions.add(Permission.objects.get(codename="add_eventocustoextra"))
        client.force_login(usuario)

        resposta = client.post(
            reverse("caixa:api_criar_custo_extra_evento"),
            data=json.dumps(
                {
                    "eventId": 1,
                    "category": "material",
                    "description": "Custo sem csrf",
                    "plannedAmount": "100.00",
                    "dueDate": "2026-06-20",
                }
            ),
            content_type="application/json",
        )

        self.assertEqual(resposta.status_code, 403)
        self.assertFalse(EventoCustoExtra.objects.exists())

        client_com_csrf = Client(enforce_csrf_checks=True)
        usuario_com_csrf = User.objects.create_user("api-extra-csrf-ok", password="senha")
        usuario_com_csrf.user_permissions.add(
            Permission.objects.get(codename="add_eventocustoextra")
        )
        client_com_csrf.force_login(usuario_com_csrf)
        csrf_token = client_com_csrf.get(reverse("caixa:api_auth_csrf")).json()["csrfToken"]

        resposta_com_csrf = client_com_csrf.post(
            reverse("caixa:api_criar_custo_extra_evento"),
            data=json.dumps(
                {
                    "eventId": 999999,
                    "category": "material",
                    "description": "Custo com csrf valido",
                    "plannedAmount": "100.00",
                    "dueDate": "2026-06-20",
                }
            ),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        self.assertEqual(resposta_com_csrf.status_code, 400)
        self.assertIn("errors", resposta_com_csrf.json())
        self.assertIn("evento", resposta_com_csrf.json()["errors"])

