    def test_dashboard_mantem_queries_constantes_com_mais_registros(self):
        self._criar_lote_dashboard_performance(1, deslocamento=0)
        queries_com_um, contexto_um = self._contar_queries_contexto_dashboard()

        self._criar_lote_dashboard_performance(8, deslocamento=100)
        queries_com_nove, contexto_nove = self._contar_queries_contexto_dashboard()

        self.assertEqual(queries_com_nove, queries_com_um)
        self.assertLessEqual(queries_com_nove, 25)
        self.assertGreater(len(contexto_um["movimentacoes"]), 0)
        self.assertGreater(
            len(contexto_nove["movimentacoes"]),
            len(contexto_um["movimentacoes"]),
        )

