    def test_apis_cadastros_mantem_queries_constantes_com_mais_registros(self):
        self._criar_lote_cadastros_performance(1, deslocamento=800)
        endpoints = [
            ("clientes", reverse("caixa:api_clientes"), {}, "clients"),
            ("orcamentos", reverse("caixa:api_orcamentos"), {}, "budgets"),
            (
                "eventos",
                reverse("caixa:api_eventos"),
                {"periodo_rapido": "todos"},
                "events",
            ),
        ]
        consultas_base = {}
        tamanhos_base = {}

        for nome, url, params, collection_key in endpoints:
            with self.subTest(api=nome, fase="base"):
                consultas, payload = self._contar_queries_payload_api(url, params)

            consultas_base[nome] = consultas
            tamanhos_base[nome] = len(payload[collection_key])

        self._criar_lote_cadastros_performance(8, deslocamento=900)

        for nome, url, params, collection_key in endpoints:
            with self.subTest(api=nome, fase="crescimento"):
                consultas, payload = self._contar_queries_payload_api(url, params)

            self.assertEqual(consultas, consultas_base[nome])
            self.assertLessEqual(consultas, 25)
            self.assertGreater(len(payload[collection_key]), tamanhos_base[nome])

