    def test_api_fcf_debts_preserva_auth_permissao_csrf_e_headers(self):
        credor = Credor.objects.create(nome="Banco Auth Divida FCF")
        url = reverse("caixa:api_criar_divida_financeira")
        payload = self._fcf_debt_payload(credor)

        token_anonimo = "c" * 32
        anonimo = Client(enforce_csrf_checks=True)
        anonimo.cookies[settings.CSRF_COOKIE_NAME] = token_anonimo
        response_anonimo = anonimo.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=token_anonimo,
        )

        self.assertEqual(response_anonimo.status_code, 401)
        self.assertEqual(
            response_anonimo.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(response_anonimo)

        usuario_sem_permissao = self._usuario_com_permissoes_caixa(
            "api-fcf-debt-sem-add",
            "view_parceladivida",
        )
        client_sem_permissao, csrf_headers_sem_permissao = self._csrf_client_for_user(
            usuario_sem_permissao
        )
        response_sem_permissao = client_sem_permissao.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            **csrf_headers_sem_permissao,
        )

        self.assertEqual(response_sem_permissao.status_code, 403)
        self.assertEqual(response_sem_permissao.json(), {"detail": "Permission denied."})
        self._assert_json_no_store(response_sem_permissao)

        usuario_com_add = self._usuario_com_permissoes_caixa(
            "api-fcf-debt-add",
            "add_dividafinanceira",
        )
        client_sem_csrf = Client(enforce_csrf_checks=True)
        client_sem_csrf.force_login(usuario_com_add)
        response_sem_csrf = client_sem_csrf.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
        )

        self.assertEqual(response_sem_csrf.status_code, 403)
        self.assertIn("text/html", response_sem_csrf["Content-Type"])

        client_com_csrf, csrf_headers_com_add = self._csrf_client_for_user(
            usuario_com_add
        )
        response_com_csrf = client_com_csrf.post(
            url,
            data=json.dumps(self._fcf_debt_payload(credor, contractedAmount="invalido")),
            content_type="application/json",
            **csrf_headers_com_add,
        )

        self.assertEqual(response_com_csrf.status_code, 400)
        self.assertEqual(
            response_com_csrf.json(),
            {"errors": {"contractedAmount": ["Valor contratado invalido."]}},
        )
        self._assert_json_no_store(response_com_csrf)
        self.assertEqual(DividaFinanceira.objects.count(), 0)
        self.assertEqual(ParcelaDivida.objects.count(), 0)
        self.assertEqual(FinanciamentoMovimentacao.objects.count(), 0)

    def test_api_fcf_debts_preserva_erros_de_content_type_json_e_validacao(self):
        usuario = self._usuario_com_permissoes_caixa(
            "api-fcf-debt-erros",
            "add_dividafinanceira",
        )
        client, csrf_headers = self._csrf_client_for_user(usuario)
        credor = Credor.objects.create(nome="Banco Erros Divida FCF")
        url = reverse("caixa:api_criar_divida_financeira")

        response_content_type = client.post(
            url,
            data="description=Divida",
            content_type="text/plain",
            **csrf_headers,
        )
        response_json_invalido = client.post(
            url,
            data="{",
            content_type="application/json",
            **csrf_headers,
        )
        response_body_lista = client.post(
            url,
            data=json.dumps(["nao-dict"]),
            content_type="application/json",
            **csrf_headers,
        )

        self.assertEqual(response_content_type.status_code, 415)
        self.assertEqual(
            response_content_type.json(),
            {"detail": "Content-Type deve ser application/json."},
        )
        self._assert_json_no_store(response_content_type)

        for response in (response_json_invalido, response_body_lista):
            self.assertEqual(response.status_code, 400)
            self.assertEqual(response.json(), {"detail": "JSON invalido."})
            self._assert_json_no_store(response)

        casos = [
            (
                "credor-invalido",
                self._fcf_debt_payload(credor, creditorId="abc"),
                "creditorId",
                ["Credor invalido."],
            ),
            (
                "credor-inexistente",
                self._fcf_debt_payload(credor, creditorId=999999),
                "creditorId",
                ["Credor nao encontrado."],
            ),
            (
                "evento-invalido",
                self._fcf_debt_payload(credor, eventId="evento-invalido"),
                "eventId",
                ["Evento invalido."],
            ),
            (
                "evento-inexistente",
                self._fcf_debt_payload(credor, eventId=999999),
                "eventId",
                ["Evento nao encontrado."],
            ),
            (
                "valor-contratado-invalido",
                self._fcf_debt_payload(credor, contractedAmount="valor"),
                "contractedAmount",
                ["Valor contratado invalido."],
            ),
            (
                "juros-invalido",
                self._fcf_debt_payload(credor, monthlyInterestRate="valor"),
                "monthlyInterestRate",
                ["Taxa de juros mensal invalida."],
            ),
            (
                "parcelas-invalidas",
                self._fcf_debt_payload(credor, installmentsCount=0),
                "installmentsCount",
                ["Quantidade de parcelas invalida."],
            ),
            (
                "dia-invalido",
                self._fcf_debt_payload(credor, dueDay=0),
                "dueDay",
                ["Dia de vencimento invalido."],
            ),
            (
                "data-invalida",
                self._fcf_debt_payload(credor, contractedDate="data-invalida"),
                "contractedDate",
                ["Data de contratacao invalida."],
            ),
        ]

        for nome, payload, campo, mensagens in casos:
            with self.subTest(nome=nome):
                response = client.post(
                    url,
                    data=json.dumps(payload),
                    content_type="application/json",
                    **csrf_headers,
                )
                self.assertEqual(response.status_code, 400)
                self.assertEqual(response.json(), {"errors": {campo: mensagens}})
                self._assert_json_no_store(response)

        response_tipo_invalido = client.post(
            url,
            data=json.dumps(self._fcf_debt_payload(credor, type="tipo-invalido")),
            content_type="application/json",
            **csrf_headers,
        )
        self.assertEqual(response_tipo_invalido.status_code, 400)
        self.assertIn("tipo", response_tipo_invalido.json()["errors"])
        self._assert_json_no_store(response_tipo_invalido)
        self.assertEqual(DividaFinanceira.objects.count(), 0)
        self.assertEqual(ParcelaDivida.objects.count(), 0)
        self.assertEqual(FinanciamentoMovimentacao.objects.count(), 0)

    def test_api_fcf_debts_preserva_405_manual_sem_allow(self):
        usuario = self._usuario_com_permissoes_caixa(
            "api-fcf-debt-405",
            "add_dividafinanceira",
        )
        self.client.force_login(usuario)
        url = reverse("caixa:api_criar_divida_financeira")

        for metodo in ("get", "put", "patch", "delete"):
            with self.subTest(metodo=metodo):
                if metodo == "get":
                    response = self.client.get(url)
                else:
                    response = getattr(self.client, metodo)(
                        url,
                        data=json.dumps({}),
                        content_type="application/json",
                    )

                self.assertEqual(response.status_code, 405)
                self.assertEqual(response.json(), {"detail": "Metodo nao permitido."})
                self.assertNotIn("Allow", response.headers)
                self._assert_json_no_store(response)

        self.assertEqual(DividaFinanceira.objects.count(), 0)
        self.assertEqual(ParcelaDivida.objects.count(), 0)

