    def test_api_credores_financiamentos_retorna_cadastro_ativo_para_frontend(self):
        self.user.user_permissions.add(Permission.objects.get(codename="view_credor"))
        credor_b = Credor.objects.create(
            nome="Banco Beta",
            documento="22.222.222/0001-22",
        )
        credor_a = Credor.objects.create(
            nome="Banco Alpha",
            documento="11.111.111/0001-11",
        )
        Credor.objects.create(nome="Banco Inativo", ativo=False)

        response = self.client.get(
            reverse("caixa:api_credores_financiamentos"),
            secure=True,
        )
        payload = response.json()

        self.assertEqual(response.status_code, 200)
        self.assertEqual(response["Content-Type"], "application/json")
        self.assertIn("no-store", response["Cache-Control"])
        self.assertEqual(set(payload), {"creditors", "credores", "meta", "permissions"})
        self.assertEqual(payload["meta"]["count"], 2)
        self.assertTrue(payload["meta"]["onlyActive"])
        self.assertEqual(payload["meta"]["source"], "cadastro_credor")
        self.assertEqual(set(payload["meta"]), {"count", "onlyActive", "source"})
        self.assertEqual(set(payload["permissions"]), {"canCreate"})
        self.assertEqual(payload["credores"], ["Banco Alpha", "Banco Beta"])
        self.assertFalse(payload["permissions"]["canCreate"])
        self.assertEqual(
            [credor["creditorId"] for credor in payload["creditors"]],
            [credor_a.id, credor_b.id],
        )
        self.assertEqual(
            [credor["label"] for credor in payload["creditors"]],
            ["Banco Alpha", "Banco Beta"],
        )
        self.assertEqual(
            set(payload["creditors"][0]),
            {
                "id",
                "value",
                "label",
                "name",
                "credor_id",
                "creditorId",
                "credor_nome",
                "creditorName",
                "document",
                "isActive",
                "notes",
                "observacao",
                "createdAt",
                "criado_em",
                "updatedAt",
                "atualizado_em",
            },
        )
        self.assertEqual(payload["creditors"][0]["id"], str(credor_a.id))
        self.assertEqual(payload["creditors"][0]["value"], str(credor_a.id))
        self.assertEqual(payload["creditors"][0]["document"], "11.111.111/0001-11")
        self.assertEqual(payload["creditors"][0]["name"], "Banco Alpha")
        self.assertEqual(payload["creditors"][0]["creditorName"], "Banco Alpha")
        self.assertEqual(payload["creditors"][0]["credor_id"], credor_a.id)
        self.assertEqual(payload["creditors"][0]["credor_nome"], "Banco Alpha")
        self.assertEqual(payload["creditors"][0]["notes"], "")
        self.assertEqual(payload["creditors"][0]["observacao"], "")
        self.assertTrue(payload["creditors"][0]["isActive"])
        self.assertIn("createdAt", payload["creditors"][0])
        self.assertEqual(payload["creditors"][0]["createdAt"], payload["creditors"][0]["criado_em"])
        self.assertIn("updatedAt", payload["creditors"][0])
        self.assertEqual(payload["creditors"][0]["updatedAt"], payload["creditors"][0]["atualizado_em"])

