        self.assertEqual(credor.atualizado_por, self.user)
        self.assertEqual(DividaFinanceira.objects.count(), 0)
        self.assertEqual(ParcelaDivida.objects.count(), 0)
        self.assertEqual(ObrigacaoFinanceira.objects.count(), 0)
        self.assertEqual(BaixaFinanceira.objects.count(), 0)
        self.assertEqual(LancamentoFinanceiro.objects.count(), 0)

