    def test_api_credores_financiamentos_get_preserva_auth_permissao_e_headers(self):
        url = reverse("caixa:api_credores_financiamentos")

        self.client.logout()
        resposta_anonima = self.client.get(url, secure=True)

        usuario_sem_permissao = User.objects.create_user(
            "api-credores-sem-view",
            password="senha",
        )
        self.client.force_login(usuario_sem_permissao)
        resposta_sem_permissao = self.client.get(url, secure=True)

        self.assertEqual(resposta_anonima.status_code, 401)
        self.assertEqual(resposta_anonima["Content-Type"], "application/json")
        self.assertIn("no-store", resposta_anonima["Cache-Control"])
        self.assertEqual(
            resposta_anonima.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self.assertEqual(resposta_sem_permissao.status_code, 403)
        self.assertEqual(resposta_sem_permissao["Content-Type"], "application/json")
        self.assertIn("no-store", resposta_sem_permissao["Cache-Control"])
        self.assertEqual(resposta_sem_permissao.json(), {"detail": "Permission denied."})

    def test_api_credores_financiamentos_post_preserva_csrf_auth_e_permissoes(self):
        url = reverse("caixa:api_credores_financiamentos")
        payload = {"name": "Banco CSRF"}

        client_csrf = Client(enforce_csrf_checks=True)
        usuario_com_permissoes = User.objects.create_user(
            "api-credores-csrf",
            password="senha",
        )
        usuario_com_permissoes.user_permissions.add(
            Permission.objects.get(codename="view_credor"),
            Permission.objects.get(codename="add_credor"),
        )
        client_csrf.force_login(usuario_com_permissoes)

        resposta_sem_csrf = client_csrf.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
        )

        csrf_token = client_csrf.get(reverse("caixa:api_auth_csrf")).json()["csrfToken"]
        resposta_com_csrf = client_csrf.post(
            url,
            data=json.dumps({"name": ""}),
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )

        self.client.logout()
        resposta_anonima = self.client.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            secure=True,
        )

        usuario_sem_view = User.objects.create_user(
            "api-credores-post-sem-view",
            password="senha",
        )
        self.client.force_login(usuario_sem_view)
        resposta_sem_view = self.client.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            secure=True,
        )

        usuario_sem_add = User.objects.create_user(
            "api-credores-post-sem-add",
            password="senha",
        )
        usuario_sem_add.user_permissions.add(Permission.objects.get(codename="view_credor"))
        self.client.force_login(usuario_sem_add)
        resposta_sem_add = self.client.post(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            secure=True,
        )

        self.assertEqual(resposta_sem_csrf.status_code, 403)
        self.assertFalse(Credor.objects.filter(nome="Banco CSRF").exists())
        self.assertEqual(resposta_com_csrf.status_code, 400)
        self.assertEqual(resposta_com_csrf["Content-Type"], "application/json")
        self.assertIn("errors", resposta_com_csrf.json())
        self.assertIn("nome", resposta_com_csrf.json()["errors"])
        self.assertEqual(resposta_anonima.status_code, 401)
        self.assertEqual(
            resposta_anonima.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self.assertEqual(resposta_sem_view.status_code, 403)
        self.assertEqual(resposta_sem_view.json(), {"detail": "Permission denied."})
        self.assertEqual(resposta_sem_add.status_code, 403)
        self.assertEqual(resposta_sem_add.json(), {"detail": "Permission denied."})
        self.assertFalse(Credor.objects.filter(nome="Banco CSRF").exists())

    def test_api_credores_financiamentos_post_erros_de_payload_preservam_contrato(self):
        self.user.user_permissions.add(
            Permission.objects.get(codename="view_credor"),
            Permission.objects.get(codename="add_credor"),
        )
        url = reverse("caixa:api_credores_financiamentos")

        resposta_content_type = self.client.post(
            url,
            data="name=Banco",
            content_type="application/x-www-form-urlencoded",
            secure=True,
        )
        resposta_json_invalido = self.client.post(
            url,
            data='{"name":',
            content_type="application/json",
            secure=True,
        )
        resposta_body_nao_dict = self.client.post(
            url,
            data=json.dumps(["Banco"]),
            content_type="application/json",
            secure=True,
        )
        resposta_nome_vazio = self.client.post(
            url,
            data=json.dumps({"name": "   "}),
            content_type="application/json",
            secure=True,
        )

        self.assertEqual(resposta_content_type.status_code, 415)
        self.assertEqual(
            resposta_content_type.json(),
            {"detail": "Content-Type deve ser application/json."},
        )
        self.assertEqual(resposta_json_invalido.status_code, 400)
        self.assertEqual(resposta_json_invalido.json(), {"detail": "JSON invalido."})
        self.assertEqual(resposta_body_nao_dict.status_code, 400)
        self.assertEqual(resposta_body_nao_dict.json(), {"detail": "JSON invalido."})
        self.assertEqual(resposta_nome_vazio.status_code, 400)
        self.assertIn("nome", resposta_nome_vazio.json()["errors"])

        for response in (
            resposta_content_type,
            resposta_json_invalido,
            resposta_body_nao_dict,
            resposta_nome_vazio,
        ):
            with self.subTest(status=response.status_code):
                self.assertEqual(response["Content-Type"], "application/json")
                self.assertIn("no-store", response["Cache-Control"])

    def test_api_credores_financiamentos_post_preserva_aliases_defaults_e_efeitos(self):
        self.user.user_permissions.add(
            Permission.objects.get(codename="view_credor"),
            Permission.objects.get(codename="add_credor"),
        )
        url = reverse("caixa:api_credores_financiamentos")
        casos = [
            (
                {
                    "nome": "Banco Alias Legado",
                    "documento": "44.444.444/0001-44",
                    "observacao": "Observacao legada",
                    "ativo": False,
                },
                "Banco Alias Legado",
                "44.444.444/0001-44",
                "Observacao legada",
                False,
            ),
            (
                {
                    "name": "Banco Observation Alias",
                    "document": "55.555.555/0001-55",
                    "observation": "Observation alias",
                },
                "Banco Observation Alias",
                "55.555.555/0001-55",
                "Observation alias",
                True,
            ),
        ]

        for payload, nome, documento, observacao, ativo in casos:
            with self.subTest(nome=nome):
                counts_before = {
                    "debts": DividaFinanceira.objects.count(),
                    "installments": ParcelaDivida.objects.count(),
                    "obligations": ObrigacaoFinanceira.objects.count(),
                    "write_offs": BaixaFinanceira.objects.count(),
                    "ledger": LancamentoFinanceiro.objects.count(),
                    "movements": FinanciamentoMovimentacao.objects.count(),
                }
                response = self.client.post(
                    url,
                    data=json.dumps(payload),
                    content_type="application/json",
                    secure=True,
                )
                response_payload = response.json()["data"]["creditor"]
                credor = Credor.objects.get(nome=nome)

                self.assertEqual(response.status_code, 201)
                self.assertEqual(response["Content-Type"], "application/json")
                self.assertIn("no-store", response["Cache-Control"])
                self.assertEqual(response_payload["creditorId"], credor.id)
                self.assertEqual(response_payload["name"], nome)
                self.assertEqual(response_payload["creditorName"], nome)
                self.assertEqual(response_payload["document"], documento)
                self.assertEqual(response_payload["notes"], observacao)
                self.assertEqual(response_payload["observacao"], observacao)
                self.assertEqual(response_payload["isActive"], ativo)
                self.assertEqual(credor.documento, documento)
                self.assertEqual(credor.observacao, observacao)
                self.assertEqual(credor.ativo, ativo)
                self.assertEqual(credor.criado_por, self.user)
                self.assertEqual(credor.atualizado_por, self.user)
                self.assertEqual(DividaFinanceira.objects.count(), counts_before["debts"])
                self.assertEqual(ParcelaDivida.objects.count(), counts_before["installments"])
                self.assertEqual(
                    ObrigacaoFinanceira.objects.count(),
                    counts_before["obligations"],
                )
                self.assertEqual(BaixaFinanceira.objects.count(), counts_before["write_offs"])
                self.assertEqual(LancamentoFinanceiro.objects.count(), counts_before["ledger"])
                self.assertEqual(
                    FinanciamentoMovimentacao.objects.count(),
                    counts_before["movements"],
                )

    def test_api_credores_financiamentos_metodos_nao_permitidos_preservam_405(self):
        self.user.user_permissions.add(Permission.objects.get(codename="view_credor"))
        url = reverse("caixa:api_credores_financiamentos")

        for method_name in ("put", "patch", "delete"):
            with self.subTest(method=method_name):
                response = getattr(self.client, method_name)(
                    url,
                    data="{}",
                    content_type="application/json",
                    secure=True,
                )

                self.assertEqual(response.status_code, 405)
                self.assertEqual(response["Content-Type"], "application/json")
                self.assertIn("no-store", response["Cache-Control"])
                self.assertEqual(response.json(), {"detail": "Metodo nao permitido."})
                self.assertNotIn("Allow", response.headers)

    def test_api_financiamentos_filtra_por_id_do_credor_cadastrado(self):
        credor_alvo = Credor.objects.create(nome="Banco Filtro ID")
        credor_outro = Credor.objects.create(nome="Banco Fora ID")
        divida_alvo = DividaFinanceira.objects.create(
            descricao="Divida filtro credor alvo",
            credor="",
            credor_cadastro=credor_alvo,
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        divida_outro = DividaFinanceira.objects.create(
            descricao="Divida filtro credor fora",
            credor="",
            credor_cadastro=credor_outro,
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        ParcelaDivida.objects.create(
            divida=divida_alvo,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 10),
            data_vencimento_atual=date(2026, 5, 10),
            valor_principal=Decimal("100.00"),
            valor_juros=Decimal("0.00"),
        )
        ParcelaDivida.objects.create(
            divida=divida_outro,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 10),
            data_vencimento_atual=date(2026, 5, 10),
            valor_principal=Decimal("100.00"),
            valor_juros=Decimal("0.00"),
        )

        response = self.client.get(
            reverse("caixa:api_financiamentos"),
            {"creditorId": str(credor_alvo.id)},
        )
        payload = response.json()

        self.assertEqual(response.status_code, 200)
        self.assertEqual(len(payload["debts"]), 1)
        self.assertEqual(payload["debts"][0]["creditorId"], credor_alvo.id)
        self.assertEqual(payload["debts"][0]["creditorName"], "Banco Filtro ID")
        valores_credores = {
            opcao["value"] for opcao in payload["filterOptions"]["creditors"]
        }
        self.assertEqual(
            valores_credores,
            {str(credor_alvo.id), str(credor_outro.id)},
        )
        self.assertEqual(payload["filters"]["credor"], str(credor_alvo.id))
        self.assertEqual(payload["filters"]["creditorId"], str(credor_alvo.id))
        self.assertEqual(payload["filters"]["credor_id"], str(credor_alvo.id))

