    def test_api_financiamentos_filtra_movimentacoes_por_source_type(self):
        divida = DividaFinanceira.objects.create(
            descricao="Emprestimo filtro origem FCF",
            credor="Banco Origem FCF",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("500.00"),
            quantidade_parcelas=1,
        )
        automatica = FinanciamentoMovimentacao.objects.get(divida_financeira=divida)
        manual = FinanciamentoMovimentacao.objects.create(
            descricao="Movimentacao manual filtro origem FCF",
            categoria="aporte_socio",
            tipo_fluxo="entrada",
            valor_previsto=Decimal("100.00"),
            valor_realizado=Decimal("100.00"),
            data_prevista=date(2026, 5, 2),
            data_realizacao=date(2026, 5, 2),
        )

        cenarios = (
            (
                {"sourceType": "divida_automatica"},
                automatica.id,
                "divida_automatica",
                "true",
            ),
            (
                {"sourceType": "manual"},
                manual.id,
                "manual",
                "false",
            ),
        )

        for parametros, movimento_id, source_type, automatic_from_debt in cenarios:
            with self.subTest(parametros=parametros):
                response = self.client.get(
                    reverse("caixa:api_financiamentos"),
                    {"quickPeriod": "todos", **parametros},
                )
                payload = response.json()

                self.assertEqual(response.status_code, 200)
                self.assertEqual(
                    [movimento["id"] for movimento in payload["financingMovements"]],
                    [movimento_id],
                )
                self.assertEqual(payload["filters"]["sourceType"], source_type)
                self.assertEqual(
                    payload["filters"]["movementSourceType"],
                    source_type,
                )
                self.assertEqual(
                    payload["filters"]["origem_movimentacao"],
                    source_type,
                )
                self.assertEqual(
                    payload["filters"]["automaticFromDebt"],
                    automatic_from_debt,
                )

        self.assertIn(
            {
                "valor": "divida_automatica",
                "rotulo": "Entrada automatica da divida",
                "value": "divida_automatica",
                "label": "Entrada automatica da divida",
            },
            payload["filterOptions"]["financingMovementSourceTypes"],
        )
        self.assertIn(
            {
                "valor": "manual",
                "rotulo": "Movimentacao FCF manual",
                "value": "manual",
                "label": "Movimentacao FCF manual",
            },
            payload["filterOptions"]["movementSourceTypes"],
        )

