    def test_api_financiamentos_preserva_auth_permissoes_e_headers(self):
        url = reverse("caixa:api_financiamentos")
        anonimo = Client()

        for metodo in ("get", "post"):
            with self.subTest(usuario="anonimo", metodo=metodo):
                if metodo == "get":
                    response = anonimo.get(url)
                else:
                    response = anonimo.post(
                        url,
                        data=json.dumps(self._fcf_payload()),
                        content_type="application/json",
                    )

                self.assertEqual(response.status_code, 401)
                self.assertEqual(
                    response.json(),
                    {"detail": "Authentication credentials were not provided."},
                )
                self._assert_json_no_store(response)

        usuario_sem_view = self._usuario_com_permissoes_caixa(
            "api-fcf-sem-view",
        )
        self.client.force_login(usuario_sem_view)

        for metodo in ("get", "post"):
            with self.subTest(usuario="sem-view", metodo=metodo):
                if metodo == "get":
                    response = self.client.get(url)
                else:
                    response = self.client.post(
                        url,
                        data=json.dumps(self._fcf_payload()),
                        content_type="application/json",
                    )

                self.assertEqual(response.status_code, 403)
                self.assertEqual(response.json(), {"detail": "Permission denied."})
                self._assert_json_no_store(response)

        usuario_view_sem_add = self._usuario_com_permissoes_caixa(
            "api-fcf-view-sem-add",
            "view_parceladivida",
        )
        self.client.force_login(usuario_view_sem_add)

        response_get = self.client.get(url, {"quickPeriod": "todos"})
        response_post = self.client.post(
            url,
            data=json.dumps(self._fcf_payload()),
            content_type="application/json",
        )

        self.assertEqual(response_get.status_code, 200)
        self._assert_json_no_store(response_get)
        self.assertFalse(response_get.json()["permissions"]["canCreate"])
        self.assertFalse(response_get.json()["permissions"]["canCreateDebt"])
        self.assertFalse(
            response_get.json()["permissions"]["canCreateFinancingMovement"]
        )
        self.assertEqual(response_post.status_code, 403)
        self.assertEqual(response_post.json(), {"detail": "Permission denied."})
        self._assert_json_no_store(response_post)
        self.assertEqual(FinanciamentoMovimentacao.objects.count(), 0)

    def test_api_financiamentos_preserva_csrf_real_no_post(self):
        usuario = self._usuario_com_permissoes_caixa(
            "api-fcf-csrf",
            "view_parceladivida",
            "add_financiamentomovimentacao",
        )
        client = Client(enforce_csrf_checks=True)
        client.force_login(usuario)

        response = client.post(
            reverse("caixa:api_financiamentos"),
            data=json.dumps(self._fcf_payload()),
            content_type="application/json",
        )

        self.assertEqual(response.status_code, 403)
        self.assertIn("text/html", response["Content-Type"])
        self.assertEqual(FinanciamentoMovimentacao.objects.count(), 0)

