    def test_api_obrigacoes_financeiras_combina_periodo_personalizado_e_vencidas(self):
        permissao_ledger = Permission.objects.get(
            content_type__app_label="caixa",
            codename="view_lancamentofinanceiro",
        )
        self.user.user_permissions.add(permissao_ledger)
        CustoFixo.objects.create(
            descricao="Custo vencido dentro do periodo",
            categoria="sistema",
            valor_previsto=Decimal("100.00"),
            data_vencimento=date(2026, 1, 10),
        )
        CustoFixo.objects.create(
            descricao="Custo vencido fora do periodo",
            categoria="sistema",
            valor_previsto=Decimal("200.00"),
            data_vencimento=date(2026, 3, 10),
        )
        CustoFixo.objects.create(
            descricao="Custo liquidado dentro do periodo",
            categoria="sistema",
            valor_previsto=Decimal("80.00"),
            valor_pago=Decimal("80.00"),
            data_vencimento=date(2026, 1, 15),
        )

        response = self.client.get(
            reverse("caixa:api_obrigacoes_financeiras"),
            {
                "startDate": "2026-01-01",
                "endDate": "2026-02-28",
                "status": "vencido",
                "source": "custo_fixo",
                "dataSource": "legacy",
            },
        )
        payload = response.json()["data"]

        self.assertEqual(response.status_code, 200, response.json())
        self.assertEqual(payload["pagination"]["total"], 1)
        self.assertEqual(payload["summary"]["pendingAmount"], 100.0)
        self.assertEqual(payload["filters"]["startDate"], "2026-01-01")
        self.assertEqual(payload["filters"]["endDate"], "2026-02-28")
        self.assertEqual(payload["filters"]["settlementStatus"], "vencido")
        semantica_filtros = payload["meta"]["filterSemantics"]
        self.assertEqual(
            semantica_filtros["version"],
            "financial-obligations-filter-semantics-v1",
        )
        self.assertEqual(semantica_filtros["combinationRule"], "intersection")
        self.assertEqual(semantica_filtros["dateBasis"], "dueDate")
        self.assertTrue(
            semantica_filtros["rules"]["periodAndSettlementStatusAreCombined"]
        )
        self.assertTrue(
            semantica_filtros["rules"]["overdueWithPeriodMeansOverdueInsidePeriod"]
        )
        self.assertEqual(
            semantica_filtros["fields"]["settlementStatus"]["businessTerm"],
            "Status de liquidacao",
        )
        self.assertEqual(
            semantica_filtros["fields"]["realizedAbovePlanned"]["businessTerm"],
            "Realizado acima do previsto",
        )
        self.assertEqual(
            semantica_filtros["fields"]["contractCode"]["businessTerm"],
            "Contrato",
        )
        self.assertNotIn("contractId", semantica_filtros["fields"])
        self.assertEqual(
            semantica_filtros["aliases"]["overRealized"],
            "realizedAbovePlanned",
        )
        filtros_ativos = {
            filtro["field"]: filtro["value"]
            for filtro in semantica_filtros["activeFilters"]
        }
        self.assertEqual(filtros_ativos["startDate"], "2026-01-01")
        self.assertEqual(filtros_ativos["endDate"], "2026-02-28")
        self.assertEqual(filtros_ativos["settlementStatus"], "vencido")
        self.assertEqual(filtros_ativos["source"], "custo_fixo")
        self.assertEqual(
            payload["items"][0]["obligationDescription"],
            "Custo vencido dentro do periodo",
        )
        self.assertEqual(payload["items"][0]["settlementStatus"], "vencido")

