        self.assertEqual(response_receitas.status_code, 200, response_receitas.content)
        self.assertEqual(response_despesas.status_code, 200, response_despesas.content)
        self.assertEqual(len(rows_receitas) - 1, 305)
        self.assertEqual(len(rows_despesas) - 1, 305)
        self.assertTrue(
            any("Receita export volume 304" in cell for cell in rows_receitas[-1]),
            rows_receitas[-1],
        )
        self.assertTrue(
            any("Despesa export volume 304" in cell for cell in rows_despesas[-1]),
            rows_despesas[-1],
        )

