    def _criar_despesa_operacional_manual_liquidacao(self, sufixo, *, valor_pago=Decimal("20.00")):
        criar_entrada_caixa_teste(valor=Decimal("1000.00"), data=date(2026, 6, 1))
        cliente = Cliente.objects.create(
            nome_razao_social=f"Cliente Liquidacao {sufixo}",
            tipo_pessoa="PJ",
            cpf_cnpj=f"91.223.456/0001-{sufixo:02d}",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero=f"EVT-LIQ-{sufixo}",
            nome_evento=f"Evento Liquidacao {sufixo}",
            data_inicio=date(2026, 6, 20),
            data_fim=date(2026, 6, 20),
        )
        return DespesaOperacional.objects.create(
            evento=evento,
            descricao=f"Despesa liquidacao {sufixo}",
            categoria="material",
            valor_previsto=Decimal("100.00"),
            valor_pago=valor_pago,
            data_vencimento=date(2026, 6, 20),
            data_pagamento=date(2026, 6, 20) if valor_pago else None,
            forma_pagamento="pix" if valor_pago else "",
        )

    def _assert_liquidacao_json_no_store(self, response, status_code):
        self.assertEqual(response.status_code, status_code, response.content[:200])
        self.assertEqual(response["Content-Type"], "application/json")
        self.assertIn("no-store", response["Cache-Control"])

    def _assert_liquidacao_method_not_allowed(self, response):
        self.assertEqual(response.status_code, 405, response.content[:200])
        self.assertEqual(response["Allow"], "POST")
        self.assertEqual(response["Content-Type"], "text/html; charset=utf-8")
        self.assertEqual(response.content, b"")
        self.assertNotIn("Cache-Control", response)

    def _assert_liquidacao_invalid_body_response(self, response):
        self._assert_liquidacao_json_no_store(response, 400)
        self.assertEqual(
            response.json(),
            {"detail": "JSON inválido ou Content-Type incorreto."},
        )

