    def test_api_liquidar_obrigacao_preserva_405_django_nas_duas_rotas(self):
        urls = [
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            reverse("caixa:api_settle_payment_obligation"),
        ]

        for url in urls:
            with self.subTest(url=url):
                self._assert_liquidacao_method_not_allowed(self.client.get(url))
                self._assert_liquidacao_method_not_allowed(
                    self.client.put(url, data="{}", content_type="application/json")
                )
                self._assert_liquidacao_method_not_allowed(
                    self.client.patch(url, data="{}", content_type="application/json")
                )
                self._assert_liquidacao_method_not_allowed(self.client.delete(url))

    def test_api_liquidar_obrigacao_preserva_csrf_real(self):
        url = reverse("caixa:api_liquidar_obrigacao_financeira")
        csrf_client = Client(enforce_csrf_checks=True)
        csrf_client.force_login(self.user)

        sem_csrf = csrf_client.post(
            url,
            data={"source": "custo_extra", "sourceId": 1, "realizedAmount": "10.00"},
            content_type="application/json",
        )
        self.assertEqual(sem_csrf.status_code, 403)
        self.assertEqual(sem_csrf["Content-Type"], "text/html; charset=utf-8")

        csrf_response = csrf_client.get(reverse("caixa:api_auth_csrf"))
        csrf_token = csrf_response.json()["csrfToken"]
        com_csrf = csrf_client.post(
            url,
            data={"source": "custo_extra", "sourceId": 1, "realizedAmount": "10.00"},
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        self._assert_liquidacao_json_no_store(com_csrf, 403)
        self.assertEqual(com_csrf.json(), {"detail": "Permission denied."})

    def test_api_liquidar_obrigacao_preserva_autenticacao_e_borda_json_nas_duas_rotas(self):
        urls = [
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            reverse("caixa:api_settle_payment_obligation"),
        ]

        for url in urls:
            with self.subTest(url=url, scenario="anonymous"):
                anonymous_client = Client()
                resposta = anonymous_client.post(
                    url,
                    data={"source": "custo_extra", "sourceId": 1, "realizedAmount": "10.00"},
                    content_type="application/json",
                )
                self._assert_liquidacao_json_no_store(resposta, 401)
                self.assertEqual(
                    resposta.json(),
                    {"detail": "Authentication credentials were not provided."},
                )

            for data, content_type in (
                ("{}", "text/plain"),
                ("{", "application/json"),
                ("[]", "application/json"),
            ):
                with self.subTest(url=url, data=data, content_type=content_type):
                    resposta = self.client.post(
                        url,
                        data=data,
                        content_type=content_type,
                    )
                    self._assert_liquidacao_invalid_body_response(resposta)

