    def test_api_liquidar_obrigacao_preserva_sucesso_shape_alias_e_sem_view_lancamento(self):
        self.user.user_permissions.set(
            Permission.objects.filter(
                content_type__app_label="caixa",
                codename="change_despesaoperacional",
            )
        )
        despesa = self._criar_despesa_operacional_manual_liquidacao(31)
        payload = {
            "source": "despesa_operacional",
            "sourceId": despesa.id,
            "valor_pago": "70.00",
            "data_pagamento": "2026-06-21",
            "formaPagamento": "transferencia",
            "observacao": "Baixa via alias PT-BR",
        }
        urls = [
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            reverse("caixa:api_settle_payment_obligation"),
        ]

        responses = [
            self.client.post(url, data=payload, content_type="application/json")
            for url in urls
        ]

        for response in responses:
            self._assert_liquidacao_json_no_store(response, 200)
            self._assert_liquidacao_success_shape(response.json()["data"])
            self.assertEqual(
                response.json()["data"]["item"]["source"],
                "despesa_operacional",
            )
            self.assertEqual(response.json()["data"]["item"]["realizedAmount"], 70.0)
            self.assertEqual(response.json()["data"]["item"]["pendingAmount"], 30.0)

        despesa.refresh_from_db()
        self.assertEqual(despesa.valor_pago, Decimal("70.00"))
        self.assertEqual(despesa.data_pagamento, date(2026, 6, 21))
        self.assertEqual(despesa.forma_pagamento, "transferencia")
        self.assertEqual(despesa.observacao, "Baixa via alias PT-BR")
        self.assertEqual(
            LancamentoFinanceiro.objects.filter(despesa_operacional=despesa).count(),
            1,
        )
        self.assertEqual(
            BaixaFinanceira.objects.filter(despesa_operacional=despesa).count(),
            1,
        )
        self.assertEqual(
            BaixaFinanceiraAlocacao.objects.filter(
                obrigacao__chave_origem=f"despesa_operacional:{despesa.id}",
            ).count(),
            1,
        )

    def test_api_liquidar_obrigacao_preserva_aliases_baixa_saldo_e_idempotencia(self):
        self.user.user_permissions.add(
            Permission.objects.get(codename="change_despesaoperacional")
        )
        despesa = self._criar_despesa_operacional_manual_liquidacao(
            32,
            valor_pago=Decimal("0.00"),
        )
        payload = {
            "source": "despesa_operacional",
            "sourceId": despesa.id,
            "valorRealizado": "70.00",
            "dataPagamento": "2026-06-21",
            "baixarSaldo": True,
            "motivoBaixa": "Fornecedor aceitou desconto por alias.",
            "forma_pagamento": "pix",
        }

        primeira = self.client.post(
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            data=payload,
            content_type="application/json",
        )
        segunda = self.client.post(
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            data=payload,
            content_type="application/json",
        )

        self._assert_liquidacao_json_no_store(primeira, 200)
        self._assert_liquidacao_json_no_store(segunda, 200)
        despesa.refresh_from_db()
        item = segunda.json()["data"]["item"]

        self.assertEqual(despesa.valor_pago, Decimal("70.00"))
        self.assertEqual(despesa.status, "pago")
        self.assertTrue(despesa.baixado_manualmente)
        self.assertIn("Fornecedor aceitou desconto", despesa.motivo_baixa)
        self.assertEqual(item["pendingAmount"], 0.0)
        self.assertEqual(item["settlementStatus"], "liquidado")
        self.assertEqual(
            LancamentoFinanceiro.objects.filter(despesa_operacional=despesa).count(),
            1,
        )
        self.assertEqual(
            BaixaFinanceira.objects.filter(despesa_operacional=despesa).count(),
            1,
        )

