    def test_api_liquidar_obrigacao_manual_define_realizado_total_idempotente(self):
        permissoes = Permission.objects.filter(
            content_type__app_label="caixa",
            codename__in=["change_despesaoperacional", "view_lancamentofinanceiro"],
        )
        self.user.user_permissions.add(*permissoes)
        criar_entrada_caixa_teste(valor=Decimal("1000.00"), data=date(2026, 6, 1))
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Baixa API",
            tipo_pessoa="PJ",
            cpf_cnpj="91.123.456/0001-94",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero="EVT-BAIXA-API",
            nome_evento="Evento Baixa API",
            data_inicio=date(2026, 6, 20),
            data_fim=date(2026, 6, 20),
        )
        despesa = DespesaOperacional.objects.create(
            evento=evento,
            descricao="Despesa manual baixa API",
            categoria="material",
            valor_previsto=Decimal("100.00"),
            valor_pago=Decimal("20.00"),
            data_vencimento=date(2026, 6, 20),
            data_pagamento=date(2026, 6, 20),
            forma_pagamento="pix",
        )
        corpo = {
            "source": "despesa_operacional",
            "sourceId": despesa.id,
            "realizedAmount": "70.00",
            "paymentDate": "2026-06-21",
            "paymentMethod": "transferencia",
            "notes": "Baixa parcial via Next.js",
        }

        primeira_resposta = self.client.post(
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            data=corpo,
            content_type="application/json",
        )
        segunda_resposta = self.client.post(
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            data=corpo,
            content_type="application/json",
        )

        self.assertEqual(primeira_resposta.status_code, 200)
        self.assertEqual(segunda_resposta.status_code, 200)
        self.assertIn("no-store", primeira_resposta["Cache-Control"])
        self.assertIn("no-store", segunda_resposta["Cache-Control"])
        despesa.refresh_from_db()
        lancamento = LancamentoFinanceiro.objects.get(despesa_operacional=despesa)
        payload_resposta = segunda_resposta.json()["data"]
        item = payload_resposta["item"]
        baixa_canonica = payload_resposta["canonicalSettlement"]

        self.assertEqual(despesa.valor_pago, Decimal("70.00"))
        self.assertEqual(despesa.data_pagamento, date(2026, 6, 21))
        self.assertEqual(despesa.forma_pagamento, "transferencia")
        self.assertEqual(despesa.status, "parcial")
        self.assertEqual(despesa.atualizado_por, self.user)
        self.assertEqual(lancamento.valor, Decimal("70.00"))
        self.assertEqual(lancamento.data_lancamento, date(2026, 6, 21))
        self.assertEqual(LancamentoFinanceiro.objects.filter(despesa_operacional=despesa).count(), 1)
        self.assertEqual(item["source"], "despesa_operacional")
        self.assertEqual(item["sourceId"], despesa.id)
        self.assertEqual(item["realizedAmount"], 70.0)
        self.assertEqual(item["pendingAmount"], 30.0)
        self.assertEqual(item["ledgerRealizedAmount"], 70.0)
        self.assertTrue(item["isLedgerReconciled"])
        self.assertEqual(payload_resposta["settlement"], baixa_canonica)
        self.assertTrue(baixa_canonica["available"])
        self.assertTrue(baixa_canonica["synced"])
        self.assertEqual(baixa_canonica["writeModelSource"], "legacyAdapterSynced")
        self.assertEqual(
            baixa_canonica["latestSettlement"]["writeModelSource"],
            "legacyAdapterSynced",
        )
        self.assertEqual(
            baixa_canonica["obligationKey"],
            f"despesa_operacional:{despesa.id}",
        )
        self.assertEqual(baixa_canonica["settlementModel"], "BaixaFinanceira")
        self.assertEqual(baixa_canonica["allocationModel"], "BaixaFinanceiraAlocacao")
        self.assertEqual(baixa_canonica["settlementCount"], 1)
        self.assertEqual(baixa_canonica["allocatedAmount"], 70.0)
        self.assertEqual(baixa_canonica["latestSettlement"]["amount"], 70.0)
        self.assertEqual(baixa_canonica["latestSettlement"]["settlementAmount"], 70.0)
        self.assertEqual(
            baixa_canonica["latestSettlement"]["settlementDescription"],
            "Despesa manual baixa API",
        )
        self.assertEqual(baixa_canonica["latestSettlement"]["ledgerEntryId"], lancamento.id)

