    def test_comando_verificar_prontidao_escrita_canonica_reporta_adapters(self):
        saida = StringIO()

        call_command("verificar_prontidao_escrita_canonica", stdout=saida)

        texto = saida.getvalue()
        self.assertIn("Prontidao de escrita canonica consistente.", texto)
        self.assertIn("Modo atual: legacyAdapterSynced", texto)
        self.assertIn("Canonical-first pronto: nao", texto)
        self.assertIn("Feature flag canonical-first: desligada", texto)
        self.assertIn("Origens canonical-first habilitadas: -", texto)
        self.assertIn("Origens adapter-only PM-04", texto)

        saida_json = StringIO()
        call_command(
            "verificar_prontidao_escrita_canonica",
            "--json",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertTrue(payload["ready"])
        self.assertFalse(payload["canonicalFirstReady"])
        self.assertFalse(payload["featureFlagEnabled"])
        self.assertEqual(payload["featureFlagSources"], [])
        self.assertEqual(payload["enabledCanonicalFirstSources"], [])
        self.assertEqual(payload["invalidFeatureFlagSources"], [])
        self.assertEqual(payload["currentWriteMode"], "legacyAdapterSynced")
        self.assertIn("despesa_operacional", payload["directCanonicalFirstSources"])
        self.assertEqual(
            payload["adapterOnlySources"],
            ["custo_extra", "custo_servico", "parcela_divida"],
        )
        matriz_pm04 = {
            item["source"]: item
            for item in payload["pm04DecisionMatrix"]["items"]
        }
        self.assertEqual(
            payload["pm04DecisionMatrix"]["adapterOnlySources"],
            ["custo_extra", "custo_servico", "parcela_divida"],
        )
        self.assertTrue(matriz_pm04["custo_servico"]["decisionRequired"])
        self.assertTrue(matriz_pm04["custo_servico"]["requiresSourceDetail"])
        self.assertIn("sourceDetail", matriz_pm04["custo_servico"]["recommendation"])
        self.assertTrue(matriz_pm04["parcela_divida"]["supportsAdjustments"])
        self.assertEqual(matriz_pm04["parcela_divida"]["recommendedPhase"], "PM-04")
        self.assertFalse(matriz_pm04["custo_fixo"]["decisionRequired"])
        self.assertEqual(matriz_pm04["custo_fixo"]["recommendedPhase"], "PM-03")
        self.assertTrue(
            payload["adapters"]["despesa_operacional"][
                "supportsCanonicalFirstWrite"
            ]
        )
        self.assertEqual(
            payload["adapters"]["despesa_operacional"]["supportedObligationTypes"],
            ["pagar"],
        )
        self.assertFalse(
            payload["adapters"]["custo_servico"]["supportsCanonicalFirstWrite"]
        )
        self.assertEqual(
            payload["adapters"]["custo_servico"]["canonicalSettlementOriginField"],
            "pagamento_custo_servico",
        )
        self.assertTrue(payload["adapters"]["custo_servico"]["requiresSourceDetail"])
        self.assertEqual(payload["inconsistencies"], [])

        call_command(
            "verificar_prontidao_escrita_canonica",
            "--falhar-com-inconsistencia",
            stdout=StringIO(),
        )

