    def test_comando_simular_baixa_canonica_nao_grava_dados(self):
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Simulacao Canonical First",
            tipo_pessoa="PJ",
            cpf_cnpj="91.123.456/0001-71",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero="EVT-SIM-CANON",
            nome_evento="Evento Simulacao Canonical First",
            data_inicio=date(2026, 7, 10),
            data_fim=date(2026, 7, 10),
        )
        criar_entrada_caixa_teste(valor=Decimal("200.00"), data=date(2026, 7, 10))
        despesa = DespesaOperacional.objects.create(
            evento=evento,
            descricao="Despesa simulacao canonical-first",
            categoria="material",
            valor_previsto=Decimal("120.00"),
            valor_pago=Decimal("20.00"),
            data_vencimento=date(2026, 7, 10),
            data_pagamento=date(2026, 7, 10),
        )
        baixas_antes = BaixaFinanceira.objects.count()
        alocacoes_antes = BaixaFinanceiraAlocacao.objects.count()
        saida_json = StringIO()

        call_command(
            "simular_baixa_canonica",
            "--source=despesa_operacional",
            f"--source-id={despesa.id}",
            "--realized-amount=80.00",
            "--payment-date=2026-07-11",
            "--json",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        despesa.refresh_from_db()
        self.assertTrue(payload["ready"])
        self.assertTrue(payload["dryRun"])
        self.assertEqual(payload["writeMode"], "canonicalFirstDryRun")
        self.assertEqual(payload["currentWriteMode"], "legacyAdapterSynced")
        self.assertEqual(payload["obligationKey"], f"despesa_operacional:{despesa.id}")
        self.assertEqual(payload["current"]["realizedAmount"], 20.0)
        self.assertEqual(payload["requested"]["deltaAmount"], 60.0)
        self.assertEqual(payload["canonicalSettlementDraft"]["amount"], 60.0)
        self.assertEqual(payload["canonicalSettlementDraft"]["type"], "saida")
        self.assertEqual(
            payload["canonicalSettlementDraft"]["canonicalSettlementOriginField"],
            "despesa_operacional",
        )
        self.assertEqual(payload["legacyAdapter"]["name"], "liquidar_despesa_operacional_manual")
        self.assertFalse(payload["effects"]["writesDatabase"])
        self.assertEqual(despesa.valor_pago, Decimal("20.00"))
        self.assertEqual(BaixaFinanceira.objects.count(), baixas_antes)
        self.assertEqual(BaixaFinanceiraAlocacao.objects.count(), alocacoes_antes)

