    def test_comando_validar_ativacao_canonical_first_executa_canario(self):
        self.user.user_permissions.add(
            Permission.objects.get(codename="change_despesaoperacional"),
            Permission.objects.get(codename="view_lancamentofinanceiro"),
        )
        criar_entrada_caixa_teste(valor=Decimal("1000.00"), data=date(2026, 7, 1))
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Ativacao Canonical First",
            tipo_pessoa="PJ",
            cpf_cnpj="91.123.456/0001-75",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero="EVT-ATIVA-CF",
            nome_evento="Evento Ativacao Canonical First",
            data_inicio=date(2026, 7, 10),
            data_fim=date(2026, 7, 10),
        )
        despesa = DespesaOperacional.objects.create(
            evento=evento,
            descricao="Despesa ativacao canonical-first",
            categoria="material",
            valor_previsto=Decimal("120.00"),
            data_vencimento=date(2026, 7, 10),
        )
        saida_json = StringIO()

        call_command(
            "validar_ativacao_canonical_first",
            "--source=despesa_operacional",
            f"--source-id={despesa.id}",
            "--username=tester",
            "--payment-date=2026-07-11",
            "--executar-canario",
            "--exigir-canario",
            "--exigir-data-pagamento-canario",
            "--json",
            "--falhar",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        despesa.refresh_from_db()
        obrigacao = ObrigacaoFinanceira.objects.get(despesa_operacional=despesa)
        self.assertTrue(payload["ready"])
        self.assertEqual(payload["source"], "despesa_operacional")
        self.assertEqual(payload["pendingObligations"]["count"], 1)
        self.assertEqual(payload["pendingObligations"]["payableCount"], 1)
        self.assertEqual(payload["pendingObligations"]["receivableCount"], 0)
        self.assertEqual(payload["pendingObligations"]["canaryEligibleCount"], 1)
        candidatos = payload["pendingObligations"]["canaryCandidates"]
        self.assertEqual(len(candidatos), 1)
        self.assertEqual(candidatos[0]["source"], "despesa_operacional")
        self.assertEqual(candidatos[0]["sourceId"], despesa.id)
        self.assertEqual(candidatos[0]["pendingAmount"], "120.00")
        self.assertEqual(
            payload["recommendedEnvironment"][
                "CANONICAL_FIRST_SETTLEMENT_SOURCES"
            ],
            "despesa_operacional",
        )
        comando_canario = payload["recommendedCommands"]["canaryRollbackOnly"]
        self.assertIn("validar_ativacao_canonical_first", comando_canario)
        self.assertIn("--source=despesa_operacional", comando_canario)
        self.assertIn(f"--source-id={despesa.id}", comando_canario)
        self.assertIn("--exigir-source-id-canario", comando_canario)
        self.assertIn("--exigir-data-pagamento-canario", comando_canario)
        self.assertIn(
            "--diretorio-evidencias=<diretorio-evidencias-pm03-despesa-operacional>",
            comando_canario,
        )
        self.assertEqual(
            payload["nextAction"]["key"],
            "activateAllowlistWindow",
        )
        self.assertEqual(
            payload["activationDecision"]["status"],
            "readyForAllowlistWindow",
        )
        self.assertTrue(payload["activationDecision"]["mayActivateAllowlistWindow"])
        self.assertFalse(payload["activationDecision"]["mayRunCanaryRollbackOnly"])
        self.assertFalse(payload["activationDecision"]["requiresControlledCandidate"])
        self.assertEqual(
            payload["activationDecision"]["selectedSourceId"],
            str(despesa.id),
        )
        self.assertTrue(payload["canonicalParity"]["consistent"])
        self.assertTrue(payload["writeReadiness"]["ready"])
        self.assertTrue(payload["canary"]["required"])
        self.assertTrue(payload["canary"]["paymentDateRequired"])
        self.assertTrue(payload["canary"]["paymentDateProvided"])
        self.assertEqual(payload["canary"]["paymentDate"], "2026-07-11")
        self.assertTrue(payload["canary"]["sourceIdCheck"]["eligible"])
        self.assertEqual(
            payload["canary"]["sourceIdCheck"]["obligationId"],
            obrigacao.id,
        )
        self.assertTrue(payload["canary"]["executed"])
        self.assertTrue(payload["canary"]["synced"])
        self.assertFalse(payload["canary"]["result"]["writesPersisted"])
        self.assertEqual(payload["canary"]["result"]["paymentDate"], "2026-07-11")
        self.assertEqual(payload["canary"]["result"]["obligationId"], obrigacao.id)
        self.assertEqual(
            payload["canary"]["result"]["obligationKey"],
            payload["canary"]["sourceIdCheck"]["obligationKey"],
        )
        self.assertEqual(despesa.valor_pago, Decimal("0.00"))
        self.assertEqual(obrigacao.valor_realizado, Decimal("0.00"))
        self.assertFalse(BaixaFinanceira.objects.filter(despesa_operacional=despesa).exists())

        with TemporaryDirectory() as temp_dir:
            saida_evidencia = StringIO()
            call_command(
                "validar_ativacao_canonical_first",
                "--source=despesa_operacional",
                f"--source-id={despesa.id}",
                f"--diretorio-evidencias={temp_dir}",
                "--exigir-arquivos-evidencia",
                "--json",
                "--falhar",
                stdout=saida_evidencia,
            )
            payload_evidencia = json.loads(saida_evidencia.getvalue())
            json_path = Path(temp_dir) / "pm03-validacao-ativacao-canonical-first.json"
            record_path = Path(temp_dir) / "pm03-validacao-ativacao-canonical-first.md"

            self.assertTrue(payload_evidencia["ready"])
            self.assertEqual(payload_evidencia["evidenceFiles"]["json"], str(json_path))
            self.assertEqual(
                payload_evidencia["evidenceFiles"]["record"],
                str(record_path),
            )
            self.assertTrue(json_path.exists())
            self.assertTrue(record_path.exists())
            registro = record_path.read_text(encoding="utf-8")
            self.assertIn("Registro PM-03 - validacao de ativacao", registro)
            self.assertIn(f"Canario sourceId: sourceId={despesa.id}", registro)

        with self.assertRaisesMessage(CommandError, "evidencia PM-03 de ativacao"):
            call_command(
                "validar_ativacao_canonical_first",
                "--source=despesa_operacional",
                "--exigir-arquivos-evidencia",
                stdout=StringIO(),
            )

