    def test_comando_validar_ativacao_canonical_first_conta_entradas_pendentes(self):
        Investimento.objects.create(
            descricao="Entrada FCI pendente para ativacao",
            categoria="equipamento",
            tipo_fluxo="entrada",
            valor_previsto=Decimal("100.00"),
            data_prevista=date(2026, 7, 20),
        )
        saida_json = StringIO()

        call_command(
            "validar_ativacao_canonical_first",
            "--source=investimento",
            "--json",
            "--falhar",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertTrue(payload["ready"])
        self.assertEqual(payload["pendingObligations"]["count"], 1)
        self.assertEqual(payload["pendingObligations"]["payableCount"], 0)
        self.assertEqual(payload["pendingObligations"]["receivableCount"], 1)
        self.assertEqual(payload["pendingObligations"]["canaryEligibleCount"], 0)
        self.assertEqual(payload["pendingObligations"]["canaryCandidates"], [])
        self.assertEqual(payload["pendingObligations"]["nonCanaryPendingCount"], 1)
        pendencia_sem_canario = payload["pendingObligations"]["nonCanaryPendingItems"][0]
        self.assertEqual(pendencia_sem_canario["obligationType"], "receber")
        self.assertIn("entrada", pendencia_sem_canario["ineligibilityReason"])
        self.assertEqual(
            payload["candidateListHealth"]["status"],
            "onlyNonCanaryPending",
        )
        self.assertEqual(
            payload["candidateListHealth"]["recommendedAction"],
            "createControlledCandidate",
        )
        self.assertEqual(payload["nextAction"]["key"], "awaitCanaryCandidate")
        self.assertEqual(payload["activationDecision"]["status"], "awaitCanaryCandidate")
        self.assertFalse(payload["activationDecision"]["mayRunCanaryRollbackOnly"])
        self.assertFalse(payload["activationDecision"]["mayActivateAllowlistWindow"])
        self.assertTrue(payload["activationDecision"]["requiresControlledCandidate"])
        self.assertIn("ha pendencia(s)", payload["nextAction"]["detail"])
        self.assertIn("nenhuma e obrigacao a pagar", payload["nextAction"]["detail"])
        gate = payload["operationalGate"]
        self.assertEqual(gate["currentStep"], "PM-03.3")
        self.assertEqual(gate["status"], "blockedAwaitingCanaryCandidate")
        self.assertIn("investimento FCI", gate["entryGate"])
        self.assertIn("Investimento.tipo_fluxo=saida", gate["canaryCandidateCriteria"])
        self.assertIn("PM-03.4", " ".join(gate["blockedActions"]))

        saida_humana = StringIO()
        call_command(
            "validar_ativacao_canonical_first",
            "--source=investimento",
            stdout=saida_humana,
        )

        self.assertIn(
            "Obrigacoes pendentes: total=1; a pagar=0; a receber=1; canario=0",
            saida_humana.getvalue(),
        )
        self.assertIn("Pendencias sem canario:", saida_humana.getvalue())
        self.assertIn("Gate operacional: PM-03.3", saida_humana.getvalue())

