    def test_comando_listar_candidatos_canario_pm03_sinaliza_lista_limitada(self):
        primeiro = FinanciamentoMovimentacao.objects.create(
            descricao="Saida FCF candidata mais antiga",
            categoria="emprestimo",
            tipo_fluxo="saida",
            valor_previsto=Decimal("10.00"),
            data_prevista=date(2026, 7, 20),
        )
        FinanciamentoMovimentacao.objects.create(
            descricao="Saida FCF candidata posterior",
            categoria="emprestimo",
            tipo_fluxo="saida",
            valor_previsto=Decimal("20.00"),
            data_prevista=date(2026, 7, 21),
        )

        saida_json = StringIO()
        call_command(
            "listar_candidatos_canario_pm03",
            "--source=financiamento_movimentacao",
            "--limit=1",
            "--json",
            "--falhar",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertTrue(payload["ready"])
        self.assertEqual(payload["pendingObligations"]["canaryEligibleCount"], 2)
        self.assertEqual(
            payload["pendingObligations"]["canaryCandidatesReturnedCount"],
            1,
        )
        self.assertTrue(payload["pendingObligations"]["canaryCandidatesTruncated"])
        self.assertEqual(payload["candidateListHealth"]["status"], "readyTruncated")
        self.assertEqual(
            payload["candidateListHealth"]["recommendedAction"],
            "useReturnedCandidateOrIncreaseLimit",
        )
        self.assertEqual(
            payload["pendingObligations"]["canaryCandidates"][0]["sourceId"],
            primeiro.id,
        )
        self.assertEqual(
            payload["candidateDecision"]["selectedSourceId"],
            str(primeiro.id),
        )
        self.assertIn(
            "Listagem: candidatos=1/2; truncada=True",
            payload["executionRecord"]["markdown"],
        )

        saida_limite_zero = StringIO()
        call_command(
            "listar_candidatos_canario_pm03",
            "--source=financiamento_movimentacao",
            "--limit=0",
            "--json",
            stdout=saida_limite_zero,
        )
        payload_limite_zero = json.loads(saida_limite_zero.getvalue())

        self.assertFalse(payload_limite_zero["ready"])
        self.assertEqual(
            payload_limite_zero["pendingObligations"]["canaryEligibleCount"],
            2,
        )
        self.assertEqual(
            payload_limite_zero["pendingObligations"]["canaryCandidatesReturnedCount"],
            0,
        )
        self.assertTrue(
            payload_limite_zero["pendingObligations"]["canaryCandidatesTruncated"]
        )
        self.assertEqual(
            payload_limite_zero["candidateListHealth"]["status"],
            "blockedByLimit",
        )
        self.assertTrue(
            payload_limite_zero["candidateListHealth"]["requiresLimitIncrease"]
        )
        self.assertEqual(
            payload_limite_zero["candidateListHealth"]["recommendedAction"],
            "expandCandidateList",
        )
        self.assertIn(
            "limite de listagem nao retornou nenhum candidato",
            " ".join(payload_limite_zero["issues"]),
        )
        self.assertEqual(
            payload_limite_zero["nextAction"]["key"],
            "expandCanaryCandidateList",
        )
        self.assertIn(
            "limite de listagem nao retornou nenhum sourceId",
            payload_limite_zero["nextAction"]["detail"],
        )
        self.assertEqual(
            payload_limite_zero["operationalGate"]["status"],
            "blockedCandidateListLimit",
        )
        self.assertIn(
            "Reexecutar a descoberta de candidato com --limit maior que 0.",
            payload_limite_zero["operationalGate"]["allowedActions"],
        )
        self.assertEqual(
            payload_limite_zero["candidateDecision"]["status"],
            "blockedCandidateListLimit",
        )
        self.assertIn(
            "Reexecutar a descoberta com --limit maior que 0",
            payload_limite_zero["candidateDecision"]["detail"],
        )
        self.assertIn(
            "listar_candidatos_canario_pm03",
            payload_limite_zero["candidateDecision"]["suggestedCommand"],
        )
        self.assertFalse(
            payload_limite_zero["candidateDecision"]["mayRunCanaryRollbackOnly"]
        )
        orientacao_limite_zero = payload_limite_zero["candidateCreationGuidance"]
        self.assertFalse(orientacao_limite_zero["hasReadyCandidate"])
        self.assertTrue(orientacao_limite_zero["hasHiddenCandidate"])
        self.assertFalse(orientacao_limite_zero["requiredForNextCanary"])
        self.assertEqual(
            orientacao_limite_zero["recommendedAction"],
            "expandCandidateList",
        )
        self.assertIn(
            "reexecutar a descoberta com limite maior",
            orientacao_limite_zero["reason"],
        )
        with self.assertRaisesMessage(
            CommandError,
            "limite de listagem nao retornou nenhum candidato",
        ):
            call_command(
                "listar_candidatos_canario_pm03",
                "--source=financiamento_movimentacao",
                "--limit=0",
                "--falhar",
                stdout=StringIO(),
            )

