        saida_json = StringIO()

        self.assertEqual(resposta.status_code, 200)
        call_command(
            "validar_janela_canonical_first",
            "--source=despesa_operacional",
            "--data-ativacao=2026-07-01",
            "--data-final=2026-07-31",
            "--exigir-feature-flag-ativa",
            "--exigir-baixa-canonical-first",
            "--json",
            "--falhar",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertTrue(payload["ready"])
