    def test_comando_validar_janela_canonical_first_pode_validar_valores_editaveis(self):
        divida = DividaFinanceira.objects.create(
            descricao="Divida janela valores editaveis",
            credor="Banco Janela Valores",
            tipo="emprestimo",
            data_contratacao=date(2026, 7, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
            dia_vencimento=10,
        )
        divida.gerar_parcelas_iniciais()
        ParcelaDivida.objects.filter(divida=divida).update(
            valor_principal=Decimal("39.98")
        )
        saida_json = StringIO()

        call_command(
            "validar_janela_canonical_first",
            "--source=custo_fixo",
            "--validar-valores-editaveis",
            "--json",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertFalse(payload["ready"])
        self.assertTrue(payload["editableValuesIntegrity"]["checked"])
        self.assertFalse(payload["editableValuesIntegrity"]["consistent"])
        self.assertEqual(payload["editableValuesIntegrity"]["totalIssues"], 1)
        self.assertIn(
            "inconsistencia(s) de valores editaveis",
            payload["issues"][-1],
        )

        with self.assertRaisesMessage(CommandError, "valores editaveis"):
            call_command(
                "validar_janela_canonical_first",
                "--source=custo_fixo",
                "--falhar-com-valores-editaveis",
                stdout=StringIO(),
            )

    def test_comando_validar_preflight_deploy_financeiro_aprova_base_limpa(self):
        saida_json = StringIO()

        call_command(
            "validar_preflight_deploy_financeiro",
            "--json",
            "--falhar",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertTrue(payload["ready"])
        self.assertTrue(payload["readOnly"])
        self.assertTrue(payload["systemCheck"]["ok"])
        self.assertFalse(payload["deployCheck"]["checked"])
        self.assertEqual(payload["businessTotalsAudit"]["obligations"]["divergentCount"], 0)
        self.assertTrue(payload["financialLedgerIntegrity"]["consistent"])
        self.assertTrue(payload["manualExpenseOverlapIntegrity"]["consistent"])
        self.assertTrue(payload["debtCreditorIntegrity"]["consistent"])
        self.assertEqual(payload["debtCreditorIntegrity"]["pendingCount"], 0)
        self.assertTrue(payload["debtAutomaticFcfEntryIntegrity"]["consistent"])
        self.assertEqual(payload["debtAutomaticFcfEntryIntegrity"]["pendingCount"], 0)
        self.assertTrue(payload["operationalValidation"]["ready"])
        self.assertEqual(payload["issues"], [])
        self.assertEqual(
            payload["remediationPlan"]["version"],
            "financial-preflight-remediation-v1",
        )
        self.assertEqual(payload["remediationPlan"]["steps"], [])

        saida_humana = StringIO()
        call_command(
            "validar_preflight_deploy_financeiro",
            stdout=saida_humana,
        )
        self.assertIn(
            "Pre-flight de deploy financeiro aprovado.",
            saida_humana.getvalue(),
        )

