    def test_comando_gerar_snapshot_baseline_financeira_publica_ambiente_sem_senha(self):
        saida_json = StringIO()

        call_command("gerar_snapshot_baseline_financeira", "--json", stdout=saida_json)
        payload = json.loads(saida_json.getvalue())

        self.assertTrue(payload["readOnly"])
        self.assertTrue(payload["canonicalFirst"]["enabled"])
        self.assertEqual(payload["canonicalFirst"]["sources"], ["custo_fixo"])
        self.assertEqual(
            payload["cache"]["backend"],
            "django.core.cache.backends.redis.RedisCache",
        )
        self.assertEqual(
            payload["cache"]["location"],
            "redis://:***@127.0.0.1:6379/1",
        )
        self.assertIn(
            "rest_framework.throttling.AnonRateThrottle",
            payload["apiThrottling"]["classes"],
        )
        self.assertIn(
            "rest_framework.throttling.UserRateThrottle",
            payload["apiThrottling"]["classes"],
        )
        self.assertEqual(
            set(payload["apiThrottling"]["rates"]),
            {"anon", "user", "auth_login"},
        )
        self.assertNotIn("senha-cache", saida_json.getvalue())
        self.assertEqual(payload["cookies"]["sessionCookieDomain"], ".rhremoto.com")
        self.assertEqual(payload["cookies"]["csrfCookieDomain"], ".rhremoto.com")
