    def test_comando_sincronizar_credores_dividas_fcf_corrige_aliases(self):
        credor = Credor.objects.create(nome="Banco Credor Correto")
        divida_texto_divergente = DividaFinanceira.objects.create(
            descricao="Divida com texto divergente",
            credor="Banco Antigo",
            credor_cadastro=credor,
            tipo="fornecedor",
            data_contratacao=date(2026, 7, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        divida_sem_fk = DividaFinanceira.objects.create(
            descricao="Divida sem FK de credor",
            credor="Banco Sem FK",
            tipo="fornecedor",
            data_contratacao=date(2026, 7, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        DividaFinanceira.objects.filter(pk=divida_texto_divergente.pk).update(
            credor="Banco Divergente"
        )
        DividaFinanceira.objects.filter(pk=divida_sem_fk.pk).update(
            credor_cadastro=None
        )

        saida_dry_run = StringIO()
        call_command(
            "sincronizar_credores_dividas_fcf",
            "--json",
            stdout=saida_dry_run,
        )
        payload_dry_run = json.loads(saida_dry_run.getvalue())

        self.assertTrue(payload_dry_run["readOnly"])
        self.assertEqual(payload_dry_run["checked"], 2)
        self.assertEqual(payload_dry_run["pendingCount"], 2)
        self.assertEqual(payload_dry_run["wouldFix"], 2)
        self.assertEqual(payload_dry_run["fixed"], 0)

        saida_limit_zero = StringIO()
        call_command(
            "sincronizar_credores_dividas_fcf",
            "--json",
            "--limit=0",
            stdout=saida_limit_zero,
        )
        payload_limit_zero = json.loads(saida_limit_zero.getvalue())

        self.assertEqual(payload_limit_zero["pendingCount"], 2)
        self.assertEqual(payload_limit_zero["items"], [])
        self.assertEqual(payload_limit_zero["limit"], 0)

        divida_texto_divergente.refresh_from_db()
        divida_sem_fk.refresh_from_db()
        self.assertEqual(divida_texto_divergente.credor, "Banco Divergente")
        self.assertIsNone(divida_sem_fk.credor_cadastro_id)

        saida_apply = StringIO()
        call_command(
            "sincronizar_credores_dividas_fcf",
            "--aplicar",
            "--json",
            "--falhar-com-pendencia",
            stdout=saida_apply,
        )
        payload_apply = json.loads(saida_apply.getvalue())

        self.assertFalse(payload_apply["readOnly"])
        self.assertEqual(payload_apply["pendingCount"], 2)
        self.assertEqual(payload_apply["fixed"], 2)
        self.assertEqual(payload_apply["remainingIssues"], 0)
        self.assertTrue(payload_apply["consistentAfter"])

        divida_texto_divergente.refresh_from_db()
        divida_sem_fk.refresh_from_db()
        self.assertEqual(divida_texto_divergente.credor, "Banco Credor Correto")
        self.assertEqual(divida_texto_divergente.credor_cadastro_id, credor.id)
        self.assertIsNotNone(divida_sem_fk.credor_cadastro_id)
        self.assertEqual(divida_sem_fk.credor, "Banco Sem FK")

    def test_comando_sincronizar_credores_dividas_fcf_preserva_fluxo_fcf_automatico(self):
        credor_antigo = Credor.objects.create(nome="Banco Antigo FCF")
        credor_correto = Credor.objects.create(nome="Banco Correto FCF")
        divida = DividaFinanceira.objects.create(
            descricao="Emprestimo com credor divergente",
            credor="",
            credor_cadastro=credor_antigo,
            tipo="emprestimo",
            data_contratacao=date(2026, 7, 1),
            valor_contratado=Decimal("300.00"),
            quantidade_parcelas=1,
        )
        movimento = FinanciamentoMovimentacao.objects.get(divida_financeira=divida)
        movimento_id = movimento.id
        self.assertIn("Banco Antigo FCF", movimento.descricao)

        DividaFinanceira.objects.filter(pk=divida.pk).update(
            credor="Banco Antigo FCF",
            credor_cadastro=credor_correto,
        )

        call_command(
            "sincronizar_credores_dividas_fcf",
            "--aplicar",
            "--json",
            "--falhar-com-pendencia",
            stdout=StringIO(),
        )

        divida.refresh_from_db()
        movimento.refresh_from_db()
        self.assertEqual(divida.credor, "Banco Correto FCF")
        self.assertEqual(divida.credor_cadastro_id, credor_correto.id)
        self.assertEqual(movimento.id, movimento_id)
        self.assertIn("Banco Antigo FCF", movimento.descricao)

        saida_preflight = StringIO()
        call_command(
            "validar_preflight_deploy_financeiro",
            "--json",
            stdout=saida_preflight,
        )
        payload_preflight = json.loads(saida_preflight.getvalue())
        self.assertFalse(payload_preflight["ready"])
        self.assertEqual(
            payload_preflight["debtAutomaticFcfEntryIntegrity"]["updated"],
            1,
        )

        saida_entradas = StringIO()
        call_command(
            "sincronizar_entradas_fcf_dividas",
            "--aplicar",
            "--json",
            "--falhar-com-pendencia",
            stdout=saida_entradas,
        )
        payload_entradas = json.loads(saida_entradas.getvalue())

        self.assertEqual(payload_entradas["updated"], 1)
        self.assertEqual(payload_entradas["remainingIssues"], 0)
