    def test_comando_validar_preflight_deploy_financeiro_reprova_despesa_reservada_manual(self):
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Preflight Manual",
            tipo_pessoa="PJ",
            cpf_cnpj="77.777.777/0001-78",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero="EVT-PREF-MANUAL",
            nome_evento="Evento Preflight Manual",
            data_inicio=date(2026, 7, 1),
            data_fim=date(2026, 7, 1),
        )
        servico = Servico.objects.create(
            nome="Servico Preflight Manual",
            codigo="servico-preflight-manual",
            diaria_padrao=Decimal("100.00"),
        )
        EventoCustoServico.objects.create(
            evento=evento,
            servico=servico,
            valor_diarias=Decimal("120.00"),
        )
        despesa = DespesaOperacional.objects.get(
            evento=evento,
            categoria="mao_obra",
            origem=DespesaOperacional.ORIGEM_CUSTO_SERVICO,
            origem_custo_servico_tipo="diarias",
        )
        DespesaOperacional.objects.filter(pk=despesa.pk).update(
            origem=DespesaOperacional.ORIGEM_MANUAL,
            origem_custo_servico_tipo="",
        )

        saida_json = StringIO()
        call_command(
            "validar_preflight_deploy_financeiro",
            "--json",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertFalse(payload["ready"])
        self.assertFalse(payload["manualExpenseOverlapIntegrity"]["consistent"])
        self.assertEqual(
            payload["manualExpenseOverlapIntegrity"][
                "reservedWithFinancialEffectCount"
            ],
            1,
        )
        self.assertIn("custo estruturado registrado como manual", payload["issues"][0])
        comandos = [
            passo["command"]
            for passo in payload["remediationPlan"]["steps"]
        ]
        categorias = [
            passo["category"]
            for passo in payload["remediationPlan"]["steps"]
        ]
        self.assertIn("python manage.py sincronizar_despesas_eventos", comandos)
        self.assertIn(
            "python manage.py verificar_despesas_manuais_sobrepostas --falhar-com-reservada",
            comandos,
        )
        self.assertEqual(categorias[0], "structuredExpenses")
        self.assertEqual(
            comandos[-1],
            "python manage.py validar_preflight_deploy_financeiro --falhar",
        )
        self.assertEqual(
            payload["remediationPlan"]["steps"][-1]["category"],
            "preflight",
        )

        with self.assertRaisesMessage(CommandError, "custo estruturado registrado como manual"):
            call_command(
                "validar_preflight_deploy_financeiro",
                "--falhar",
                stdout=StringIO(),
            )

