    def test_fechamento_pm03_cruza_candidato_com_ativacao(self):
        def salvar_json(path, payload):
            Path(path).write_text(
                json.dumps(payload, ensure_ascii=False),
                encoding="utf-8",
            )

        with TemporaryDirectory() as temp_dir:
            base = Path(temp_dir)
            candidatos_path = base / "pm03-candidatos-canario.json"
            ativacao_path = base / "pm03-validacao-ativacao-canonical-first.json"
            salvar_json(
                candidatos_path,
                {
                    "pendingObligations": {
                        "canaryCandidates": [
                            {
                                "sourceId": 10,
                                "obligationId": 101,
                            }
                        ]
                    }
                },
            )
            salvar_json(
                ativacao_path,
                {
                    "canary": {
                        "sourceIdCheck": {
                            "sourceId": "11",
                            "obligationId": 101,
                        },
                        "result": {
                            "sourceId": 11,
                            "obligationId": 101,
                        },
                    }
                },
            )

            resumo = resumir_candidato_ativacao_fechamento(
                {
                    "candidateDiscovery": str(candidatos_path),
                    "activationValidation": str(ativacao_path),
                }
            )

            self.assertTrue(resumo["available"])
            self.assertFalse(resumo["consistent"])
            self.assertEqual(resumo["activationSourceId"], "11")
            self.assertEqual(resumo["candidateSourceIds"], ["10"])

            salvar_json(
                ativacao_path,
                {
                    "canary": {
                        "sourceIdCheck": {
                            "sourceId": "10",
                            "obligationId": 101,
                        },
                        "result": {
                            "sourceId": 10,
                            "obligationId": 101,
                        },
                    }
                },
            )
            resumo = resumir_candidato_ativacao_fechamento(
                {
                    "candidateDiscovery": str(candidatos_path),
                    "activationValidation": str(ativacao_path),
                }
            )

            self.assertTrue(resumo["consistent"])

