    def test_comando_monitorar_janela_canonical_first_aprova_custo_fixo_ativo(self):
        self.user.user_permissions.add(
            Permission.objects.get(codename="change_custofixo"),
            Permission.objects.get(codename="view_lancamentofinanceiro"),
        )
        criar_entrada_caixa_teste(valor=Decimal("1000.00"), data=date(2026, 6, 1))
        custo_fixo = CustoFixo.objects.create(
            descricao="Custo fixo monitor canonical-first",
            categoria="internet",
            valor_previsto=Decimal("100.00"),
            valor_pago=Decimal("20.00"),
            data_vencimento=date(2026, 6, 20),
            data_pagamento=date(2026, 6, 20),
        )
        resposta = self.client.post(
            reverse("caixa:api_liquidar_obrigacao_financeira"),
            data={
                "source": "custo_fixo",
                "sourceId": custo_fixo.id,
                "realizedAmount": "70.00",
                "paymentDate": "2026-06-21",
                "notes": "Baixa monitor canonical-first",
            },
            content_type="application/json",
        )
        saida_json = StringIO()

        self.assertEqual(resposta.status_code, 200)
        call_command(
            "monitorar_janela_canonical_first",
            "--source=custo_fixo",
            "--data-inicial=2026-06-01",
            "--data-final=2026-06-30",
            "--exigir-canonical-first",
            "--falhar-com-legado-na-janela",
            "--json",
            "--falhar",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertTrue(payload["ready"])
        self.assertTrue(payload["featureFlagValidation"]["activeForSource"])
        self.assertTrue(payload["operationalPreflight"]["ready"])
        self.assertEqual(payload["writeAudit"]["canonicalFirst"]["count"], 1)
        self.assertEqual(payload["writeAudit"]["legacyAdapterSynced"]["count"], 0)
        self.assertEqual(
            payload["pendingObligations"]["canaryCandidates"][0]["sourceId"],
            custo_fixo.id,
        )
        self.assertEqual(
            payload["pendingObligations"]["canaryCandidates"][0]["pendingAmount"],
            "30.00",
        )
        self.assertTrue(payload["windowGuidance"]["activationDateRecommended"])
        self.assertEqual(
            payload["windowOutcome"]["status"],
            "approvedCanonicalFirstOnly",
        )
        self.assertEqual(
            payload["windowOutcome"]["nextActionScope"],
            "activationGate",
        )
        self.assertEqual(payload["nextAction"]["key"], "runCanaryRollbackOnly")
        self.assertEqual(payload["operationalGate"]["currentStep"], "PM-03.1")
        self.assertEqual(
            payload["operationalGate"]["status"],
            "readyForCanaryRollbackOnly",
        )
        self.assertEqual(payload["sequencePosition"]["position"], 1)
        self.assertEqual(payload["sequencePosition"]["nextStep"], "PM-03.2")
        self.assertEqual(
            payload["operationalGate"]["sequencePosition"]["position"],
            1,
        )
        self.assertIn(
            "nao altera a forma de gravacao",
            payload["windowGuidance"]["message"],
        )
        self.assertEqual(payload["issues"], [])

        saida_humana = StringIO()
        call_command(
            "monitorar_janela_canonical_first",
            "--source=custo_fixo",
            "--data-inicial=2026-06-01",
            "--data-final=2026-06-30",
            "--exigir-canonical-first",
            stdout=saida_humana,
        )
        self.assertIn(
            "Monitoramento canonical-first aprovado.",
            saida_humana.getvalue(),
        )
        self.assertIn("Candidatos para canario rollback-only:", saida_humana.getvalue())
        self.assertIn(f"sourceId={custo_fixo.id}", saida_humana.getvalue())
        self.assertIn("Proxima acao:", saida_humana.getvalue())
        self.assertIn("Resultado da janela:", saida_humana.getvalue())
        self.assertIn("Gate operacional:", saida_humana.getvalue())
        self.assertIn("Sequencia PM-03: position=1/4", saida_humana.getvalue())

        saida_json_alias = StringIO()
        call_command(
            "monitorar_janela_canonical_first",
            "--source=custo_fixo",
            "--data-ativacao=2026-06-01",
            "--data-final=2026-06-30",
            "--exigir-canonical-first",
            "--json",
            "--falhar",
            stdout=saida_json_alias,
        )
        payload_alias = json.loads(saida_json_alias.getvalue())

        self.assertTrue(payload_alias["ready"])
        self.assertEqual(payload_alias["period"]["startDate"], "2026-06-01")

        with TemporaryDirectory() as temp_dir:
            evidence_dir = Path(temp_dir)
            saida_evidencias = StringIO()

            call_command(
                "monitorar_janela_canonical_first",
                "--source=custo_fixo",
                "--data-ativacao=2026-06-01",
                "--data-final=2026-06-30",
                "--exigir-canonical-first",
                f"--diretorio-evidencias={evidence_dir}",
                "--exigir-arquivos-evidencia",
                "--json",
                "--falhar",
                stdout=saida_evidencias,
            )
            payload_evidencias = json.loads(saida_evidencias.getvalue())
            json_path = evidence_dir / "pm03-monitor-canonical-first.json"
            record_path = evidence_dir / "pm03-monitor-canonical-first.md"

            self.assertTrue(payload_evidencias["ready"])
            self.assertEqual(
                payload_evidencias["evidenceFiles"]["directory"],
                str(evidence_dir),
            )
            self.assertEqual(
                payload_evidencias["evidenceFiles"]["json"],
                str(json_path),
            )
            self.assertEqual(
                payload_evidencias["evidenceFiles"]["record"],
                str(record_path),
            )
            self.assertTrue(json_path.exists())
            self.assertTrue(record_path.exists())
            registro = record_path.read_text(encoding="utf-8")
            self.assertIn("Registro PM-03 - monitoramento canonical-first", registro)
            self.assertIn("Origem: custo_fixo", registro)
            self.assertIn("ready/issues: ready=True; issues=nenhuma", registro)
            self.assertIn("Candidatos canario: sourceId=", registro)
            self.assertIn("Proxima acao: runCanaryRollbackOnly", registro)
            self.assertIn(
                "Resultado da janela: approvedCanonicalFirstOnly",
                registro,
            )
            self.assertIn("Gate operacional: step=PM-03.1", registro)
            self.assertIn("Sequencia PM-03: position=1/4", registro)
            self.assertIn(
                "Decisao: manter `custo_fixo` na allowlist",
                registro,
            )
            self.assertNotIn(
                "manter `despesa_operacional` na allowlist",
                registro,
            )

        with self.assertRaisesMessage(CommandError, "arquivos de evidencia PM-03"):
            call_command(
                "monitorar_janela_canonical_first",
                "--source=custo_fixo",
                "--exigir-arquivos-evidencia",
                stdout=StringIO(),
            )

