    def test_comando_validar_operacao_obrigacoes_valida_valores_editaveis(self):
        divida = DividaFinanceira.objects.create(
            descricao="Divida preflight valores editaveis",
            credor="Banco Preflight Valores",
            tipo="emprestimo",
            data_contratacao=date(2026, 6, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
            dia_vencimento=10,
        )
        divida.gerar_parcelas_iniciais()
        ParcelaDivida.objects.filter(divida=divida).update(
            valor_principal=Decimal("39.98")
        )

        saida = StringIO()
        call_command(
            "validar_operacao_obrigacoes",
            "--validar-valores-editaveis",
            stdout=saida,
        )

        texto = saida.getvalue()
        self.assertIn("pontos de atencao", texto)
        self.assertIn("Valores editaveis: 1 inconsistencia(s).", texto)
        self.assertIn("valor_parcela_desatualizado", texto)

        saida_json = StringIO()
        call_command(
            "validar_operacao_obrigacoes",
            "--validar-valores-editaveis",
            "--json",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertFalse(payload["ready"])
        self.assertTrue(payload["editableValuesIntegrity"]["checked"])
        self.assertFalse(payload["editableValuesIntegrity"]["consistent"])
        self.assertEqual(payload["editableValuesIntegrity"]["totalIssues"], 1)
        self.assertEqual(
            payload["editableValuesIntegrity"]["issues"][0]["code"],
            "valor_parcela_desatualizado",
        )

        with self.assertRaisesMessage(
            CommandError,
            "valor_parcela_desatualizado",
        ):
            call_command(
                "validar_operacao_obrigacoes",
                "--falhar-com-valores-editaveis",
                stdout=StringIO(),
            )

