    def test_comando_validar_rollback_conciliacao_pm06_bloqueia_sem_evidencias(self):
        saida = StringIO()
        call_command("validar_rollback_conciliacao_pm06", "--json", stdout=saida)
        payload = json.loads(saida.getvalue())

        self.assertFalse(payload["ready"])
        self.assertTrue(payload["readOnly"])
        self.assertEqual(payload["source"], "pm06_rollback_conciliation_window")
        self.assertEqual(payload["rollbackConciliationDecision"]["status"], "blocked")
        self.assertFalse(
            payload["rollbackConciliationDecision"][
                "mayUseForCleanupMigrationGate"
            ]
        )
        self.assertFalse(payload["rollbackConciliationDecision"]["mayExecuteRollback"])
        self.assertFalse(
            payload["rollbackConciliationDecision"]["mayExecuteConciliation"]
        )
