    def test_comando_verificar_integridade_valores_editaveis_filtra_escopo_e_objeto(self):
        divida_alvo = DividaFinanceira.objects.create(
            descricao="Divida filtrada comando integridade",
            credor="Banco Integridade Filtro",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        divida_alvo.gerar_parcelas_iniciais()
        divida_ignorada = DividaFinanceira.objects.create(
            descricao="Divida ignorada comando integridade",
            credor="Banco Integridade Ignorado",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("200.00"),
            quantidade_parcelas=1,
        )
        divida_ignorada.gerar_parcelas_iniciais()
        ParcelaDivida.objects.filter(divida=divida_alvo).update(
            valor_principal=Decimal("39.98")
        )
        ParcelaDivida.objects.filter(divida=divida_ignorada).update(
            valor_principal=Decimal("49.98")
        )
        saida_json = StringIO()

        call_command(
            "verificar_integridade_valores_editaveis",
            "--escopo=divida",
            f"--object-id={divida_alvo.id}",
            "--json",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertEqual(payload["filters"]["scopes"], ["divida"])
        self.assertEqual(payload["filters"]["objectIds"], [divida_alvo.id])
        self.assertEqual(payload["remaining"]["checked"]["debts"], 1)
        self.assertEqual(payload["remaining"]["checked"]["events"], 0)
        self.assertEqual(payload["remaining"]["checked"]["approvedBudgets"], 0)
        self.assertEqual(payload["remaining"]["totalIssues"], 1)
        self.assertEqual(payload["remaining"]["targets"]["divida"], [divida_alvo.id])
        self.assertEqual(payload["correctionPlan"]["totalTargets"], 1)
        self.assertEqual(
            payload["correctionPlan"]["items"][0]["applyCommand"],
            (
                "python manage.py verificar_integridade_valores_editaveis "
                f"--escopo=divida --object-id={divida_alvo.id} "
                "--corrigir --falhar-com-inconsistencia"
            ),
        )

        saida = StringIO()
        call_command(
            "verificar_integridade_valores_editaveis",
            "--escopo=divida",
            f"--object-id={divida_alvo.id}",
            stdout=saida,
        )
        self.assertIn(
            f"Filtros: escopos=divida; objectIds={divida_alvo.id}",
            saida.getvalue(),
        )
        self.assertIn("Plano de correcao sugerido:", saida.getvalue())
        self.assertIn(
            f"--escopo=divida --object-id={divida_alvo.id} --corrigir",
            saida.getvalue(),
        )

        saida_orcamento_json = StringIO()
        call_command(
            "verificar_integridade_valores_editaveis",
            "--escopo=orcamento",
            "--json",
            stdout=saida_orcamento_json,
        )
        payload_orcamento = json.loads(saida_orcamento_json.getvalue())

        self.assertEqual(payload_orcamento["remaining"]["checked"]["debts"], 0)
        self.assertEqual(payload_orcamento["remaining"]["checked"]["events"], 0)
        self.assertEqual(payload_orcamento["remaining"]["totalIssues"], 0)

