        self.assertEqual(evento.custo_total_previsto, Decimal("180.00"))
        self.assertEqual(evento.lucro_previsto, Decimal("320.00"))
        self.assertEqual(evento.valor_total_realizado, Decimal("120.00"))
        self.assertEqual(evento.custo_total_realizado, Decimal("0.00"))
        self.assertEqual(evento.lucro_realizado, Decimal("120.00"))

