    def test_comandos_operacionais_filtram_integridade_de_valores_editaveis(self):
        divida_alvo = DividaFinanceira.objects.create(
            descricao="Divida preflight filtro",
            credor="Banco Preflight Filtro",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        divida_alvo.gerar_parcelas_iniciais()
        divida_ignorada = DividaFinanceira.objects.create(
            descricao="Divida preflight ignorada",
            credor="Banco Preflight Ignorado",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("200.00"),
            quantidade_parcelas=1,
        )
        divida_ignorada.gerar_parcelas_iniciais()
        ParcelaDivida.objects.filter(divida=divida_alvo).update(
            valor_principal=Decimal("39.98")
        )
        ParcelaDivida.objects.filter(divida=divida_ignorada).update(
            valor_principal=Decimal("49.98")
        )

        comandos = [
            (
                "validar_operacao_obrigacoes",
                [
                    "--validar-valores-editaveis",
                    "--json",
                ],
            ),
            (
                "validar_janela_canonical_first",
                [
                    "--source=custo_fixo",
                    "--validar-valores-editaveis",
                    "--json",
                ],
            ),
            (
                "auditar_totais_negocio",
                [
                    "--validar-valores-editaveis",
                    "--json",
                ],
            ),
        ]

        for nome_comando, argumentos in comandos:
            with self.subTest(nome_comando=nome_comando):
                saida_json = StringIO()
                call_command(
                    nome_comando,
                    *argumentos,
                    "--valores-editaveis-escopo=divida",
                    f"--valores-editaveis-object-id={divida_alvo.id}",
                    stdout=saida_json,
                )
                payload = json.loads(saida_json.getvalue())
                integridade = payload["editableValuesIntegrity"]

                self.assertEqual(integridade["filters"]["scopes"], ["divida"])
                self.assertEqual(integridade["filters"]["objectIds"], [divida_alvo.id])
                self.assertEqual(integridade["totalIssues"], 1)
                self.assertEqual(integridade["targets"]["divida"], [divida_alvo.id])
                self.assertEqual(integridade["correctionPlan"]["totalTargets"], 1)
                self.assertEqual(
                    integridade["correctionPlan"]["items"][0]["objectId"],
                    divida_alvo.id,
                )
                self.assertNotIn(
                    divida_ignorada.id,
                    integridade["targets"]["divida"],
                )
                saida_humana = StringIO()
                argumentos_humanos = [
                    argumento for argumento in argumentos if argumento != "--json"
                ]
                call_command(
                    nome_comando,
                    *argumentos_humanos,
                    "--valores-editaveis-escopo=divida",
                    f"--valores-editaveis-object-id={divida_alvo.id}",
                    stdout=saida_humana,
                )
                self.assertIn(
                    f"Filtros valores editaveis: escopos=divida; objectIds={divida_alvo.id}",
                    saida_humana.getvalue(),
                )
                self.assertIn("Plano de correcao sugerido:", saida_humana.getvalue())
                self.assertIn(
                    f"--escopo=divida --object-id={divida_alvo.id} --corrigir",
                    saida_humana.getvalue(),
                )
                if nome_comando == "validar_janela_canonical_first":
                    checklist = payload["operationalChecklist"]["commands"]
                    self.assertIn(
                        f"--valores-editaveis-object-id={divida_alvo.id}",
                        checklist["preWindow"][3]["command"],
                    )
                    self.assertIn(
                        f"--valores-editaveis-object-id={divida_alvo.id}",
                        checklist["postWindow"][3]["command"],
                    )

    def test_comando_verificar_integridade_valores_editaveis_corrige_divida_e_orcamento(self):
        configuracao = ConfiguracaoFinanceira.objects.create(
            nome="Cfg Integridade Valores",
            valor_alimentacao=Decimal("20.00"),
            valor_transporte=Decimal("10.00"),
            margem_lucro=Decimal("0.30"),
            aliquota_imposto=Decimal("0.05"),
            data_inicio_vigencia=date(2026, 1, 1),
        )
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Integridade Valores",
            tipo_pessoa="PJ",
            cpf_cnpj="91.123.456/0001-93",
        )
        servico = Servico.objects.create(
            nome="Servico Integridade Valores",
            codigo="servico-integridade-valores",
            diaria_padrao=Decimal("100.00"),
        )
        orcamento = Orcamento.objects.create(
            cliente=cliente,
            configuracao_financeira=configuracao,
            numero="ORC-INT-VAL",
            nome_evento="Evento Integridade Valores",
            data_evento=date(2026, 5, 20),
        )
        item = OrcamentoItem.objects.create(
            orcamento=orcamento,
            servico=servico,
            horas_por_dia=8,
            quantidade_dias=1,
            quantidade_pessoas=1,
        )
        evento = orcamento.aprovar_e_gerar_evento()
        receita = ReceitaOperacional.objects.get(evento=evento)
        custo_evento = EventoCustoServico.objects.get(evento=evento, servico=servico)
        divida = DividaFinanceira.objects.create(
            descricao="Divida corrigida comando",
            credor="Banco Corrige Valores",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        divida.gerar_parcelas_iniciais()

        ParcelaDivida.objects.filter(divida=divida).update(
            valor_principal=Decimal("39.98")
        )
        Evento.objects.filter(pk=evento.pk).update(
            valor_total_previsto=Decimal("1.00")
        )
        EventoCustoServico.objects.filter(pk=custo_evento.pk).update(
            valor_diarias=Decimal("1.00")
        )

        saida = StringIO()
        call_command(
            "verificar_integridade_valores_editaveis",
            "--corrigir",
            "--falhar-com-inconsistencia",
            stdout=saida,
        )

        parcela = divida.parcelas.get()
        evento.refresh_from_db()
        receita.refresh_from_db()
        custo_evento.refresh_from_db()
        obrigacao_parcela = ObrigacaoFinanceira.objects.get(parcela_divida=parcela)
        obrigacao_receita = ObrigacaoFinanceira.objects.get(receita_operacional=receita)

        self.assertIn("Nenhuma inconsistencia de valores editaveis encontrada.", saida.getvalue())
        self.assertIn("correcoesAplicadas=3; correcoesBloqueadas=0", saida.getvalue())
        self.assertEqual(parcela.valor_total_devido, Decimal("100.00"))
        self.assertEqual(obrigacao_parcela.valor_previsto, Decimal("100.00"))
        self.assertEqual(evento.valor_total_previsto, orcamento.total_venda)
        self.assertEqual(receita.valor_previsto, orcamento.total_venda)
        self.assertEqual(obrigacao_receita.valor_previsto, orcamento.total_venda)
        self.assertEqual(custo_evento.valor_diarias, Decimal("1.00"))
        self.assertEqual(
            evento.custo_total_previsto,
            sum(
                (despesa.valor_previsto for despesa in evento.despesas.all()),
                Decimal("0.00"),
            ),
        )

