        evento_hoje = Evento.objects.create(
            cliente=cliente,
            numero="EVT-HOJE",
            nome_evento="Evento Hoje",
            data_inicio=hoje,
            data_fim=hoje,
            status="planejado",
            valor_total_previsto=Decimal("100.00"),
        )
        evento_vencido_aberto = Evento.objects.create(
            cliente=cliente,
            numero="EVT-VENC-ABERTO",
            nome_evento="Evento Vencido Aberto",
            data_inicio=passado,
            data_fim=passado,
            status="planejado",
            valor_total_previsto=Decimal("200.00"),
        )
        Evento.objects.create(
            cliente=cliente,
            numero="EVT-VENC-CONC",
            nome_evento="Evento Vencido Concluido",
            data_inicio=passado,
            data_fim=passado,
            status="concluido",
            valor_total_previsto=Decimal("300.00"),
        )
        Evento.objects.create(
            cliente=cliente,
            numero="EVT-FUTURO",
            nome_evento="Evento Futuro",
            data_inicio=futuro,
            data_fim=futuro,
            status="planejado",
            valor_total_previsto=Decimal("400.00"),
        )

        hoje_response = self.client.get(
            reverse("caixa:api_eventos"),
            {"periodo_rapido": "hoje"},
            secure=True,
        )
        hoje_payload = hoje_response.json()["data"]

        self.assertEqual(hoje_response.status_code, 200)
        self.assertEqual(hoje_payload["summary"]["total"], 1)
        self.assertEqual(hoje_payload["summary"]["plannedRevenueAmount"], "100.00")
        self.assertEqual(hoje_payload["filters"]["periodo_rapido"], "hoje")
        self.assertEqual(hoje_payload["filters"]["quickPeriod"], "hoje")
        self.assertEqual(
            [evento["id"] for evento in hoje_payload["events"]],
            [evento_hoje.id],
        )

        vencidos_response = self.client.get(
            reverse("caixa:api_eventos"),
            {"periodo_rapido": "vencidos"},
            secure=True,
        )
        vencidos_payload = vencidos_response.json()["data"]

        self.assertEqual(vencidos_response.status_code, 200)
        self.assertEqual(vencidos_payload["summary"]["total"], 1)
        self.assertEqual(vencidos_payload["summary"]["plannedRevenueAmount"], "200.00")
        self.assertEqual(vencidos_payload["filters"]["periodo_rapido"], "vencidos")
        self.assertEqual(vencidos_payload["filters"]["quickPeriod"], "vencidos")
        self.assertEqual(
            [evento["id"] for evento in vencidos_payload["events"]],
            [evento_vencido_aberto.id],
        )
        self.assertIn(
            {"value": "vencidos", "label": "Vencidos"},
            vencidos_payload["filterOptions"]["quickPeriods"],
        )

