    def test_alertas_dashboard_levam_periodo_para_paginas_de_destino(self):
        hoje = timezone.localdate()
        data_inicial = hoje - timedelta(days=7)
        data_vencida = hoje - timedelta(days=1)
        data_final = hoje
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Alertas",
            tipo_pessoa="PJ",
            cpf_cnpj="88.888.888/0001-88",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero="EVT-ALERTA-001",
            nome_evento="Evento Alertas",
            data_inicio=data_vencida,
            data_fim=data_vencida,
        )
        ReceitaOperacional.objects.create(
            evento=evento,
            cliente=cliente,
            descricao="Receita alerta",
            valor_previsto=Decimal("500.00"),
            data_vencimento=data_vencida,
        )
        DespesaOperacional.objects.create(
            evento=evento,
            descricao="Despesa alerta",
            categoria="material",
            valor_previsto=Decimal("200.00"),
            data_vencimento=data_vencida,
        )
        CustoFixo.objects.create(
            descricao="Custo alerta",
            categoria="internet",
            valor_previsto=Decimal("100.00"),
            data_vencimento=data_vencida,
        )
        divida = DividaFinanceira.objects.create(
            descricao="FCF alerta",
            credor="Banco Alertas",
            tipo="emprestimo",
            data_contratacao=data_inicial,
            valor_contratado=Decimal("300.00"),
            quantidade_parcelas=1,
        )
        ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=data_vencida,
            data_vencimento_atual=data_vencida,
            valor_principal=Decimal("300.00"),
        )

        contexto = montar_contexto_dashboard(
            {
                "data_inicial": data_inicial.isoformat(),
                "data_final": data_final.isoformat(),
            },
            self.client.session,
        )

        periodo_query = (
            f"data_inicial={data_inicial.isoformat()}&"
            f"data_final={data_final.isoformat()}"
        )
        vencidos_query = f"periodo_rapido=vencidos&{periodo_query}"
        urls_alertas = {alerta["url"] for alerta in contexto["alertas_dashboard"]}

        self.assertIn(reverse("caixa:receitas_lista") + f"?{periodo_query}", urls_alertas)
        self.assertIn(reverse("caixa:despesas_lista") + f"?{periodo_query}", urls_alertas)
        self.assertIn(reverse("caixa:custos_fixos_lista") + f"?{periodo_query}", urls_alertas)
        self.assertIn(reverse("caixa:lista_financiamentos") + f"?{vencidos_query}", urls_alertas)
        self.assertIn(reverse("caixa:custos_fixos_lista") + f"?{vencidos_query}", urls_alertas)

    @override_settings(
        NEXT_FRONTEND_URL="https://app.rhremoto.test",
        SECURE_SSL_REDIRECT=False,
    )
    def test_paginas_financeiras_html_removidas_redirecionam_para_next(self):
        rotas = [
            (reverse("caixa:receitas_lista"), "https://app.rhremoto.test/receitas"),
            (reverse("caixa:despesas_lista"), "https://app.rhremoto.test/despesas"),
            (reverse("caixa:lista_investimentos"), "https://app.rhremoto.test/fci"),
            (reverse("caixa:lista_financiamentos"), "https://app.rhremoto.test/fcf"),
        ]

        for url, next_url in rotas:
            with self.subTest(url=url):
                response = self.client.get(url)
                self.assertEqual(response.status_code, 302)
                self.assertEqual(response["Location"], next_url)

