    def test_mes_financeiro_exibe_receitas_e_dividas_do_mes_atual(self):
        hoje = timezone.localdate()
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Mes Financeiro",
            tipo_pessoa="PJ",
            cpf_cnpj="99.444.444/0001-99",
        )
        evento = Evento.objects.create(
            cliente=cliente,
            numero="EVT-MES-001",
            nome_evento="Evento Mes Financeiro",
            data_inicio=hoje,
            data_fim=hoje,
        )
        ReceitaOperacional.objects.create(
            evento=evento,
            cliente=cliente,
            descricao="Receita do mes",
            valor_previsto=Decimal("1000.00"),
            valor_recebido=Decimal("300.00"),
            data_vencimento=hoje,
        )
        divida = DividaFinanceira.objects.create(
            descricao="Divida do mes",
            credor="Credor Mes",
            tipo="fornecedor",
            data_contratacao=hoje,
            valor_contratado=Decimal("500.00"),
            quantidade_parcelas=12,
        )
        ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=2,
            data_vencimento_original=hoje,
            data_vencimento_atual=hoje,
            valor_principal=Decimal("500.00"),
            valor_pago=Decimal("125.00"),
        )
        usuario = User.objects.create_user(
            username="mes-financeiro",
            password="senha-segura",
        )
        permissoes = Permission.objects.filter(
            content_type__app_label="caixa",
            codename__in=["view_parceladivida", "view_receitaoperacional"],
        )
        usuario.user_permissions.set(permissoes)
        self.client.force_login(usuario)

        contexto = montar_contexto_mes_financeiro({})

        self.assertEqual(contexto["receita_prevista"], Decimal("1000.00"))
        self.assertEqual(contexto["divida_prevista"], Decimal("500.00"))
        self.assertEqual(contexto["divida_paga"], Decimal("125.00"))
        self.assertEqual(contexto["divida_pendente_pagamento"], Decimal("375.00"))
        self.assertEqual(contexto["divida_aberta"], Decimal("375.00"))
        self.assertEqual(contexto["saldo_realizado"], Decimal("175.00"))
        self.assertEqual(contexto["falta_cobrir"], Decimal("200.00"))
        movimento_divida = next(
            mov for mov in contexto["movimentacoes"]
            if mov["descricao"] == "Divida do mes"
        )
        movimento_receita = next(
            mov for mov in contexto["movimentacoes"]
            if mov["descricao"] == "Receita do mes"
        )
        self.assertEqual(movimento_divida["pago"], Decimal("125.00"))
        self.assertEqual(movimento_divida["aberto"], Decimal("375.00"))
        self.assertEqual(movimento_divida["saldo_previsto_acumulado"], Decimal("-500.00"))
        self.assertEqual(movimento_divida["saldo_realizado_acumulado"], Decimal("-125.00"))
        self.assertEqual(movimento_divida["falta_cobrir_acumulada"], Decimal("375.00"))
        self.assertEqual(movimento_receita["recebido"], Decimal("300.00"))
        self.assertEqual(movimento_receita["saldo_previsto_acumulado"], Decimal("500.00"))
        self.assertEqual(movimento_receita["saldo_realizado_acumulado"], Decimal("175.00"))
        self.assertEqual(movimento_receita["falta_cobrir_acumulada"], Decimal("200.00"))
        self.assertIn("Parcela 2/12", movimento_divida["referencia"])

    def test_api_mes_financeiro_exige_autenticacao_permissoes_compostas_e_headers(self):
        url = reverse("caixa:api_mes_financeiro")

        self.client.logout()
        resposta_nao_autenticada = self.client.get(url, secure=True)

        self.assertEqual(resposta_nao_autenticada.status_code, 401)
        self.assertEqual(
            resposta_nao_autenticada.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(resposta_nao_autenticada)

        for username, codenames in [
            ("mes-sem-permissoes", []),
            ("mes-so-parcela", ["view_parceladivida"]),
            ("mes-so-receita", ["view_receitaoperacional"]),
        ]:
            usuario = self._usuario_com_permissoes_caixa(username, *codenames)
            self.client.force_login(usuario)
            resposta_sem_permissao = self.client.get(url, secure=True)

            self.assertEqual(resposta_sem_permissao.status_code, 403)
            self.assertEqual(
                resposta_sem_permissao.json(),
                {"detail": "Permission denied."},
            )
            self._assert_json_no_store(resposta_sem_permissao)

        usuario_com_permissoes = self._usuario_com_permissoes_caixa(
            "mes-com-permissoes",
            "view_parceladivida",
            "view_receitaoperacional",
        )
        self.client.force_login(usuario_com_permissoes)
        resposta_sucesso = self.client.get(
            url,
            {"startDate": "2030-01-01", "endDate": "2030-01-31"},
            secure=True,
        )

        self.assertEqual(resposta_sucesso.status_code, 200)
        self._assert_json_no_store(resposta_sucesso)

    def test_api_mes_financeiro_metodos_nao_permitidos_preservam_allow(self):
        url = reverse("caixa:api_mes_financeiro")

        for method_name in ["post", "put", "patch", "delete"]:
            with self.subTest(method=method_name):
                response = getattr(self.client, method_name)(
                    url,
                    data={},
                    content_type="application/json",
                    secure=True,
                )

                self.assertEqual(response.status_code, 405)
                self.assertEqual(response["Allow"], "GET")
                self.assertTrue(response["Content-Type"].startswith("text/html"))

