    def test_api_lancamentos_financeiros_autenticacao_permissao_headers_e_shape_vazio(self):
        url = reverse("caixa:api_lancamentos_financeiros")
        anonimo = Client()

        resposta_anonima = anonimo.get(url)
        resposta_sem_permissao = self.client.get(url)

        self._adicionar_permissao_obrigacoes_financeiras()
        resposta_sucesso = self.client.get(url)
        payload = resposta_sucesso.json()["data"]

        self.assertEqual(resposta_anonima.status_code, 401)
        self.assertEqual(
            resposta_anonima.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(resposta_anonima)

        self.assertEqual(resposta_sem_permissao.status_code, 403)
        self.assertEqual(
            resposta_sem_permissao.json(),
            {"detail": "Permission denied."},
        )
        self._assert_json_no_store(resposta_sem_permissao)

        self.assertEqual(resposta_sucesso.status_code, 200)
        self._assert_json_no_store(resposta_sucesso)
        self.assertEqual(
            set(payload),
            {"items", "summary", "filters", "pagination", "meta"},
        )
        self.assertEqual(payload["items"], [])
        self.assertEqual(
            set(payload["summary"]),
            {
                "entradas",
                "inflowAmount",
                "saidas",
                "outflowAmount",
                "resultadoFinanceiro",
                "financialResultAmount",
                "resultado_financeiro",
                "cashFlows",
            },
        )
        self.assertEqual(
            set(payload["summary"]["cashFlows"]),
            {"fco", "fci", "fcf"},
        )
        for fluxo in ("fco", "fci", "fcf"):
            self.assertEqual(
                set(payload["summary"]["cashFlows"][fluxo]),
                {
                    "entradas",
                    "inflowAmount",
                    "saidas",
                    "outflowAmount",
                    "resultadoFinanceiro",
                    "financialResultAmount",
                    "resultado_financeiro",
                },
            )
        self.assertEqual(
            payload["filters"],
            {
                "period": "",
                "quickPeriod": "",
                "startDate": "",
                "endDate": "",
                "contractCode": "",
                "eventId": "",
                "clientId": "",
                "cashFlowGroup": "",
                "type": "",
                "nature": "",
                "origin": "",
                "originLabel": "",
                "source": "",
                "sourceLabel": "",
                "sourceId": "",
                "sourceDetail": "",
                "status": "",
                "search": "",
            },
        )
        self.assertEqual(
            payload["pagination"],
            {"limit": 100, "offset": 0, "total": 0, "hasMore": False},
        )
        self.assertEqual(payload["meta"]["source"], "backend")
        self.assertEqual(payload["meta"]["currency"], "BRL")
        self.assertIsInstance(payload["meta"]["generatedAt"], str)
        self.assertTrue(payload["meta"]["generatedAt"])

    def test_api_lancamentos_financeiros_metodos_nao_permitidos_preservam_405(self):
        url = reverse("caixa:api_lancamentos_financeiros")

        for metodo in ("post", "put", "patch", "delete"):
            with self.subTest(metodo=metodo):
                resposta = getattr(self.client, metodo)(
                    url,
                    data={},
                    content_type="application/json",
                )

                self.assertEqual(resposta.status_code, 405)
                self.assertEqual(resposta["Allow"], "GET")
                self.assertEqual(resposta.content, b"")
                self.assertEqual(
                    resposta["Content-Type"],
                    "text/html; charset=utf-8",
                )
                self.assertNotIn("Cache-Control", resposta)

