    def test_api_lancamentos_financeiros_mantem_query_count_constante_com_mais_registros(self):
        self._adicionar_permissao_obrigacoes_financeiras()
        self._criar_cenario_lancamentos_financeiros_api("PM26Q0")
        url = reverse("caixa:api_lancamentos_financeiros")
        parametros = {"period": "all", "limit": "10", "offset": "0"}

        self.client.get(url, parametros)
        with CaptureQueriesContext(connection) as queries_base:
            resposta_base = self.client.get(url, parametros)

        for indice in range(1, 4):
            self._criar_cenario_lancamentos_financeiros_api(f"PM26Q{indice}")

        with CaptureQueriesContext(connection) as queries_com_mais_registros:
            resposta_com_mais_registros = self.client.get(url, parametros)

        self.assertEqual(resposta_base.status_code, 200)
        self.assertEqual(resposta_com_mais_registros.status_code, 200)
        self.assertEqual(
            len(queries_com_mais_registros),
            len(queries_base),
        )

