    def test_api_dashboard_financial_overview_preserva_auth_permissao_e_headers(self):
        url = reverse("caixa:api_dashboard_financial_overview")

        self.client.logout()
        resposta_anonima = self.client.get(url, secure=True)

        self.assertEqual(resposta_anonima.status_code, 401)
        self.assertEqual(
            resposta_anonima.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(resposta_anonima)

        usuario_sem_permissao = self._usuario_com_permissoes_caixa(
            "dashboard-financial-overview-sem-view"
        )
        self.client.force_login(usuario_sem_permissao)
        resposta_sem_permissao = self.client.get(url, secure=True)

        self.assertEqual(resposta_sem_permissao.status_code, 403)
        self.assertEqual(
            resposta_sem_permissao.json(),
            {"detail": "Permission denied."},
        )
        self._assert_json_no_store(resposta_sem_permissao)

        usuario_com_permissao = self._usuario_com_permissoes_caixa(
            "dashboard-financial-overview-com-view",
            "view_evento",
        )
        self.client.force_login(usuario_com_permissao)
        resposta_sucesso = self.client.get(
            url,
            {"startDate": "2030-01-01", "endDate": "2030-01-31"},
            secure=True,
        )

        self.assertEqual(resposta_sucesso.status_code, 200)
        self._assert_json_no_store(resposta_sucesso)

