    def test_mes_financeiro_filtra_parcelas_por_status_da_divida(self):
        data_vencimento = date(2026, 5, 20)
        divida_ativa = DividaFinanceira.objects.create(
            descricao="Divida ativa mes financeiro",
            credor="Banco Ativo Mes",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        parcela_ativa = ParcelaDivida.objects.create(
            divida=divida_ativa,
            numero_parcela=1,
            data_vencimento_original=data_vencimento,
            data_vencimento_atual=data_vencimento,
            valor_principal=Decimal("100.00"),
        )
        divida_quitada = DividaFinanceira.objects.create(
            descricao="Divida quitada mes financeiro",
            credor="Banco Quitado Mes",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("200.00"),
            quantidade_parcelas=1,
        )
        parcela_quitada = ParcelaDivida.objects.create(
            divida=divida_quitada,
            numero_parcela=1,
            data_vencimento_original=data_vencimento,
            data_vencimento_atual=data_vencimento,
            valor_principal=Decimal("200.00"),
            valor_pago=Decimal("200.00"),
        )
        divida_ativa.refresh_from_db()
        divida_quitada.refresh_from_db()

        self.assertEqual(divida_ativa.status, "ativa")
        self.assertEqual(divida_quitada.status, "quitada")

        contexto_ativa = montar_contexto_mes_financeiro(
            {"periodo_rapido": "todos", "status": "ativa"}
        )
        contexto_quitada = montar_contexto_mes_financeiro(
            {"periodo_rapido": "todos", "status": "quitada"}
        )

        self.assertEqual(
            contexto_ativa["origens_mes_financeiro"],
            ORIGENS_MES_FINANCEIRO_FILTRO,
        )
        self.assertEqual(
            contexto_ativa["status_mes_financeiro"],
            STATUS_MES_FINANCEIRO_FILTRO,
        )
        self.assertEqual(contexto_ativa["filtros"]["status"], "ativa")
        self.assertEqual(contexto_quitada["filtros"]["status"], "quitada")
        self.assertEqual(list(contexto_ativa["parcelas"]), [parcela_ativa])
        self.assertEqual(list(contexto_quitada["parcelas"]), [parcela_quitada])

