    def test_form_admin_pagamento_parcela_lista_apenas_parcelas_com_saldo_pendente(self):
        divida = DividaFinanceira.objects.create(
            descricao="Divida com saldos mistos",
            credor="Fornecedor FCF",
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("500.00"),
            quantidade_parcelas=4,
        )
        parcela_pendente = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
        )
        parcela_parcial = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=2,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
            valor_pago=Decimal("40.00"),
        )
        parcela_sem_saldo = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=3,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
        )
        ParcelaDivida.objects.filter(pk=parcela_sem_saldo.pk).update(
            status="aberta",
            valor_pago=Decimal("100.00"),
        )
        parcela_baixada = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=4,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
            baixado_manualmente=True,
            motivo_baixa="Baixa administrativa",
        )
        divida_sem_saldo = DividaFinanceira.objects.create(
            descricao="Divida totalmente liquidada",
            credor="Fornecedor sem saldo",
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        parcela_divida_sem_saldo = ParcelaDivida.objects.create(
            divida=divida_sem_saldo,
            numero_parcela=1,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
        )
        ParcelaDivida.objects.filter(pk=parcela_divida_sem_saldo.pk).update(
            status="aberta",
            valor_pago=Decimal("100.00"),
        )

        form = PagamentoParcelaDividaAdminForm(data={"divida": str(divida.id)})
        dividas = set(form.fields["divida"].queryset.values_list("id", flat=True))
        parcelas = set(form.fields["parcela"].queryset.values_list("id", flat=True))

        self.assertIn(divida.id, dividas)
        self.assertNotIn(divida_sem_saldo.id, dividas)
        self.assertIn(parcela_pendente.id, parcelas)
        self.assertIn(parcela_parcial.id, parcelas)
        self.assertNotIn(parcela_sem_saldo.id, parcelas)
        self.assertNotIn(parcela_baixada.id, parcelas)

