    def test_prorrogacao_de_parcelas_ignora_parcela_sem_saldo_real(self):
        usuario = User.objects.create_user("usuario-prorrogacao", password="senha")
        divida = DividaFinanceira.objects.create(
            descricao="Divida para prorrogacao",
            credor="Fornecedor Prorrogacao",
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("200.00"),
            quantidade_parcelas=2,
        )
        parcela_pendente = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
        )
        parcela_sem_saldo = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=2,
            data_vencimento_original=date(2026, 6, 10),
            data_vencimento_atual=date(2026, 6, 10),
            valor_principal=Decimal("100.00"),
        )
        ParcelaDivida.objects.filter(pk=parcela_sem_saldo.pk).update(
            status="aberta",
            valor_pago=Decimal("100.00"),
        )

        quantidade = prorrogar_parcelas_pendentes(
            ParcelaDivida.objects.filter(divida=divida).order_by("numero_parcela"),
            usuario,
        )

        parcela_pendente.refresh_from_db()
        parcela_sem_saldo.refresh_from_db()
        self.assertEqual(quantidade, 1)
        self.assertEqual(parcela_pendente.data_vencimento_atual, date(2026, 7, 10))
        self.assertEqual(parcela_pendente.status, "prorrogada")
        self.assertEqual(parcela_sem_saldo.data_vencimento_atual, date(2026, 6, 10))
        self.assertEqual(parcela_sem_saldo.status, "aberta")

