        PagamentoEventoCustoExtra.objects.create(
            custo_extra=custo_extra_pago,
            valor_pagamento=Decimal("100.00"),
            data_pagamento=date(2026, 5, 1),
        )
        custo_extra_parcial = EventoCustoExtra.objects.create(
            evento=self.evento,
            categoria="material",
            descricao="Material parcial inline",
            valor_previsto=Decimal("100.00"),
            data_vencimento=date(2026, 5, 1),
        )
        PagamentoEventoCustoExtra.objects.create(
            custo_extra=custo_extra_parcial,
            valor_pagamento=Decimal("40.00"),
            data_pagamento=date(2026, 5, 1),
        )

        self.assertFalse(
            inline_servico.has_add_permission(request, obj=custo_servico_pago)
        )
        self.assertTrue(
            inline_servico.has_add_permission(request, obj=custo_servico_parcial)
        )
        self.assertFalse(inline_extra.has_add_permission(request, obj=custo_extra_pago))
        self.assertTrue(inline_extra.has_add_permission(request, obj=custo_extra_parcial))

