    def test_pagamento_zero_orienta_remover_lancamento(self):
        custo_servico = EventoCustoServico.objects.create(
            evento=self.evento,
            servico=self.servico,
            valor_diarias=Decimal("120.00"),
        )

        with self.assertRaises(ValidationError) as contexto:
            PagamentoEventoCustoServico.objects.create(
                custo_servico=custo_servico,
                tipo="diarias",
                valor_pagamento=Decimal("0.00"),
                data_pagamento=date(2026, 5, 1),
            )

        mensagem = contexto.exception.message_dict["valor_pagamento"][0]
