    def test_admin_divida_cria_parcelas_iniciais_em_save_related(self):
        admin_user = User.objects.create_superuser(
            "admin-divida-add",
            "admin-divida-add@example.com",
            "senha",
        )
        request = RequestFactory().post("/admin/caixa/dividafinanceira/add/")
        request.user = admin_user
        admin_divida = DividaFinanceiraAdmin(DividaFinanceira, AdminSite())
        divida = DividaFinanceira(
            descricao="Divida adicionada no admin",
            credor="Banco Admin Add",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("120.00"),
            quantidade_parcelas=2,
            dia_vencimento=10,
        )

        admin_divida.save_model(
            request,
            divida,
            SimpleNamespace(changed_data=[]),
            change=False,
        )
        self.assertEqual(divida.parcelas.count(), 0)

        form = SimpleNamespace(instance=divida, save_m2m=lambda: None)
        admin_divida.save_related(request, form, [], change=False)
        admin_divida.save_related(request, form, [], change=False)

        parcelas = list(divida.parcelas.order_by("numero_parcela"))
        self.assertEqual(len(parcelas), 2)
        self.assertEqual([parcela.valor_principal for parcela in parcelas], [
            Decimal("60.00"),
            Decimal("60.00"),
        ])

