    @override_settings(SECURE_SSL_REDIRECT=False)
    def test_admin_blinda_entrada_fcf_automatica_da_divida(self):
        divida = DividaFinanceira.objects.create(
            descricao="Emprestimo protegido no FCF",
            credor="Banco Protegido",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("400.00"),
            quantidade_parcelas=1,
        )
        automatica = FinanciamentoMovimentacao.objects.get(divida_financeira=divida)
        manual = FinanciamentoMovimentacao.objects.create(
            descricao="Entrada FCF manual",
            categoria="aporte_socio",
            tipo_fluxo="entrada",
            valor_previsto=Decimal("100.00"),
            valor_realizado=Decimal("100.00"),
            data_prevista=date(2026, 5, 1),
            data_realizacao=date(2026, 5, 1),
        )
        request = RequestFactory().get("/admin/caixa/financiamentomovimentacao/")
        request.user = User.objects.create_superuser(
            "admin-fcf-automatico",
            "admin-fcf-automatico@example.com",
            "senha",
        )
        admin_fcf = FinanciamentoMovimentacaoAdmin(
            FinanciamentoMovimentacao,
            AdminSite(),
        )

        readonly = admin_fcf.get_readonly_fields(request, automatica)

        self.assertIn("divida_financeira", readonly)
        self.assertIn("valor_previsto", readonly)
        self.assertIn("valor_realizado", readonly)
        self.assertIn("data_prevista", readonly)
        self.assertIn("data_realizacao", readonly)
        self.assertFalse(admin_fcf.has_delete_permission(request, automatica))
        self.assertTrue(admin_fcf.has_delete_permission(request, manual))

        contexto_fcf = montar_contexto_financiamentos(
            {"periodo_rapido": "todos"},
            {},
        )
        descricoes_fcf = {
            movimento.descricao
            for movimento in contexto_fcf["movimentacoes_financiamento"]
        }
        self.assertIn("Empréstimo - Banco Protegido", descricoes_fcf)
        self.assertIn("Entrada FCF manual", descricoes_fcf)

        self.client.force_login(request.user)
        resposta_api = self.client.get(
            reverse("caixa:api_financiamentos"),
            {"quickPeriod": "todos"},
        )
        payload = resposta_api.json()
        movimentos_por_id = {
            movimento["id"]: movimento
            for movimento in payload["financingMovements"]
        }

        self.assertEqual(
            payload["statistics"]["automaticFinancingMovementsCount"],
            1,
        )
        self.assertEqual(payload["statistics"]["manualFinancingMovementsCount"], 1)
        self.assertEqual(
            movimentos_por_id[automatica.id]["sourceType"],
            "divida_automatica",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["movementSourceType"],
            "divida_automatica",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["origem_movimentacao"],
            "divida_automatica",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["sourceTypeLabel"],
            "Entrada automatica da divida",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["movementSourceTypeLabel"],
            "Entrada automatica da divida",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["origem_movimentacao_display"],
            "Entrada automatica da divida",
        )
        self.assertTrue(movimentos_por_id[automatica.id]["automaticFromDebt"])
        self.assertTrue(movimentos_por_id[automatica.id]["isAutomaticFromDebt"])
        self.assertTrue(movimentos_por_id[automatica.id]["entrada_automatica_divida"])
        self.assertEqual(movimentos_por_id[automatica.id]["debtId"], divida.id)
        self.assertEqual(movimentos_por_id[automatica.id]["divida_id"], divida.id)
        self.assertEqual(
            movimentos_por_id[automatica.id]["debtCreditor"],
            "Banco Protegido",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["credor_divida"],
            "Banco Protegido",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["debtCreditorId"],
            divida.credor_cadastro_id,
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["credor_divida_id"],
            divida.credor_cadastro_id,
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["debtCreditorName"],
            "Banco Protegido",
        )
        self.assertEqual(
            movimentos_por_id[automatica.id]["nome_credor_divida"],
            "Banco Protegido",
        )
        self.assertEqual(movimentos_por_id[manual.id]["sourceType"], "manual")
        self.assertFalse(movimentos_por_id[manual.id]["automaticFromDebt"])
        self.assertIsNone(movimentos_por_id[manual.id]["debtId"])

        resposta_filtrada = self.client.get(
            reverse("caixa:api_financiamentos"),
            {
                "quickPeriod": "todos",
                "type": "emprestimo",
                "creditor": "Protegido",
                "sourceType": "divida_automatica",
            },
        )
        payload_filtrado = resposta_filtrada.json()

        self.assertEqual(
            [movimento["id"] for movimento in payload_filtrado["financingMovements"]],
            [automatica.id],
        )
        self.assertEqual(
            payload_filtrado["statistics"]["automaticFinancingMovementsCount"],
            1,
        )
        self.assertEqual(
            payload_filtrado["statistics"]["manualFinancingMovementsCount"],
            0,
        )

        resposta_filtrada_por_id = self.client.get(
            reverse("caixa:api_financiamentos"),
            {
                "quickPeriod": "todos",
                "type": "emprestimo",
                "creditorId": str(divida.credor_cadastro_id),
                "sourceType": "divida_automatica",
            },
        )
        payload_filtrado_por_id = resposta_filtrada_por_id.json()

        self.assertEqual(
            [
                movimento["id"]
                for movimento in payload_filtrado_por_id["financingMovements"]
            ],
            [automatica.id],
        )

        admin_fcf.delete_queryset(
            request,
            FinanciamentoMovimentacao.objects.filter(id__in=[automatica.id, manual.id]),
        )

        self.assertTrue(
            FinanciamentoMovimentacao.objects.filter(pk=automatica.pk).exists()
        )
        self.assertFalse(FinanciamentoMovimentacao.objects.filter(pk=manual.pk).exists())

