    def test_edicao_custo_servico_atualiza_despesa_obrigacao_e_saldos(self):
        custo_servico = EventoCustoServico.objects.create(
            evento=self.evento,
            servico=self.servico,
            valor_diarias=Decimal("120.00"),
        )
        PagamentoEventoCustoServico.objects.create(
            custo_servico=custo_servico,
            tipo="diarias",
            valor_pagamento=Decimal("50.00"),
            data_pagamento=date(2026, 5, 1),
        )

        custo_servico.valor_diarias = Decimal("200.00")
        custo_servico.save()

        custo_servico.refresh_from_db()
        despesa = DespesaOperacional.objects.get(
            evento=self.evento,
            origem=DespesaOperacional.ORIGEM_CUSTO_SERVICO,
            origem_custo_servico_tipo="diarias",
        )
        obrigacao = ObrigacaoFinanceira.objects.get(
            evento_custo_servico=custo_servico,
            detalhe_origem="diarias",
        )
        self.evento.refresh_from_db()

        self.assertEqual(custo_servico.valor_diarias, Decimal("200.00"))
        self.assertEqual(custo_servico.total_pago_diarias, Decimal("50.00"))
        self.assertEqual(custo_servico.valor_pendente_diarias, Decimal("150.00"))
        self.assertEqual(despesa.valor_previsto, Decimal("200.00"))
        self.assertEqual(despesa.valor_pago, Decimal("50.00"))
        self.assertEqual(despesa.valor_pendente_pagamento, Decimal("150.00"))
        self.assertEqual(obrigacao.valor_previsto, Decimal("200.00"))
        self.assertEqual(obrigacao.valor_realizado, Decimal("50.00"))
        self.assertEqual(obrigacao.valor_pendente, Decimal("150.00"))
        self.assertEqual(self.evento.custo_total_realizado, Decimal("50.00"))
        self.assertNotEqual(despesa.valor_previsto, Decimal("120.00"))

