    def test_editar_custo_extra_adota_despesa_reservada_herdada_como_manual(self):
        custo_extra = EventoCustoExtra.objects.create(
            evento=self.evento,
            categoria="material",
            descricao="Cabo HDMI",
            valor_previsto=Decimal("75.00"),
            data_vencimento=date(2026, 5, 1),
        )
        descricao = "Custo extra: Cabo HDMI"
        despesa = DespesaOperacional.objects.get(origem_custo_extra=custo_extra)
        DespesaOperacional.objects.filter(pk=despesa.pk).update(
            origem=DespesaOperacional.ORIGEM_MANUAL,
            origem_custo_extra=None,
            valor_previsto=Decimal("10.00"),
            status="pendente",
        )

        custo_extra.valor_previsto = Decimal("100.00")
        custo_extra.save()

        despesa.refresh_from_db()
        self.assertEqual(despesa.origem, DespesaOperacional.ORIGEM_CUSTO_EXTRA)
        self.assertEqual(despesa.origem_custo_extra_id, custo_extra.id)
        self.assertEqual(despesa.valor_previsto, Decimal("100.00"))
        self.assertFalse(
            DespesaOperacional.objects.filter(
                evento=self.evento,
                origem=DespesaOperacional.ORIGEM_MANUAL,
                descricao=descricao,
            ).exists()
        )
        self.assertEqual(
            DespesaOperacional.objects.filter(
                evento=self.evento,
                descricao=descricao,
            ).count(),
            1,
        )

