    def _criar_lote_pagamentos_performance(self, quantidade, deslocamento=0):
        servico = Servico.objects.create(
            nome=f"Servico Pagamento Performance {deslocamento}",
            codigo=f"servico-pagamento-performance-{deslocamento}",
            diaria_padrao=Decimal("100.00"),
        )

        for indice in range(deslocamento, deslocamento + quantidade):
            data_movimento = date(2026, 5, (indice % 20) + 1)
            cliente = Cliente.objects.create(
                nome_razao_social=f"Cliente Pagamento Performance {indice}",
                tipo_pessoa="PJ",
                cpf_cnpj=f"91.000.000/{indice:04d}-00",
            )
            evento = Evento.objects.create(
                cliente=cliente,
                numero=f"EVT-PAG-PERF-{indice:04d}",
                nome_evento=f"Evento Pagamento Performance {indice}",
                data_inicio=data_movimento,
                data_fim=data_movimento,
            )
            custo_servico = EventoCustoServico.objects.create(
                evento=evento,
                servico=servico,
                valor_diarias=Decimal("100.00"),
                valor_alimentacao=Decimal("50.00"),
                valor_transporte=Decimal("20.00"),
            )
            PagamentoEventoCustoServico.objects.create(
                custo_servico=custo_servico,
                tipo="diarias",
                valor_pagamento=Decimal("40.00"),
                data_pagamento=data_movimento,
            )
            custo_extra = EventoCustoExtra.objects.create(
                evento=evento,
                categoria="material",
                descricao=f"Custo Extra Pagamento Performance {indice}",
                valor_previsto=Decimal("100.00"),
                data_vencimento=data_movimento,
            )
            PagamentoEventoCustoExtra.objects.create(
                custo_extra=custo_extra,
                valor_pagamento=Decimal("40.00"),
                data_pagamento=data_movimento,
            )
            divida = DividaFinanceira.objects.create(
                descricao=f"Divida Pagamento Performance {indice}",
                credor=f"Banco Pagamento Performance {indice}",
                tipo="emprestimo",
                data_contratacao=data_movimento,
                valor_contratado=Decimal("100.00"),
                quantidade_parcelas=1,
            )
            parcela = ParcelaDivida.objects.create(
                divida=divida,
                numero_parcela=1,
                data_vencimento_original=data_movimento,
                data_vencimento_atual=data_movimento,
                valor_principal=Decimal("100.00"),
            )
            PagamentoParcelaDivida.objects.create(
                parcela=parcela,
                data_pagamento=data_movimento,
                valor_pagamento=Decimal("40.00"),
                forma_pagamento="pix",
            )

    def _contar_queries_pagina(self, url):
        with CaptureQueriesContext(connection) as queries:
            resposta = self.client.get(url)

        return len(queries), resposta

