    def test_parcela_disponivel_para_pagamento_centraliza_regra_de_saldo(self):
        divida = DividaFinanceira.objects.create(
            descricao="Regra parcela pagavel",
            credor="Credor regra parcela",
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        parcela = ParcelaDivida.objects.create(
            divida=divida,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 10),
            data_vencimento_atual=date(2026, 5, 10),
            valor_principal=Decimal("100.00"),
        )

        self.assertTrue(parcela_disponivel_para_pagamento(parcela))
        self.assertTrue(parcela.disponivel_para_pagamento)

        parcela.status = "paga"
        self.assertFalse(parcela_disponivel_para_pagamento(parcela))
        self.assertFalse(parcela.disponivel_para_pagamento)

        parcela.status = "aberta"
        parcela.valor_pago = Decimal("100.00")
        self.assertFalse(parcela_disponivel_para_pagamento(parcela))
        self.assertFalse(parcela.disponivel_para_pagamento)

