    def test_selector_custos_servico_filtra_no_banco_e_mantem_prefetch(self):
        outro_evento = Evento.objects.create(
            cliente=self.cliente,
            numero="EVT-PAG-002",
            nome_evento="Evento Pagamentos Outro",
            data_inicio=date(2026, 5, 2),
            data_fim=date(2026, 5, 2),
        )
        custo_visivel = EventoCustoServico.objects.create(
            evento=self.evento,
            servico=self.servico,
            valor_diarias=Decimal("100.00"),
        )
        servico_quitado = Servico.objects.create(
            nome="Recepcao quitada",
            codigo="recepcao-quitada",
            diaria_padrao=Decimal("100.00"),
        )
        custo_quitado = EventoCustoServico.objects.create(
            evento=self.evento,
            servico=servico_quitado,
            valor_diarias=Decimal("100.00"),
        )
        EventoCustoServico.objects.create(
            evento=outro_evento,
            servico=self.servico,
            valor_diarias=Decimal("200.00"),
        )
        PagamentoEventoCustoServico.objects.create(
            custo_servico=custo_visivel,
            tipo="diarias",
            valor_pagamento=Decimal("40.00"),
            data_pagamento=date(2026, 5, 1),
        )
        PagamentoEventoCustoServico.objects.create(
            custo_servico=custo_quitado,
            tipo="diarias",
            valor_pagamento=Decimal("100.00"),
            data_pagamento=date(2026, 5, 1),
        )

        filtros = {
            "busca": "Recep",
            "evento": str(self.evento.id),
            "tipo": "diarias",
            "situacao": "em_aberto",
        }

        with self.assertNumQueries(2):
            custos = listar_custos_servico(filtros)
            saldos = [custo.saldo_diarias for custo in custos]

        self.assertEqual([custo.id for custo in custos], [custo_visivel.id])
        self.assertEqual(saldos, [Decimal("60.00")])

        filtros["situacao"] = "quitado"
        with self.assertNumQueries(2):
            custos_quitados = listar_custos_servico(filtros)
            saldos_quitados = [custo.saldo_geral for custo in custos_quitados]

        self.assertEqual([custo.id for custo in custos_quitados], [custo_quitado.id])
        self.assertEqual(saldos_quitados, [Decimal("0.00")])

