    def test_selector_parcelas_fcf_filtra_no_banco_e_mantem_prefetch(self):
        divida_visivel = DividaFinanceira.objects.create(
            descricao="Financiamento equipamento",
            credor="Banco Alpha",
            tipo="financiamento",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        parcela_visivel = ParcelaDivida.objects.create(
            divida=divida_visivel,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 10),
            data_vencimento_atual=date(2026, 5, 10),
            valor_principal=Decimal("100.00"),
        )
        divida_quitada = DividaFinanceira.objects.create(
            descricao="Financiamento equipamento quitado",
            credor="Banco Alpha",
            tipo="financiamento",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("100.00"),
            quantidade_parcelas=1,
        )
        ParcelaDivida.objects.create(
            divida=divida_quitada,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 10),
            data_vencimento_atual=date(2026, 5, 10),
            valor_principal=Decimal("100.00"),
            valor_pago=Decimal("100.00"),
        )
        divida_oculta = DividaFinanceira.objects.create(
            descricao="Capital de giro",
            credor=f"Banco Beta {divida_visivel.credor_cadastro_id}",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 1),
            valor_contratado=Decimal("200.00"),
            quantidade_parcelas=1,
        )
        ParcelaDivida.objects.create(
            divida=divida_oculta,
            numero_parcela=1,
            data_vencimento_original=date(2026, 5, 10),
            data_vencimento_atual=date(2026, 5, 10),
            valor_principal=Decimal("200.00"),
        )

        filtros = {
            "busca": "equipamento",
            "credor": "Banco Alpha",
            "tipo": "financiamento",
            "situacao": "em_aberto",
        }

        with self.assertNumQueries(2):
            parcelas = listar_parcelas_fcf(filtros)
            saldos = [parcela.saldo_em_aberto for parcela in parcelas]

        self.assertEqual([parcela.id for parcela in parcelas], [parcela_visivel.id])
        self.assertEqual(saldos, [Decimal("100.00")])

        filtros["situacao"] = "quitado"
        with self.assertNumQueries(2):
            parcelas_quitadas = listar_parcelas_fcf(filtros)
            saldos_quitados = [parcela.saldo_em_aberto for parcela in parcelas_quitadas]

        self.assertEqual([parcela.divida_id for parcela in parcelas_quitadas], [divida_quitada.id])
        self.assertEqual(saldos_quitados, [Decimal("0.00")])

        filtros_creditor_id = {
            "busca": "",
            "credor": "",
            "creditorId": str(divida_visivel.credor_cadastro_id),
            "tipo": "",
            "situacao": "contas_pendentes",
        }
        parcelas_por_credor_id = listar_parcelas_fcf(filtros_creditor_id)
        self.assertEqual(
            [parcela.id for parcela in parcelas_por_credor_id],
            [parcela_visivel.id],
        )

        filtros_creditor_id_invalido = {
            "busca": "",
            "credor": "",
            "creditorId": "Banco Alpha",
            "tipo": "",
            "situacao": "contas_pendentes",
        }
        parcelas_creditor_id_invalido = listar_parcelas_fcf(
            filtros_creditor_id_invalido
        )
        self.assertEqual(list(parcelas_creditor_id_invalido), [])

        filtros_credor_id_invalido = {
            "busca": "",
            "credor": "",
            "credor_id": "Banco Alpha",
            "tipo": "",
            "situacao": "contas_pendentes",
        }
        parcelas_credor_id_invalido = listar_parcelas_fcf(
            filtros_credor_id_invalido
        )
        self.assertEqual(list(parcelas_credor_id_invalido), [])

    def test_selectors_de_pagamento_mantem_queries_constantes_com_mais_registros(self):
        self._criar_lote_pagamentos_performance(1, deslocamento=100)
        selectors = {
            "custos_servico": (
                lambda: listar_custos_servico({"situacao": "contas_pendentes"}),
                lambda item: item.saldo_geral,
            ),
            "custos_extras": (
                lambda: listar_custos_extras({"situacao": "contas_pendentes"}),
                lambda item: item.saldo_a_pagar,
            ),
            "parcelas_fcf": (
                lambda: listar_parcelas_fcf({"situacao": "contas_pendentes"}),
                lambda item: item.valor_pendente_pagamento,
            ),
        }
        consultas_base = {}
        registros_base = {}

        for nome, (selector, saldo) in selectors.items():
            with CaptureQueriesContext(connection) as queries:
                registros = selector()
                saldos = [saldo(item) for item in registros]

            self.assertTrue(saldos)
            consultas_base[nome] = len(queries)
            registros_base[nome] = len(registros)

        self._criar_lote_pagamentos_performance(6, deslocamento=200)

        for nome, (selector, saldo) in selectors.items():
            with self.subTest(selector=nome):
                with CaptureQueriesContext(connection) as queries:
                    registros = selector()
                    saldos = [saldo(item) for item in registros]

                self.assertEqual(len(queries), consultas_base[nome])
                self.assertLessEqual(len(queries), 3)
                self.assertGreater(
                    len(registros),
                    registros_base[nome],
                )
                self.assertTrue(saldos)

