class ModelagemIntegridadeBancoTests(TestCase):
    def test_configuracao_financeira_permite_apenas_uma_ativa_no_banco(self):
        ConfiguracaoFinanceira.objects.create(
            nome="Padrao",
            ativa=True,
            data_inicio_vigencia=date(2026, 1, 1),
        )

        with self.assertRaises(IntegrityError):
            with transaction.atomic():
                ConfiguracaoFinanceira.objects.bulk_create([
                    ConfiguracaoFinanceira(
                        nome="Outra ativa",
                        ativa=True,
                        data_inicio_vigencia=date(2026, 2, 1),
                    )
                ])

    def test_evento_nao_permite_periodo_invertido_no_banco(self):
        cliente = Cliente.objects.create(
            nome_razao_social="Cliente Integridade",
            tipo_pessoa="PJ",
            cpf_cnpj="11.111.111/0001-11",
        )

        with self.assertRaises(IntegrityError):
            with transaction.atomic():
                Evento.objects.create(
                    cliente=cliente,
                    numero="EVT-INTEGRIDADE-001",
                    nome_evento="Evento invalido",
                    data_inicio=date(2026, 5, 20),
                    data_fim=date(2026, 5, 19),
                )

    def test_divida_valida_parametros_operacionais_antes_do_banco(self):
        divida = DividaFinanceira(
            descricao="Divida invalida",
            credor="Banco Integridade",
            tipo="financiamento",
            data_contratacao=date(2026, 5, 20),
            valor_contratado=Decimal("-1.00"),
            taxa_juros_mensal=Decimal("-0.0100"),
            quantidade_parcelas=0,
            dia_vencimento=40,
        )

        with self.assertRaises(ValidationError) as contexto:
            divida.full_clean()

        erros = contexto.exception.message_dict
        self.assertIn("valor_contratado", erros)
        self.assertIn("taxa_juros_mensal", erros)
        self.assertIn("quantidade_parcelas", erros)
        self.assertIn("dia_vencimento", erros)


