    def test_divida_emprestimo_gera_entrada_fcf_no_caixa_e_mes_financeiro(self):
        divida = DividaFinanceira.objects.create(
            evento=self.evento,
            descricao="Capital de giro",
            credor="Banco Entrada",
            tipo="emprestimo",
            data_contratacao=date(2026, 5, 10),
            valor_contratado=Decimal("400.00"),
            quantidade_parcelas=2,
        )

        movimento = FinanciamentoMovimentacao.objects.get(divida_financeira=divida)

        self.assertEqual(movimento.categoria, "emprestimo")
        self.assertEqual(movimento.tipo_fluxo, "entrada")
        self.assertEqual(movimento.valor_previsto, Decimal("400.00"))
        self.assertEqual(movimento.valor_realizado, Decimal("400.00"))
        self.assertEqual(movimento.data_prevista, date(2026, 5, 10))
        self.assertEqual(movimento.data_realizacao, date(2026, 5, 10))
        self.assertEqual(movimento.status, "realizado")
        self.assertFalse(hasattr(movimento, "contrato_operacional_id"))
        self.assertEqual(movimento.evento_id, self.evento.id)
        self.assertIn("Banco Entrada", movimento.descricao)

        lancamento = LancamentoFinanceiro.objects.get(
            financiamento_movimentacao=movimento
        )
        self.assertEqual(lancamento.tipo, "entrada")
        self.assertEqual(lancamento.fluxo, LancamentoFinanceiro.FLUXO_FCF)
        self.assertEqual(lancamento.natureza, LancamentoFinanceiro.NATUREZA_FINANCIAMENTO)
        self.assertEqual(lancamento.valor, Decimal("400.00"))
        self.assertEqual(lancamento.data_lancamento, date(2026, 5, 10))

        self.assertEqual(saldo_caixa_disponivel(date(2026, 5, 31)), Decimal("400.00"))

        contexto = montar_contexto_mes_financeiro(
            {
                "data_inicial": "2026-05-01",
                "data_final": "2026-05-31",
            }
        )
        movimento_mes = next(
            item
            for item in contexto["movimentacoes"]
            if item["descricao"] == movimento.descricao
        )

        self.assertIn("Empr", movimento_mes["tipo"])
        self.assertEqual(movimento_mes["fluxo_caixa"], "FCF")
        self.assertEqual(movimento_mes["entrada"], Decimal("400.00"))
        self.assertEqual(movimento_mes["recebido"], Decimal("400.00"))
        self.assertEqual(contexto["entrada_prevista_fcf"], Decimal("400.00"))
        self.assertEqual(contexto["entrada_realizada_fcf"], Decimal("400.00"))
        self.assertEqual(contexto["caixa_final_mes"], Decimal("400.00"))

