    def test_divida_entrada_fcf_atualiza_valor_data_e_remove_ao_mudar_tipo(self):
        divida = DividaFinanceira.objects.create(
            descricao="Financiamento editavel",
            credor="Banco Original",
            tipo="financiamento",
            data_contratacao=date(2026, 5, 10),
            valor_contratado=Decimal("400.00"),
            quantidade_parcelas=2,
        )
        movimento = FinanciamentoMovimentacao.objects.get(divida_financeira=divida)
        movimento_id = movimento.id
        lancamento_id = LancamentoFinanceiro.objects.get(
            financiamento_movimentacao=movimento
        ).id

        credor_atualizado = Credor.objects.create(nome="Banco Atualizado")

        divida.credor_cadastro = credor_atualizado
        divida.valor_contratado = Decimal("650.00")
        divida.data_contratacao = date(2026, 6, 3)
        divida.save()

        movimento.refresh_from_db()
        lancamento = LancamentoFinanceiro.objects.get(pk=lancamento_id)

        self.assertEqual(movimento.id, movimento_id)
        self.assertEqual(movimento.valor_previsto, Decimal("650.00"))
        self.assertEqual(movimento.valor_realizado, Decimal("650.00"))
        self.assertEqual(movimento.data_prevista, date(2026, 6, 3))
        self.assertEqual(movimento.data_realizacao, date(2026, 6, 3))
        self.assertIn("Banco Atualizado", movimento.descricao)
        self.assertEqual(lancamento.valor, Decimal("650.00"))
        self.assertEqual(lancamento.data_lancamento, date(2026, 6, 3))
        self.assertEqual(saldo_caixa_disponivel(date(2026, 5, 31)), Decimal("0.00"))
        self.assertEqual(saldo_caixa_disponivel(date(2026, 6, 30)), Decimal("650.00"))

        divida.tipo = "fornecedor"
        divida.save()

        self.assertFalse(
            FinanciamentoMovimentacao.objects.filter(pk=movimento_id).exists()
        )
        self.assertFalse(LancamentoFinanceiro.objects.filter(pk=lancamento_id).exists())

