    def test_comando_sincronizar_entradas_fcf_dividas_recria_apos_restore(self):
        divida = DividaFinanceira.objects.create(
            descricao="Emprestimo restore",
            credor="Banco Restore",
            tipo="fornecedor",
            data_contratacao=date(2026, 5, 10),
            valor_contratado=Decimal("400.00"),
            quantidade_parcelas=2,
        )
        DividaFinanceira.objects.filter(pk=divida.pk).update(tipo="emprestimo")

        saida_dry_run = StringIO()
        call_command("sincronizar_entradas_fcf_dividas", stdout=saida_dry_run)

        self.assertIn("criadas=1", saida_dry_run.getvalue())
        self.assertFalse(
            FinanciamentoMovimentacao.objects.filter(divida_financeira=divida).exists()
        )

        saida_json = StringIO()
        call_command(
            "sincronizar_entradas_fcf_dividas",
            "--json",
            stdout=saida_json,
        )
        payload_json = json.loads(saida_json.getvalue())

        self.assertTrue(payload_json["readOnly"])
        self.assertEqual(payload_json["mode"], "dry-run")
        self.assertEqual(payload_json["checked"], 1)
        self.assertEqual(payload_json["created"], 1)
        self.assertEqual(payload_json["pendingCount"], 1)
        self.assertEqual(payload_json["pending"], [f"criar divida:{divida.id}"])
        self.assertEqual(payload_json["limit"], 20)
        self.assertEqual(payload_json["remainingIssues"], 1)
        self.assertFalse(payload_json["consistentAfter"])

        saida_limit_zero = StringIO()
        call_command(
            "sincronizar_entradas_fcf_dividas",
            "--json",
            "--limit=0",
            stdout=saida_limit_zero,
        )
        payload_limit_zero = json.loads(saida_limit_zero.getvalue())

        self.assertEqual(payload_limit_zero["pendingCount"], 1)
        self.assertEqual(payload_limit_zero["pending"], [])
        self.assertEqual(payload_limit_zero["limit"], 0)

        saida = StringIO()
        call_command(
            "sincronizar_entradas_fcf_dividas",
            "--aplicar",
            "--json",
            "--falhar-com-pendencia",
            stdout=saida,
        )
        payload_apply = json.loads(saida.getvalue())

        movimento = FinanciamentoMovimentacao.objects.get(divida_financeira=divida)
        self.assertEqual(movimento.valor_realizado, Decimal("400.00"))
        self.assertFalse(payload_apply["readOnly"])
        self.assertEqual(payload_apply["mode"], "apply")
        self.assertEqual(payload_apply["checked"], 1)
        self.assertEqual(payload_apply["created"], 1)
        self.assertEqual(payload_apply["remainingIssues"], 0)
        self.assertTrue(payload_apply["consistentAfter"])

    def test_comando_sincronizar_entradas_fcf_dividas_rejeita_limit_negativo(self):
        with self.assertRaisesMessage(CommandError, "--limit"):
            call_command(
                "sincronizar_entradas_fcf_dividas",
                "--limit=-1",
                stdout=StringIO(),
            )

