    def test_edicao_valores_diretos_substitui_valor_antigo_em_lancamentos_e_obrigacoes(self):
        criar_entrada_caixa_teste(valor=Decimal("1000.00"), data=date(2026, 5, 1))
        receita = ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita editavel",
            valor_previsto=Decimal("200.00"),
            valor_recebido=Decimal("50.00"),
            data_vencimento=date(2026, 5, 20),
            data_recebimento=date(2026, 5, 20),
        )
        despesa = DespesaOperacional.objects.create(
            evento=self.evento,
            descricao="Despesa editavel",
            categoria="material",
            valor_previsto=Decimal("100.00"),
            valor_pago=Decimal("20.00"),
            data_vencimento=date(2026, 5, 20),
            data_pagamento=date(2026, 5, 20),
        )
        custo_fixo = CustoFixo.objects.create(
            descricao="Custo fixo editavel",
            categoria="sistema",
            valor_previsto=Decimal("80.00"),
            valor_pago=Decimal("30.00"),
            data_vencimento=date(2026, 5, 20),
            data_pagamento=date(2026, 5, 20),
        )
        investimento = Investimento.objects.create(
            descricao="Investimento editavel",
            categoria="outros",
            tipo_fluxo="saida",
            valor_previsto=Decimal("120.00"),
            valor_realizado=Decimal("40.00"),
            data_prevista=date(2026, 5, 20),
            data_realizacao=date(2026, 5, 20),
        )
        financiamento = FinanciamentoMovimentacao.objects.create(
            descricao="Financiamento editavel",
            categoria="retirada_socio",
            tipo_fluxo="saida",
            valor_previsto=Decimal("110.00"),
            valor_realizado=Decimal("35.00"),
            data_prevista=date(2026, 5, 20),
            data_realizacao=date(2026, 5, 20),
        )

        receita.valor_previsto = Decimal("300.00")
        receita.valor_recebido = Decimal("70.00")
        receita.save()
        despesa.valor_previsto = Decimal("150.00")
        despesa.valor_pago = Decimal("40.00")
        despesa.save()
        custo_fixo.valor_previsto = Decimal("90.00")
        custo_fixo.valor_pago = Decimal("45.00")
        custo_fixo.save()
        investimento.valor_previsto = Decimal("160.00")
        investimento.valor_realizado = Decimal("60.00")
        investimento.save()
        financiamento.valor_previsto = Decimal("140.00")
        financiamento.valor_realizado = Decimal("55.00")
        financiamento.save()

        pares = [
            (
                receita,
                "receita_operacional",
                Decimal("300.00"),
                Decimal("70.00"),
                Decimal("230.00"),
            ),
            (
                despesa,
                "despesa_operacional",
                Decimal("150.00"),
                Decimal("40.00"),
                Decimal("110.00"),
            ),
            (
                custo_fixo,
                "custo_fixo",
                Decimal("90.00"),
                Decimal("45.00"),
                Decimal("45.00"),
            ),
            (
                investimento,
                "investimento",
                Decimal("160.00"),
                Decimal("60.00"),
                Decimal("100.00"),
            ),
            (
                financiamento,
                "financiamento_movimentacao",
                Decimal("140.00"),
                Decimal("55.00"),
                Decimal("85.00"),
            ),
        ]

        for objeto, campo_origem, previsto, realizado, pendente in pares:
            with self.subTest(campo_origem=campo_origem):
                obrigacao = ObrigacaoFinanceira.objects.get(**{campo_origem: objeto})
                lancamento = LancamentoFinanceiro.objects.get(**{campo_origem: objeto})
                self.assertEqual(obrigacao.valor_previsto, previsto)
                self.assertEqual(obrigacao.valor_realizado, realizado)
                self.assertEqual(obrigacao.valor_pendente, pendente)
                self.assertEqual(lancamento.valor, realizado)

        self.assertFalse(
            ObrigacaoFinanceira.objects.filter(valor_previsto__in=[
                Decimal("200.00"),
                Decimal("100.00"),
                Decimal("80.00"),
                Decimal("120.00"),
                Decimal("110.00"),
            ]).exists()
        )

