class ModelagemFinanceiraCanonicaTests(TestCase):
    def setUp(self):
        self.cliente = Cliente.objects.create(
            nome_razao_social="Cliente Modelagem Canonica",
            tipo_pessoa="PJ",
            cpf_cnpj="77.777.777/0001-77",
        )
        self.configuracao = ConfiguracaoFinanceira.objects.create(
            nome="Configuracao Modelagem Canonica",
            data_inicio_vigencia=date(2026, 1, 1),
        )
        self.orcamento = Orcamento.objects.create(
            cliente=self.cliente,
            configuracao_financeira=self.configuracao,
            numero="CTR-CANON-001",
            nome_evento="Evento Modelagem Canonica",
            data_evento=date(2026, 7, 10),
        )

        class ContratoVisual:
            id = None
            codigo = "CTR-CANON-001"
            nome = "Evento Modelagem Canonica"

            def __str__(self):
                return self.codigo

        self.contrato = ContratoVisual()
        self.evento = Evento.objects.create(
            cliente=self.cliente,
            orcamento=self.orcamento,
            numero="EVT-CTR-CANON-001",
            nome_evento="Evento Modelagem Canonica",
            data_inicio=date(2026, 7, 10),
            data_fim=date(2026, 7, 10),
        )

    def _rotas_modelagem_canonica(self):
        return (
            "api_modelagem_financeira_canonica",
            "api_canonical_financial_model",
        )

