    def test_obrigacao_financeira_registra_origem_unica_e_dimensoes(self):
        despesa = DespesaOperacional.objects.create(
            evento=self.evento,
            descricao="Despesa canonica",
            categoria="material",
            valor_previsto=Decimal("120.00"),
            data_vencimento=date(2026, 7, 10),
        )

        obrigacao = ObrigacaoFinanceira.objects.get(despesa_operacional=despesa)

        self.assertEqual(obrigacao.campos_origem_preenchidos(), ["despesa_operacional"])
        self.assertEqual(obrigacao.valor_pendente_pagamento, Decimal("120.00"))
        self.assertEqual(obrigacao.valor_pendente_recebimento, Decimal("0.00"))
        self.assertFalse(hasattr(obrigacao, "contrato_operacional_id"))
        self.assertEqual(obrigacao.evento_id, self.evento.id)

    def test_obrigacao_financeira_rejeita_origem_ausente_ou_dupla(self):
        receita = ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita canonica",
            valor_previsto=Decimal("100.00"),
            data_vencimento=date(2026, 7, 10),
        )
        despesa = DespesaOperacional.objects.create(
            evento=self.evento,
            descricao="Despesa canonica dupla",
            categoria="material",
            valor_previsto=Decimal("80.00"),
            data_vencimento=date(2026, 7, 10),
        )
        sem_origem = ObrigacaoFinanceira(
            tipo=ObrigacaoFinanceira.TIPO_RECEBER,
            origem="receita_operacional",
            fluxo=LancamentoFinanceiro.FLUXO_FCO,
            natureza=LancamentoFinanceiro.NATUREZA_RECEITA_OPERACIONAL,
            descricao="Obrigacao sem origem",
            data_vencimento=date(2026, 7, 10),
            valor_previsto=Decimal("100.00"),
        )
        origem_dupla = ObrigacaoFinanceira(
            tipo=ObrigacaoFinanceira.TIPO_RECEBER,
            origem="receita_operacional",
            fluxo=LancamentoFinanceiro.FLUXO_FCO,
            natureza=LancamentoFinanceiro.NATUREZA_RECEITA_OPERACIONAL,
            descricao="Obrigacao origem dupla",
            data_vencimento=date(2026, 7, 10),
            valor_previsto=Decimal("100.00"),
            receita_operacional=receita,
            despesa_operacional=despesa,
        )
        origem_inconsistente = ObrigacaoFinanceira(
            tipo=ObrigacaoFinanceira.TIPO_RECEBER,
            origem="despesa_operacional",
            fluxo=LancamentoFinanceiro.FLUXO_FCO,
            natureza=LancamentoFinanceiro.NATUREZA_RECEITA_OPERACIONAL,
            descricao="Obrigacao origem inconsistente",
            data_vencimento=date(2026, 7, 10),
            valor_previsto=Decimal("100.00"),
            receita_operacional=receita,
        )

        with self.assertRaises(ValidationError) as contexto_sem_origem:
            sem_origem.full_clean()
        with self.assertRaises(ValidationError) as contexto_origem_dupla:
            origem_dupla.full_clean()
        with self.assertRaises(ValidationError) as contexto_origem_inconsistente:
            origem_inconsistente.full_clean()

        self.assertIn("__all__", contexto_sem_origem.exception.message_dict)
        self.assertIn("__all__", contexto_origem_dupla.exception.message_dict)
        self.assertIn("origem", contexto_origem_inconsistente.exception.message_dict)

