    def test_comando_sincroniza_modelagem_canonica_com_modo_seguro(self):
        ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita comando canonico",
            valor_previsto=Decimal("150.00"),
            valor_recebido=Decimal("150.00"),
            data_vencimento=date(2026, 7, 10),
        )
        saida_simulacao = StringIO()
        saida_aplicacao = StringIO()

        call_command(
            "sincronizar_modelagem_financeira_canonica",
            stdout=saida_simulacao,
        )

        self.assertIn("Modo: somente leitura", saida_simulacao.getvalue())
        self.assertEqual(ObrigacaoFinanceira.objects.count(), 1)
        self.assertEqual(BaixaFinanceira.objects.count(), 1)
        self.assertEqual(BaixaFinanceiraAlocacao.objects.count(), 1)

        call_command(
            "sincronizar_modelagem_financeira_canonica",
            "--aplicar",
            stdout=saida_aplicacao,
        )

        self.assertIn("Modo: aplicacao", saida_aplicacao.getvalue())
        self.assertEqual(ObrigacaoFinanceira.objects.count(), 1)
        self.assertEqual(BaixaFinanceira.objects.count(), 1)
        self.assertEqual(BaixaFinanceiraAlocacao.objects.count(), 1)

    def test_comando_verifica_paridade_modelagem_canonica(self):
        ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita paridade canonica",
            valor_previsto=Decimal("150.00"),
            valor_recebido=Decimal("150.00"),
            data_vencimento=date(2026, 7, 10),
        )
        saida_consistente = StringIO()
        call_command(
            "sincronizar_modelagem_financeira_canonica",
            "--aplicar",
            stdout=StringIO(),
        )

        call_command(
            "verificar_paridade_modelagem_canonica",
            "--falhar",
            stdout=saida_consistente,
        )

        self.assertIn(
            "Paridade da modelagem financeira canonica consistente",
            saida_consistente.getvalue(),
        )

        obrigacao = ObrigacaoFinanceira.objects.get()
        obrigacao.valor_previsto = Decimal("140.00")
        obrigacao.save()
        saida_json = StringIO()

        call_command(
            "verificar_paridade_modelagem_canonica",
            "--json",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertFalse(payload["consistent"])
        self.assertEqual(payload["obrigacoes"]["divergent"], 1)
        self.assertEqual(payload["issues"][0]["tipo"], "obrigacao_divergente")
        with self.assertRaisesMessage(CommandError, "obrigacao_divergente"):
            call_command(
                "verificar_paridade_modelagem_canonica",
                "--falhar",
                stdout=StringIO(),
            )

    def test_api_modelagem_canonica_autenticacao_permissao_e_headers_em_ambas_rotas(self):
        anonimo = Client()

        for url_name in self._rotas_modelagem_canonica():
            with self.subTest(url_name=url_name, caso="anonimo"):
                response = anonimo.get(reverse(f"caixa:{url_name}"))

                self.assertEqual(response.status_code, 401)
                self.assertEqual(response["Content-Type"], "application/json")
                self.assertEqual(
                    response.json(),
                    {"detail": "Authentication credentials were not provided."},
                )
                self.assertIn("no-store", response["Cache-Control"])

            with self.subTest(url_name=url_name, caso="sem_permissao"):
                usuario_sem_permissao = User.objects.create_user(
                    username=f"{url_name}-sem-permissao",
                    password="senha-segura",
                )
                self.client.force_login(usuario_sem_permissao)
                response = self.client.get(reverse(f"caixa:{url_name}"))

                self.assertEqual(response.status_code, 403)
                self.assertEqual(response["Content-Type"], "application/json")
                self.assertEqual(response.json(), {"detail": "Permission denied."})
                self.assertIn("no-store", response["Cache-Control"])

            with self.subTest(url_name=url_name, caso="com_permissao"):
                usuario_com_permissao = self._usuario_com_permissao_modelagem_canonica(
                    username=f"{url_name}-com-permissao",
                )
                self.client.force_login(usuario_com_permissao)
                response = self.client.get(reverse(f"caixa:{url_name}"))

                self.assertEqual(response.status_code, 200)
                self.assertEqual(response["Content-Type"], "application/json")
                self.assertIn("no-store", response["Cache-Control"])
                self.assertTrue(response.json()["data"]["meta"]["readOnly"])

    def test_api_modelagem_canonica_metodos_nao_permitidos_preservam_405_em_ambas_rotas(self):
        for url_name in self._rotas_modelagem_canonica():
            url = reverse(f"caixa:{url_name}")
            for metodo in ("post", "put", "patch", "delete"):
                with self.subTest(url_name=url_name, metodo=metodo):
                    response = getattr(self.client, metodo)(
                        url,
                        data={},
                        content_type="application/json",
                    )

                    self.assertEqual(response.status_code, 405)
                    self.assertEqual(response["Allow"], "GET")
                    self.assertEqual(response.content, b"")
                    self.assertEqual(
                        response["Content-Type"],
                        "text/html; charset=utf-8",
                    )
                    self.assertNotIn("Cache-Control", response)

    def test_api_modelagem_canonica_preserva_shape_e_igualdade_funcional_das_rotas(self):
        ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita shape canonico",
            valor_previsto=Decimal("150.00"),
            valor_recebido=Decimal("150.00"),
            data_vencimento=date(2026, 7, 10),
        )
        usuario = self._usuario_com_permissao_modelagem_canonica(
            username="api-canonica-shape",
        )
        self.client.force_login(usuario)

        response_pt = self.client.get(
            reverse("caixa:api_modelagem_financeira_canonica"),
            {"limit": "5"},
        )
        response_en = self.client.get(
            reverse("caixa:api_canonical_financial_model"),
            {"limit": "5"},
        )
        payload_pt = response_pt.json()["data"]
        payload_en = response_en.json()["data"]
        payload_pt_normalizado = {
            **payload_pt,
            "meta": {**payload_pt["meta"], "generatedAt": "<generated>"},
        }
        payload_en_normalizado = {
            **payload_en,
            "meta": {**payload_en["meta"], "generatedAt": "<generated>"},
        }

        self.assertEqual(response_pt.status_code, 200)
        self.assertEqual(response_en.status_code, 200)
        self._assert_modelagem_canonica_shape(payload_pt)
        self._assert_modelagem_canonica_shape(payload_en)
        self.assertEqual(payload_pt_normalizado, payload_en_normalizado)
        self.assertEqual(
            payload_pt["synchronizationPreview"],
            payload_pt["syncPreview"],
        )
        self.assertFalse(payload_pt["synchronizationPreview"]["aplicar"])
        self.assertTrue(payload_pt["meta"]["readOnly"])
        self.assertEqual(payload_pt["meta"]["source"], "backend")
        self.assertEqual(payload_pt["meta"]["currency"], "BRL")
        self.assertEqual(payload_pt["parity"]["limit"], 5)
        self.assertTrue(payload_pt["status"]["readyForCanonicalReads"])
        self.assertTrue(payload_pt["status"]["hasCanonicalParity"])
        self.assertEqual(
            payload_pt["status"]["recommendedNextAction"],
            "ready_for_canonical_reads",
        )
        self.assertEqual(payload_pt["canonicalTotals"]["obligations"]["count"], 1)
        self.assertEqual(payload_pt["canonicalTotals"]["settlements"]["count"], 1)
        self.assertEqual(payload_pt["canonicalTotals"]["allocations"]["count"], 1)

    def test_api_modelagem_canonica_preserva_limit_issue_limit_e_limites(self):
        usuario = self._usuario_com_permissao_modelagem_canonica(
            username="api-canonica-limites",
        )
        self.client.force_login(usuario)
        url = reverse("caixa:api_modelagem_financeira_canonica")

        cenarios = (
            ({}, 20),
            ({"issueLimit": "7"}, 7),
            ({"limit": "5", "issueLimit": "7"}, 5),
            ({"limit": "0"}, 1),
            ({"limit": "999"}, 200),
            ({"limit": "invalido"}, 20),
        )

        for params, esperado in cenarios:
            with self.subTest(params=params):
                response = self.client.get(url, params)

                self.assertEqual(response.status_code, 200)
                self.assertEqual(response.json()["data"]["parity"]["limit"], esperado)

    def test_api_modelagem_canonica_get_preserva_dry_run_sem_aplicar_sincronizacao(self):
        ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita dry run canonico",
            valor_previsto=Decimal("180.00"),
            valor_recebido=Decimal("180.00"),
            data_vencimento=date(2026, 7, 10),
        )
        BaixaFinanceiraAlocacao.objects.all().delete()
        BaixaFinanceira.objects.all().delete()
        ObrigacaoFinanceira.objects.all().delete()
        usuario = self._usuario_com_permissao_modelagem_canonica(
            username="api-canonica-dry-run",
        )
        self.client.force_login(usuario)

        response = self.client.get(
            reverse("caixa:api_modelagem_financeira_canonica"),
            {"limit": "10"},
        )
        payload = response.json()["data"]

        self.assertEqual(response.status_code, 200)
        self.assertFalse(payload["synchronizationPreview"]["aplicar"])
        self.assertGreater(
            payload["synchronizationPreview"]["obrigacoes"]["criadas"],
            0,
        )
        self.assertGreater(payload["parity"]["obrigacoes"]["missing"], 0)
        self.assertEqual(ObrigacaoFinanceira.objects.count(), 0)
        self.assertEqual(BaixaFinanceira.objects.count(), 0)
        self.assertEqual(BaixaFinanceiraAlocacao.objects.count(), 0)

    def test_api_baixas_canonicas_autenticacao_permissao_e_headers_em_ambas_rotas(self):
        for rota in self._rotas_baixas_canonicas():
            with self.subTest(rota=rota, usuario="anonimo"):
                response = self.client.get(reverse(f"caixa:{rota}"), secure=True)

                self.assertEqual(response.status_code, 401)
                self._assert_json_no_store(response)
                self.assertEqual(
                    response.json(),
                    {"detail": "Authentication credentials were not provided."},
                )

        usuario_sem_permissao = User.objects.create_user(
            username="api-baixa-sem-permissao",
            password="senha-segura",
        )
        self.client.force_login(usuario_sem_permissao)

        for rota in self._rotas_baixas_canonicas():
            with self.subTest(rota=rota, usuario="sem-permissao"):
                response = self.client.get(reverse(f"caixa:{rota}"), secure=True)

                self.assertEqual(response.status_code, 403)
                self._assert_json_no_store(response)
                self.assertEqual(response.json(), {"detail": "Permission denied."})

        usuario_com_permissao = self._usuario_com_permissao_modelagem_canonica(
            username="api-baixa-com-permissao",
        )
        self.client.force_login(usuario_com_permissao)

        for rota in self._rotas_baixas_canonicas():
            with self.subTest(rota=rota, usuario="com-permissao"):
                response = self.client.get(reverse(f"caixa:{rota}"), secure=True)

                self.assertEqual(response.status_code, 200)
                self._assert_json_no_store(response)
                self._assert_baixas_canonicas_shape(response.json()["data"])

    def test_api_baixas_canonicas_metodos_nao_permitidos_preservam_405_em_ambas_rotas(self):
        for rota in self._rotas_baixas_canonicas():
            for metodo in ("post", "put", "patch", "delete"):
                with self.subTest(rota=rota, metodo=metodo):
                    response = getattr(self.client, metodo)(
                        reverse(f"caixa:{rota}"),
                        data={},
                        content_type="application/json",
                        secure=True,
                    )

                    self.assertEqual(response.status_code, 405)
                    self.assertEqual(response["Allow"], "GET")
                    self.assertEqual(response["Content-Type"], "text/html; charset=utf-8")
                    self.assertEqual(response.content, b"")
                    self.assertNotIn("Cache-Control", response)

