        self.assertEqual(payload_pt["summary"]["inflowAmount"], 170.0)
        self.assertEqual(payload_pt["summary"]["outflowAmount"], 0.0)
        self.assertEqual(payload_pt["summary"]["allocatedAmount"], 170.0)
