        self.assertEqual(payload_pt["filters"]["source"], "receita_operacional")
        self.assertEqual(payload_pt["filters"]["type"], "entrada")
        item = payload_pt["items"][0]
        alocacao = item["allocations"][0]
        self.assertEqual(item["source"], "receita_operacional")
        self.assertEqual(item["sourceId"], receita.id)
        self.assertEqual(item["amount"], 170.0)
        self.assertEqual(item["allocatedAmount"], 170.0)
        self.assertEqual(item["unallocatedAmount"], 0.0)
        self.assertEqual(item["contractCode"], self.contrato.codigo)
        self.assertEqual(item["eventId"], self.evento.id)
        self.assertEqual(item["cliente_id"], self.cliente.id)
        self.assertEqual(alocacao["source"], "receita_operacional")
        self.assertEqual(alocacao["sourceId"], receita.id)
        self.assertEqual(alocacao["allocatedAmount"], 170.0)

