    def test_api_modelagem_canonica_publica_status_para_next(self):
        ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita API canonica",
            valor_previsto=Decimal("150.00"),
            valor_recebido=Decimal("150.00"),
            data_vencimento=date(2026, 7, 10),
        )
        usuario = User.objects.create_user(
            username="api-canonica",
            password="senha-segura",
        )
        usuario.user_permissions.add(
            Permission.objects.get(codename="view_lancamentofinanceiro"),
            Permission.objects.get(codename="view_receitaoperacional"),
        )
        self.client.force_login(usuario)

        response_pendente = self.client.get(
            reverse("caixa:api_modelagem_financeira_canonica"),
            {"limit": "5"},
            secure=True,
        )
        payload_pendente = response_pendente.json()["data"]

        self.assertEqual(response_pendente.status_code, 200)
        self.assertIn("no-store", response_pendente["Cache-Control"])
        self.assertTrue(payload_pendente["meta"]["readOnly"])
        self.assertTrue(payload_pendente["status"]["readyForCanonicalReads"])
        self.assertEqual(
            payload_pendente["status"]["recommendedNextAction"],
            "ready_for_canonical_reads",
        )
        self.assertEqual(
            payload_pendente["synchronizationPreview"]["obrigacoes"]["atualizadas"],
            1,
        )
        self.assertIn(
            "obrigacaoFinanceira",
            payload_pendente["nomenclature"]["canonicalFields"],
        )
        self.assertEqual(payload_pendente["canonicalTotals"]["obligations"]["count"], 1)

        call_command(
            "sincronizar_modelagem_financeira_canonica",
            "--aplicar",
            stdout=StringIO(),
        )
        response_pronta = self.client.get(
            reverse("caixa:api_canonical_financial_model"),
            {"issueLimit": "5"},
            secure=True,
        )
        payload_pronto = response_pronta.json()["data"]

        self.assertEqual(response_pronta.status_code, 200)
        self.assertIn("no-store", response_pronta["Cache-Control"])
        self.assertTrue(payload_pronto["status"]["readyForCanonicalReads"])
        self.assertTrue(payload_pronto["status"]["hasCanonicalParity"])
        self.assertEqual(
            payload_pronto["status"]["recommendedNextAction"],
            "ready_for_canonical_reads",
        )
        self.assertEqual(payload_pronto["canonicalTotals"]["obligations"]["count"], 1)
        self.assertEqual(payload_pronto["canonicalTotals"]["settlements"]["count"], 1)
        self.assertEqual(payload_pronto["canonicalTotals"]["allocations"]["count"], 1)

