    def test_comando_auditar_fonte_escrita_baixas_agrupa_canonical_first(self):
        ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita auditoria fonte escrita",
            valor_previsto=Decimal("100.00"),
            valor_recebido=Decimal("100.00"),
            data_vencimento=date(2026, 7, 10),
        )
        BaixaFinanceira.objects.create(
            tipo="saida",
            fluxo=LancamentoFinanceiro.FLUXO_FCO,
            natureza=LancamentoFinanceiro.NATUREZA_DESPESA_OPERACIONAL,
            valor_total=Decimal("50.00"),
            data_baixa=date(2026, 7, 10),
            descricao="Baixa canonical-first auditada",
            fonte_escrita="canonicalFirst",
        )
        saida_json = StringIO()

        call_command(
            "auditar_fonte_escrita_baixas",
            "--data-ativacao=2026-07-01",
            "--data-final=2026-07-31",
            "--json",
            "--exigir-canonical-first",
            stdout=saida_json,
        )
        payload = json.loads(saida_json.getvalue())

        self.assertEqual(payload["count"], 2)
        self.assertEqual(payload["legacyAdapterSynced"]["count"], 1)
        self.assertEqual(payload["canonicalFirst"]["count"], 1)
        self.assertEqual(payload["canonicalFirst"]["outflowAmount"], 50.0)

        with TemporaryDirectory() as temp_dir:
            saida_evidencia_json = StringIO()
            call_command(
                "auditar_fonte_escrita_baixas",
                "--data-ativacao=2026-07-01",
                "--data-final=2026-07-31",
                "--write-model-source=canonicalFirst",
                f"--diretorio-evidencias={temp_dir}",
                "--exigir-arquivos-evidencia",
                "--json",
                "--exigir-canonical-first",
                stdout=saida_evidencia_json,
            )
            payload_evidencia = json.loads(saida_evidencia_json.getvalue())
            json_path = Path(payload_evidencia["evidenceFiles"]["json"])
            record_path = Path(payload_evidencia["evidenceFiles"]["record"])

            self.assertEqual(payload_evidencia["evidenceFiles"]["directory"], temp_dir)
            self.assertTrue(json_path.exists())
            self.assertTrue(record_path.exists())
            self.assertIn(
                "Registro PM-03 - auditoria de fonte de escrita",
                record_path.read_text(encoding="utf-8"),
            )
            self.assertIn(
                "Canonical-first: count=1",
                payload_evidencia["executionRecord"]["markdown"],
            )

        with self.assertRaisesMessage(CommandError, "arquivos de evidencia PM-03"):
            call_command(
                "auditar_fonte_escrita_baixas",
                "--exigir-arquivos-evidencia",
                stdout=StringIO(),
            )

        saida_filtrada_json = StringIO()
        call_command(
            "auditar_fonte_escrita_baixas",
            "--data-inicial=2026-07-01",
            "--data-final=2026-07-31",
            "--write-model-source=canonicalFirst",
            "--json",
            "--exigir-canonical-first",
            stdout=saida_filtrada_json,
        )
        payload_filtrado = json.loads(saida_filtrada_json.getvalue())

        self.assertEqual(payload_filtrado["count"], 1)
        self.assertEqual(payload_filtrado["filters"]["writeModelSource"], "canonicalFirst")
        self.assertEqual(payload_filtrado["legacyAdapterSynced"]["count"], 0)
        self.assertEqual(payload_filtrado["canonicalFirst"]["count"], 1)

        saida_alias_json = StringIO()
        call_command(
            "auditar_fonte_escrita_baixas",
            "--data-inicial=2026-07-01",
            "--data-final=2026-07-31",
            "--fonte-escrita=legacyAdapterSynced",
            "--json",
            stdout=saida_alias_json,
        )
        payload_alias = json.loads(saida_alias_json.getvalue())

        self.assertEqual(payload_alias["count"], 1)
        self.assertEqual(payload_alias["filters"]["writeModelSource"], "legacyAdapterSynced")
        self.assertEqual(payload_alias["legacyAdapterSynced"]["count"], 1)

        with self.assertRaisesMessage(CommandError, "Data de ativacao"):
            call_command(
                "auditar_fonte_escrita_baixas",
                "--exigir-canonical-first",
                "--exigir-data-ativacao",
                stdout=StringIO(),
            )

        with self.assertRaisesMessage(CommandError, "source=custo_fixo"):
            call_command(
                "auditar_fonte_escrita_baixas",
                "--data-inicial=2026-08-01",
                "--data-final=2026-08-31",
                "--source=custo_fixo",
                "--write-model-source=canonicalFirst",
                "--exigir-canonical-first",
                stdout=StringIO(),
            )

    def test_preflight_operacional_valida_modelagem_canonica_quando_solicitado(self):
        ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Receita preflight canonico",
            valor_previsto=Decimal("150.00"),
            valor_recebido=Decimal("150.00"),
            data_vencimento=date(2026, 7, 10),
        )
        ObrigacaoFinanceira.objects.all().delete()
        BaixaFinanceira.objects.all().delete()
        saida_sem_canonico = StringIO()

        call_command(
            "validar_operacao_obrigacoes",
            "--falhar",
            stdout=saida_sem_canonico,
        )

        self.assertIn("ambiente pronto", saida_sem_canonico.getvalue())
        self.assertIn(
            "Modelagem canonica: nao validada",
            saida_sem_canonico.getvalue(),
        )
        with self.assertRaisesMessage(CommandError, "obrigacao_ausente"):
            call_command(
                "validar_operacao_obrigacoes",
                "--validar-canonico",
                "--falhar",
                stdout=StringIO(),
            )

        call_command(
            "sincronizar_modelagem_financeira_canonica",
            "--aplicar",
            stdout=StringIO(),
        )
        saida_com_canonico = StringIO()
        call_command(
            "validar_operacao_obrigacoes",
            "--validar-canonico",
            "--falhar",
            stdout=saida_com_canonico,
        )

        self.assertIn("ambiente pronto", saida_com_canonico.getvalue())
        self.assertIn(
            "Modelagem canonica: paridade consistente",
            saida_com_canonico.getvalue(),
        )

    def test_api_obrigacoes_usa_modelagem_canonica_com_leitura_legada_segura(self):
        despesa = DespesaOperacional.objects.create(
            evento=self.evento,
            descricao="Despesa leitura canonica",
            categoria="material",
            valor_previsto=Decimal("120.00"),
            valor_pago=Decimal("0.00"),
            data_vencimento=date(2026, 7, 10),
        )
        ObrigacaoFinanceira.objects.all().delete()
        BaixaFinanceira.objects.all().delete()
        usuario = User.objects.create_user(
            username="api-obrigacao-canonica",
            password="senha-segura",
        )
        usuario.user_permissions.add(
            Permission.objects.get(codename="view_lancamentofinanceiro")
        )
        self.client.force_login(usuario)

        response_leitura_legada = self.client.get(
            reverse("caixa:api_obrigacoes_financeiras"),
            {"dataSource": "canonical"},
            secure=True,
        )
        payload_leitura_legada = response_leitura_legada.json()["data"]

        self.assertEqual(response_leitura_legada.status_code, 200)
        self.assertEqual(payload_leitura_legada["filters"]["dataSource"], "canonical")
        self.assertEqual(payload_leitura_legada["meta"]["dataSourceRequested"], "canonical")
        self.assertEqual(payload_leitura_legada["meta"]["dataSourceActual"], "legacy")
        self.assertEqual(
            payload_leitura_legada["meta"]["canonicalFallbackReason"],
            "missing_canonical_records",
        )
        self.assertEqual(
            payload_leitura_legada["meta"]["readModelStatusReason"],
            "missing_canonical_records",
        )
        status_leitura_legada = payload_leitura_legada["meta"]["readModelStatus"]
        self.assertEqual(status_leitura_legada["label"], "Leitura legada")
        self.assertEqual(
            status_leitura_legada["detail"],
            "modelagem canônica incompleta",
        )
        self.assertEqual(status_leitura_legada["tone"], "warning")
        self.assertEqual(
            status_leitura_legada["reason"],
            "missing_canonical_records",
        )
        self.assertEqual(status_leitura_legada["dataSourceRequested"], "canonical")
        self.assertEqual(status_leitura_legada["dataSourceActual"], "legacy")
        self.assertFalse(status_leitura_legada["canonicalReady"])
        self.assertEqual(
            payload_leitura_legada["meta"]["readModelStatusLabel"],
            "Leitura legada",
        )
        self.assertEqual(
            payload_leitura_legada["meta"]["readModelStatusDetail"],
            "modelagem canônica incompleta",
        )
        self.assertEqual(payload_leitura_legada["meta"]["readModelStatusTone"], "warning")
        diagnostico_leitura_legada = payload_leitura_legada["meta"][
            "readModelStatusDiagnostics"
        ]
        self.assertEqual(diagnostico_leitura_legada["requested"], "canonical")
        self.assertEqual(diagnostico_leitura_legada["actual"], "legacy")
        self.assertEqual(
            diagnostico_leitura_legada["legacyReadReason"],
            "missing_canonical_records",
        )
        self.assertEqual(
            diagnostico_leitura_legada["fallbackReason"],
            "missing_canonical_records",
        )
        self.assertFalse(diagnostico_leitura_legada["canonicalReady"])
        self.assertGreater(diagnostico_leitura_legada["missing"], 0)
        self.assertEqual(payload_leitura_legada["items"][0]["readModelSource"], "legacy")
        semantica_legada = payload_leitura_legada["meta"]["amountSemantics"]
        self.assertEqual(
            semantica_legada["version"],
            "financial-obligations-amount-semantics-v1",
        )
        self.assertEqual(semantica_legada["readModel"]["dataSourceActual"], "legacy")
        self.assertEqual(
            semantica_legada["readModel"]["fallbackReason"],
            "missing_canonical_records",
        )
        self.assertEqual(
            semantica_legada["aliases"]["contas_pendentes"],
            "pendingAmount",
        )

        call_command(
            "sincronizar_modelagem_financeira_canonica",
            "--aplicar",
            stdout=StringIO(),
        )
        response_canonica = self.client.get(
            reverse("caixa:api_obrigacoes_financeiras"),
            {"dataSource": "canonical"},
            secure=True,
        )
        payload_canonico = response_canonica.json()["data"]

        self.assertEqual(response_canonica.status_code, 200)
        self.assertEqual(payload_canonico["meta"]["dataSourceActual"], "canonical")
        self.assertEqual(
            payload_canonico["meta"]["readModelStatusLabel"],
            "Leitura: Modelagem canônica",
        )
        self.assertEqual(payload_canonico["meta"]["readModelStatusDetail"], "")
        self.assertEqual(payload_canonico["meta"]["readModelStatusTone"], "neutral")
        self.assertEqual(payload_canonico["meta"]["readModelStatusReason"], "")
        status_canonico = payload_canonico["meta"]["readModelStatus"]
        self.assertEqual(status_canonico["label"], "Leitura: Modelagem canônica")
        self.assertEqual(status_canonico["reason"], "")
        self.assertEqual(status_canonico["dataSourceRequested"], "canonical")
        self.assertEqual(status_canonico["dataSourceActual"], "canonical")
        self.assertTrue(status_canonico["canonicalReady"])
        self.assertTrue(
            payload_canonico["meta"]["canonicalReadiness"]["readyForCanonicalReads"]
        )
        diagnostico_canonico = payload_canonico["meta"]["readModelStatusDiagnostics"]
        self.assertEqual(diagnostico_canonico["requested"], "canonical")
        self.assertEqual(diagnostico_canonico["actual"], "canonical")
        self.assertEqual(diagnostico_canonico["legacyReadReason"], "")
        self.assertEqual(diagnostico_canonico["fallbackReason"], "")
        self.assertTrue(diagnostico_canonico["canonicalReady"])
        self.assertEqual(diagnostico_canonico["missing"], 0)
        self.assertEqual(diagnostico_canonico["divergent"], 0)
        self.assertEqual(diagnostico_canonico["extra"], 0)
        self.assertEqual(payload_canonico["pagination"]["total"], 1)
        self.assertEqual(payload_canonico["items"][0]["readModelSource"], "canonical")
        self.assertEqual(payload_canonico["items"][0]["source"], "despesa_operacional")
