        self.assertEqual(item_financiamento["plannedAmount"], 150.0)
        self.assertEqual(item_financiamento["realizedAmount"], 30.0)
        self.assertEqual(item_financiamento["pendingAmount"], 120.0)
        self.assertEqual(item_financiamento["pendingReceivableAmount"], 120.0)
        self.assertIsNone(item_financiamento["pendingPaymentAmount"])

        self.assertEqual(payload["summary"]["plannedAmount"], 650.0)
        self.assertEqual(payload["summary"]["realizedAmount"], 200.0)
        self.assertEqual(payload["summary"]["pendingAmount"], 450.0)

