    def test_aprovar_orcamento_nao_cria_entidade_de_contrato_separada(self):
        servico = Servico.objects.create(
            nome="Servico Sem Pasta Automatica",
            codigo="servico-sem-pasta-automatica",
            diaria_padrao=Decimal("100.00"),
        )
        orcamento = Orcamento.objects.create(
            cliente=self.cliente,
            configuracao_financeira=self.configuracao,
            numero="03685/25",
            nome_evento="Primeiro contrato",
            data_evento=date(2025, 12, 12),
        )
        OrcamentoItem.objects.create(
            orcamento=orcamento,
            servico=servico,
            horas_por_dia=8,
            quantidade_dias=1,
            quantidade_pessoas=1,
        )

        evento = orcamento.aprovar_e_gerar_evento()
