        self.assertEqual(payload["summary"]["draftCount"], 1)
        self.assertEqual(payload["filters"]["busca"], "Shape")
        self.assertEqual(payload["filters"]["search"], "Shape")
        self.assertEqual(payload["filters"]["status"], "rascunho")
        self.assertEqual(len(payload["budgets"]), 1)
        self._assert_budget_shape(payload["budgets"][0])
        self.assertTrue(payload["permissions"]["canCreate"])
        self.assertTrue(payload["permissions"]["canUpdate"])
        self.assertFalse(payload["permissions"]["canApprove"])

