    def test_api_orcamento_detalhe_edita_orcamento_antes_da_aprovacao(self):
        outro_servico = Servico.objects.create(
            nome="Recepcao API Orcamento",
            codigo="recepcao-api-orcamento",
            diaria_padrao=Decimal("120.00"),
            horas_base_diaria=8,
        )
        orcamento = Orcamento.objects.create(
            cliente=self.cliente,
            configuracao_financeira=self.configuracao,
            numero="ORC-API-EDIT",
            nome_evento="Evento API Editar",
            data_evento=date(2026, 5, 20),
            status="rascunho",
        )
        OrcamentoItem.objects.create(
            orcamento=orcamento,
            servico=self.servico,
            horas_por_dia=8,
            quantidade_dias=1,
            quantidade_pessoas=1,
        )
        valor_venda_original = orcamento.total_venda
        self.client.force_login(self.usuario)

        response = self._put_json(
            reverse("caixa:api_orcamento_detalhe", args=[orcamento.id]),
            self._payload(
                number="ORC-API-EDIT",
                eventName="Evento API Editado",
                status="enviado",
                items=[
                    {
                        "serviceId": outro_servico.id,
                        "hoursPerDay": 10,
                        "daysCount": 2,
                        "peopleCount": 3,
                        "dailyRateUsed": "150.00",
                        "mealAmountUsed": "22.00",
                        "transportAmountUsed": "18.00",
                        "profitMarginUsed": "0.35",
                        "taxRateUsed": "0.07",
                        "usesSpecialRule": True,
                    }
                ],
                extraCosts=[],
            ),
        )
        payload = response.json()["data"]
        orcamento.refresh_from_db()
        item = orcamento.itens.get()

        self.assertEqual(response.status_code, 200)
        self.assertEqual(payload["budget"]["eventName"], "Evento API Editado")
        self.assertEqual(orcamento.status, "enviado")
        self.assertEqual(item.servico_id, outro_servico.id)
        self.assertEqual(item.horas_por_dia, 10)
        self.assertEqual(item.quantidade_dias, 2)
        self.assertEqual(item.quantidade_pessoas, 3)
        self.assertEqual(item.valor_diaria_usada, Decimal("150.00"))
        self.assertEqual(item.valor_alimentacao_usado, Decimal("22.00"))
        self.assertEqual(item.valor_transporte_usado, Decimal("18.00"))
        self.assertEqual(item.margem_lucro_usada, Decimal("0.35"))
        self.assertEqual(item.aliquota_imposto_usada, Decimal("0.07"))
        self.assertTrue(item.usa_regra_especial)
        self.assertNotEqual(orcamento.total_venda, valor_venda_original)
        self.assertEqual(payload["budget"]["saleAmount"], f"{orcamento.total_venda:.2f}")
        self.assertEqual(orcamento.custos_extras.count(), 0)

        lista_response = self.client.get(reverse("caixa:api_orcamentos"), secure=True)
        lista_payload = lista_response.json()["data"]
        lista_orcamento = next(
            budget for budget in lista_payload["budgets"] if budget["id"] == orcamento.id
        )
        self.assertEqual(lista_orcamento["saleAmount"], f"{orcamento.total_venda:.2f}")
        self.assertEqual(lista_payload["summary"]["saleAmount"], f"{orcamento.total_venda:.2f}")

