        self.assertEqual(custos_extras[0].data_vencimento, date(2026, 5, 21))
        self.assertEqual(custos_extras[0].observacao, "Observacao editada.")
        self.assertEqual(custos_extras[1].categoria, "logistica")
        self.assertEqual(custos_extras[1].descricao, "Logistica adicionada")
        self.assertEqual(custos_extras[1].valor_previsto, Decimal("120.00"))
        self.assertEqual(payload["budget"]["extraCosts"][0]["description"], "Material editado")
        self.assertEqual(payload["budget"]["extraCosts"][1]["description"], "Logistica adicionada")

