    def test_api_aprovar_orcamento_preserva_auth_permissao_superuser_404_e_csrf(self):
        orcamento = self._criar_orcamento_com_item_e_custo_extra(
            numero="ORC-API-APROVAR-AUTH"
        )
        url = reverse("caixa:api_aprovar_orcamento", args=[orcamento.id])

        client_sem_csrf = Client(enforce_csrf_checks=True)
        superuser_sem_csrf = User.objects.create_superuser(
            username="api-aprovar-sem-csrf",
            password="senha-segura",
            email="api-aprovar-sem-csrf@example.com",
        )
        client_sem_csrf.force_login(superuser_sem_csrf)
        response_sem_csrf = client_sem_csrf.post(url, secure=True)
        orcamento.refresh_from_db()

        client_anonimo = Client(enforce_csrf_checks=True)
        token_anonimo = self._csrf_token(client_anonimo)
        response_anonimo = client_anonimo.post(url, HTTP_X_CSRFTOKEN=token_anonimo)

        usuario_sem_permissao = User.objects.create_user(
            username="api-aprovar-sem-permissao",
            password="senha-segura",
        )
        client_sem_permissao = Client(enforce_csrf_checks=True)
        client_sem_permissao.force_login(usuario_sem_permissao)
        token_sem_permissao = self._csrf_token(client_sem_permissao)
        response_sem_permissao = client_sem_permissao.post(
            url,
            HTTP_X_CSRFTOKEN=token_sem_permissao,
        )

        usuario_nao_superuser = self._usuario_com_permissoes(
            "api-aprovar-nao-superuser",
            "change_orcamento",
        )
        client_nao_superuser = Client(enforce_csrf_checks=True)
        client_nao_superuser.force_login(usuario_nao_superuser)
        token_nao_superuser = self._csrf_token(client_nao_superuser)
        response_nao_superuser = client_nao_superuser.post(
            url,
            HTTP_X_CSRFTOKEN=token_nao_superuser,
        )

        client_superuser = Client(enforce_csrf_checks=True)
        superuser = User.objects.create_superuser(
            username="api-aprovar-404",
            password="senha-segura",
            email="api-aprovar-404@example.com",
        )
        client_superuser.force_login(superuser)
        token_superuser = self._csrf_token(client_superuser)
        response_inexistente = client_superuser.post(
            reverse("caixa:api_aprovar_orcamento", args=[orcamento.id + 999]),
            HTTP_X_CSRFTOKEN=token_superuser,
        )

        self.assertEqual(response_sem_csrf.status_code, 403)
        self.assertEqual(orcamento.status, "rascunho")
        self.assertEqual(response_anonimo.status_code, 401)
        self.assertEqual(
            response_anonimo.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(response_anonimo)
        self.assertEqual(response_sem_permissao.status_code, 403)
        self.assertEqual(response_sem_permissao.json(), {"detail": "Permission denied."})
        self._assert_json_no_store(response_sem_permissao)
        self.assertEqual(response_nao_superuser.status_code, 400)
        self.assertEqual(
            response_nao_superuser.json(),
            {"detail": "Apenas superusuários podem aprovar orçamentos por esta tela."},
        )
        self._assert_json_no_store(response_nao_superuser)
        self._assert_django_404_padrao(response_inexistente)

    def test_api_aprovar_orcamento_preserva_content_type_json_invalido_sucesso_e_efeitos(self):
        orcamento_form = self._criar_orcamento_com_item_e_custo_extra(
            numero="ORC-API-APROVAR-FORM"
        )
        orcamento_json_invalido = self._criar_orcamento_com_item_e_custo_extra(
            numero="ORC-API-APROVAR-JSON-INVALIDO"
        )
        client = Client(enforce_csrf_checks=True)
        superuser = User.objects.create_superuser(
            username="api-aprovar-content-type",
            password="senha-segura",
            email="api-aprovar-content-type@example.com",
        )
        client.force_login(superuser)
        csrf_token = self._csrf_token(client)

        response_form = client.post(
            reverse("caixa:api_aprovar_orcamento", args=[orcamento_form.id]),
            data="payload=ignorado",
            content_type="application/x-www-form-urlencoded",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        response_json_invalido = client.post(
            reverse("caixa:api_aprovar_orcamento", args=[orcamento_json_invalido.id]),
            data='{"payload":',
            content_type="application/json",
            HTTP_X_CSRFTOKEN=csrf_token,
        )
        orcamento_json_invalido.refresh_from_db()
        evento = Evento.objects.get(orcamento=orcamento_json_invalido)
        payload = response_json_invalido.json()["data"]

        self.assertEqual(response_form.status_code, 200)
        self._assert_json_no_store(response_form)
        self.assertEqual(response_json_invalido.status_code, 200)
        self._assert_json_no_store(response_json_invalido)
        self.assertEqual(set(payload), {"budget", "event", "message"})
        self._assert_budget_shape(payload["budget"])
        self.assertEqual(payload["budget"]["status"], "aprovado")
        self.assertEqual(set(payload["event"]), {"id", "contract", "number", "name"})
        self.assertEqual(payload["event"]["id"], evento.id)
        self.assertEqual(payload["event"]["contract"], "ORC-API-APROVAR-JSON-INVALIDO")
        self.assertEqual(payload["event"]["number"], "EVT-ORC-API-APROVAR-JSON-INVALIDO")
        self.assertEqual(payload["event"]["name"], "Evento API Shape")
        self.assertEqual(
            payload["message"],
            (
                "Contrato ORC-API-APROVAR-JSON-INVALIDO aprovado. "
                "Evento ORC-API-APROVAR-JSON-INVALIDO gerado/atualizado."
            ),
        )
        self.assertEqual(orcamento_json_invalido.status, "aprovado")
        self.assertTrue(ReceitaOperacional.objects.filter(evento=evento).exists())
        self.assertTrue(DespesaOperacional.objects.filter(evento=evento).exists())
        self.assertTrue(EventoCustoServico.objects.filter(evento=evento).exists())
        self.assertTrue(EventoCustoExtra.objects.filter(evento=evento).exists())
        self.assertTrue(
            OrcamentoCustoExtra.objects.filter(
                orcamento=orcamento_json_invalido,
                evento_custo_extra__evento=evento,
            ).exists()
        )

