    def test_api_aprovar_orcamento_metodos_nao_permitidos_preservam_405_e_allow(self):
        orcamento = self._criar_orcamento_com_item_e_custo_extra(
            numero="ORC-API-APROVAR-METODOS"
        )
        url = reverse("caixa:api_aprovar_orcamento", args=[orcamento.id])

        for metodo in ["get", "put", "patch", "delete"]:
            with self.subTest(metodo=metodo):
                if metodo == "get":
                    response = self.client.get(url, secure=True)
                else:
                    response = getattr(self.client, metodo)(
                        url,
                        data='{"payload":',
                        content_type="application/json",
                        secure=True,
                    )

                self.assertEqual(response.status_code, 405)
                self.assertEqual(response["Allow"], "POST")

