        methods = [
            self.client.post,
            self.client.put,
            self.client.patch,
            self.client.delete,
        ]

        for method in methods:
            with self.subTest(method=method.__name__):
                response = method(
                    url,
                    data={},
                    content_type="application/json",
                    secure=True,
                )

                self.assertEqual(response.status_code, 405)
                self.assertEqual(response["Allow"], "GET")

