    def test_api_receita_detalhe_put_preserva_aliases_campos_ignorados_shape_e_efeitos(self):
        usuario_change = self._usuario_com_permissoes_caixa(
            "api-receita-detalhe-aliases",
            "change_receitaoperacional",
        )
        client, csrf_headers = self._csrf_client_for_user(usuario_change)
        url = self._url()

        response = client.put(
            url,
            data=json.dumps(
                {
                    "valor_previsto": "1400.00",
                    "recebido": True,
                    "valor_recebido": "600.00",
                    "data_recebimento": "2026-05-27",
                    "observacao": "Atualizada por alias legado.",
                    "description": "Descricao ignorada",
                    "dueDate": "2026-06-30",
                    "paymentMethod": "pix",
                    "eventId": self.evento.id + 999,
                    "clientId": self.cliente.id + 999,
                }
            ),
            content_type="application/json",
            **csrf_headers,
        )

        self.assertEqual(response.status_code, 200, response.content[:200])
        self._assert_json_no_store(response)
        data = response.json()["data"]
        self.assertEqual(set(data), {"revenue", "message"})
        self.assertEqual(data["message"], "Receita atualizada com sucesso.")
        self.receita.refresh_from_db()
        self._assert_receita_api_fields(data["revenue"], self.receita)
        self.assertEqual(self.receita.descricao, "Receita API Original")
        self.assertEqual(self.receita.valor_previsto, Decimal("1400.00"))
        self.assertEqual(self.receita.valor_recebido, Decimal("600.00"))
        self.assertEqual(self.receita.data_vencimento, date(2026, 5, 25))
        self.assertEqual(self.receita.data_recebimento, date(2026, 5, 27))
        self.assertEqual(self.receita.status, "parcial")
        self.assertEqual(self.receita.observacao, "Atualizada por alias legado.")
        self.assertEqual(self.receita.forma_pagamento, "")
        self.assertEqual(self.receita.evento_id, self.evento.id)
        self.assertEqual(self.receita.cliente_id, self.cliente.id)

        lancamento = LancamentoFinanceiro.objects.get(receita_operacional=self.receita)
        obrigacao = ObrigacaoFinanceira.objects.get(receita_operacional=self.receita)
        baixa = BaixaFinanceira.objects.get(receita_operacional=self.receita)
        self.assertEqual(lancamento.valor, Decimal("600.00"))
        self.assertEqual(lancamento.data_lancamento, date(2026, 5, 27))
        self.assertEqual(obrigacao.valor_previsto, Decimal("1400.00"))
        self.assertEqual(obrigacao.valor_realizado, Decimal("600.00"))
        self.assertEqual(obrigacao.valor_pendente, Decimal("800.00"))
        self.assertEqual(baixa.valor_total, Decimal("600.00"))
        self.assertEqual(
            LancamentoFinanceiro.objects.filter(receita_operacional=self.receita).count(),
            1,
        )
        self.assertEqual(
            ObrigacaoFinanceira.objects.filter(receita_operacional=self.receita).count(),
            1,
        )
        self.assertEqual(
            BaixaFinanceira.objects.filter(receita_operacional=self.receita).count(),
            1,
        )

        resposta_limpeza = client.put(
            url,
            data=json.dumps({"received": False}),
            content_type="application/json",
            **csrf_headers,
        )

        self.assertEqual(resposta_limpeza.status_code, 200, resposta_limpeza.content[:200])
        self.receita.refresh_from_db()
        self.assertEqual(self.receita.valor_recebido, Decimal("0.00"))
        self.assertIsNone(self.receita.data_recebimento)
        self.assertEqual(self.receita.status, "pendente")
        self.assertFalse(
            LancamentoFinanceiro.objects.filter(receita_operacional=self.receita).exists()
        )
        obrigacao.refresh_from_db()
        self.assertEqual(obrigacao.valor_realizado, Decimal("0.00"))
        self.assertEqual(obrigacao.valor_pendente, Decimal("1400.00"))
        self.assertFalse(
            BaixaFinanceira.objects.filter(receita_operacional=self.receita).exists()
        )

    def test_api_receita_detalhe_metodos_nao_permitidos_preservam_405(self):
        url = self._url()

        for method_name in ("post", "patch", "delete"):
            with self.subTest(method=method_name):
                response = getattr(self.client, method_name)(url)

                self.assertEqual(response.status_code, 405)
                self.assertEqual(response["Allow"], "GET, PUT")
                self.assertTrue(response["Content-Type"].startswith("text/html"))

