class DespesasApiTests(TestCase):
    def setUp(self):
        self.cliente = Cliente.objects.create(
            nome_razao_social="Cliente API Despesa",
            nome_fantasia="Cliente Despesa",
            tipo_pessoa="PJ",
            cpf_cnpj="88.888.888/0001-88",
        )
        self.evento = Evento.objects.create(
            cliente=self.cliente,
            numero="EVT-API-DESPESA",
            nome_evento="Evento API Despesa",
            data_inicio=date(2026, 5, 20),
            data_fim=date(2026, 5, 20),
        )
        self.caixa_disponivel = ReceitaOperacional.objects.create(
            evento=self.evento,
            cliente=self.cliente,
            descricao="Caixa para teste de despesa",
            valor_previsto=Decimal("5000.00"),
            valor_recebido=Decimal("5000.00"),
            data_vencimento=date(2026, 5, 1),
            data_recebimento=date(2026, 5, 1),
        )
        self.despesa = DespesaOperacional.objects.create(
            evento=self.evento,
            descricao="Despesa API Original",
            categoria="outros",
            valor_previsto=Decimal("300.00"),
            valor_pago=Decimal("0.00"),
            data_vencimento=date(2026, 5, 25),
        )
        self.usuario = User.objects.create_user(
            username="api-despesas",
            password="senha-segura",
        )
        self.usuario.user_permissions.add(
            Permission.objects.get(
                content_type__app_label="caixa",
                codename="view_despesaoperacional",
            )
        )

    def _put_json(self, url, payload):
        return self.client.put(
            url,
            data=json.dumps(payload),
            content_type="application/json",
        )

    def _url(self, despesa=None):
        return reverse(
            "caixa:api_despesa_detalhe",
            args=[(despesa or self.despesa).id],
        )

    def _usuario_com_permissoes_caixa(self, username, *codenames):
        usuario = User.objects.create_user(username=username, password="senha-segura")
        for codename in codenames:
            usuario.user_permissions.add(
                Permission.objects.get(
                    content_type__app_label="caixa",
                    codename=codename,
                )
            )
        return usuario

    def _csrf_client_for_user(self, user=None):
        client = Client(enforce_csrf_checks=True)
        if user is not None:
            client.force_login(user)
        csrf_token = "d" * 32
        client.cookies[settings.CSRF_COOKIE_NAME] = csrf_token
        return client, {"HTTP_X_CSRFTOKEN": csrf_token}

    def _assert_json_no_store(self, response):
        self.assertEqual(response["Content-Type"], "application/json")
        self.assertIn("no-store", response["Cache-Control"])

    def _assert_django_404_padrao(self, response):
        self.assertEqual(response.status_code, 404)
        self.assertTrue(response["Content-Type"].startswith("text/html"))

    def _assert_despesa_api_fields(self, payload, despesa):
        self.assertEqual(
            set(payload),
            {
                "id",
                "description",
                "category",
                "categoryLabel",
                "plannedAmount",
                "paidAmount",
                "pendingPaymentAmount",
                "dueDate",
                "paymentDate",
                "status",
                "statusLabel",
                "paymentMethod",
                "manuallySettled",
                "settlementReason",
                "notes",
                "eventId",
                "eventLabel",
                "eventNumber",
                "clientId",
                "clientName",
                "contractCode",
                "contractLabel",
                "createdAt",
                "updatedAt",
            },
        )
        self.assertEqual(payload["id"], despesa.id)
        self.assertEqual(payload["description"], despesa.descricao)
        self.assertEqual(payload["category"], despesa.categoria)
        self.assertEqual(payload["categoryLabel"], despesa.get_categoria_display())
        self.assertEqual(payload["plannedAmount"], f"{despesa.valor_previsto:.2f}")
        self.assertEqual(payload["paidAmount"], f"{despesa.valor_pago:.2f}")
        self.assertEqual(
            payload["pendingPaymentAmount"],
            f"{despesa.valor_pendente_pagamento:.2f}",
        )
        self.assertEqual(
            payload["dueDate"],
            despesa.data_vencimento.isoformat() if despesa.data_vencimento else "",
        )
        self.assertEqual(
            payload["paymentDate"],
            despesa.data_pagamento.isoformat() if despesa.data_pagamento else "",
        )
        self.assertEqual(payload["status"], despesa.status)
        self.assertEqual(payload["statusLabel"], despesa.get_status_display())
        self.assertEqual(payload["paymentMethod"], despesa.forma_pagamento)
        self.assertEqual(payload["manuallySettled"], despesa.baixado_manualmente)
        self.assertEqual(payload["settlementReason"], despesa.motivo_baixa)
        self.assertEqual(payload["notes"], despesa.observacao)
        self.assertEqual(payload["eventId"], despesa.evento_id)
        self.assertEqual(payload["eventLabel"], despesa.evento.nome_evento)
        self.assertEqual(payload["eventNumber"], despesa.evento.numero)
        self.assertEqual(payload["clientId"], despesa.evento.cliente_id)
        self.assertEqual(payload["clientName"], despesa.evento.cliente.nome_razao_social)
        self.assertIn("T", payload["createdAt"])
        self.assertIn("T", payload["updatedAt"])

    def _despesa_nao_manual(self):
        despesa = DespesaOperacional.objects.create(
            evento=self.evento,
            descricao="Despesa API Sincronizada",
            categoria="material",
            valor_previsto=Decimal("80.00"),
            valor_pago=Decimal("0.00"),
            data_vencimento=date(2026, 5, 30),
        )
        DespesaOperacional.objects.filter(pk=despesa.pk).update(
            origem=DespesaOperacional.ORIGEM_CUSTO_EXTRA,
        )
        despesa.refresh_from_db()
        return despesa

    def test_api_despesa_detalhe_exige_autenticacao_e_permissao(self):
        response_sem_login = self.client.get(
            reverse("caixa:api_despesa_detalhe", args=[self.despesa.id])
        )

        usuario_sem_permissao = User.objects.create_user(
            username="api-despesas-sem-permissao",
            password="senha-segura",
        )
        self.client.force_login(usuario_sem_permissao)
        response_sem_permissao = self.client.get(
            reverse("caixa:api_despesa_detalhe", args=[self.despesa.id])
        )

        self.assertEqual(response_sem_login.status_code, 401)
        self.assertEqual(response_sem_permissao.status_code, 403)
        self.assertEqual(
            response_sem_login.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(response_sem_login)
        self.assertEqual(response_sem_permissao.json(), {"detail": "Permission denied."})
        self._assert_json_no_store(response_sem_permissao)

    def test_api_despesa_detalhe_get_preserva_shape_permissoes_headers_e_404(self):
        despesa_nao_manual = self._despesa_nao_manual()
        usuario_view = self._usuario_com_permissoes_caixa(
            "api-despesa-detalhe-view",
            "view_despesaoperacional",
        )
        usuario_view_change = self._usuario_com_permissoes_caixa(
            "api-despesa-detalhe-view-change",
            "view_despesaoperacional",
            "change_despesaoperacional",
        )
        usuario_super = User.objects.create_superuser(
            username="api-despesa-detalhe-super",
            email="api-despesa-detalhe-super@example.com",
            password="senha-segura",
        )
        url = self._url()
        url_inexistente = reverse("caixa:api_despesa_detalhe", args=[self.despesa.id + 999])

        client_view = Client()
        client_view.force_login(usuario_view)
        resposta_view = client_view.get(url)
        client_view_change = Client()
        client_view_change.force_login(usuario_view_change)
        resposta_view_change = client_view_change.get(url)
        client_super = Client()
        client_super.force_login(usuario_super)
        resposta_super = client_super.get(url)
        resposta_inexistente = client_view.get(url_inexistente)
        resposta_nao_manual = client_view.get(self._url(despesa_nao_manual))

        self.assertEqual(resposta_view.status_code, 200)
        self._assert_json_no_store(resposta_view)
        data_view = resposta_view.json()["data"]
        self.assertEqual(set(data_view), {"expense", "permissions", "meta"})
        self._assert_despesa_api_fields(data_view["expense"], self.despesa)
        self.assertEqual(
            data_view["permissions"],
            {
                "canView": True,
                "canUpdate": False,
                "canManageInAdmin": False,
            },
        )
        self.assertEqual(data_view["meta"], {"source": "backend"})

        self.assertEqual(resposta_view_change.status_code, 200)
        data_view_change = resposta_view_change.json()["data"]
        self.assertEqual(data_view_change["permissions"]["canView"], True)
        self.assertEqual(data_view_change["permissions"]["canUpdate"], True)
        self.assertEqual(data_view_change["permissions"]["canManageInAdmin"], False)

        self.assertEqual(resposta_super.status_code, 200)
        data_super = resposta_super.json()["data"]
        self.assertEqual(data_super["permissions"]["canManageInAdmin"], True)

        self._assert_django_404_padrao(resposta_inexistente)
        self._assert_django_404_padrao(resposta_nao_manual)

    def test_api_despesa_detalhe_put_preserva_csrf_auth_permissao_404_e_origem_manual(self):
        despesa_nao_manual = self._despesa_nao_manual()
        url = self._url()
        url_inexistente = reverse("caixa:api_despesa_detalhe", args=[self.despesa.id + 999])
        payload = {"plannedAmount": "600.00", "paid": True}
        usuario_change = self._usuario_com_permissoes_caixa(
            "api-despesa-detalhe-change-csrf",
            "change_despesaoperacional",
        )
        usuario_apenas_view = self._usuario_com_permissoes_caixa(
            "api-despesa-detalhe-apenas-view",
            "view_despesaoperacional",
        )

        client_sem_csrf = Client(enforce_csrf_checks=True)
        client_sem_csrf.force_login(usuario_change)
        resposta_sem_csrf = client_sem_csrf.put(
            url,
            data=json.dumps(payload),
            content_type="application/json",
        )

        client_anonimo, csrf_anonimo = self._csrf_client_for_user()
        resposta_anonimo = client_anonimo.put(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            **csrf_anonimo,
        )

        client_apenas_view, csrf_apenas_view = self._csrf_client_for_user(
            usuario_apenas_view
        )
        resposta_apenas_view = client_apenas_view.put(
            url,
            data=json.dumps(payload),
            content_type="application/json",
            **csrf_apenas_view,
        )

        client_change, csrf_change = self._csrf_client_for_user(usuario_change)
        resposta_inexistente = client_change.put(
            url_inexistente,
            data=json.dumps(payload),
            content_type="application/json",
            **csrf_change,
        )
        resposta_nao_manual = client_change.put(
            self._url(despesa_nao_manual),
            data=json.dumps(payload),
            content_type="application/json",
            **csrf_change,
        )

        self.despesa.refresh_from_db()
        despesa_nao_manual.refresh_from_db()
        self.assertEqual(resposta_sem_csrf.status_code, 403)
        self.assertTrue(resposta_sem_csrf["Content-Type"].startswith("text/html"))
        self.assertEqual(self.despesa.valor_previsto, Decimal("300.00"))
        self.assertEqual(self.despesa.valor_pago, Decimal("0.00"))
        self.assertEqual(despesa_nao_manual.valor_previsto, Decimal("80.00"))
        self.assertEqual(resposta_anonimo.status_code, 401)
        self.assertEqual(
            resposta_anonimo.json(),
            {"detail": "Authentication credentials were not provided."},
        )
        self._assert_json_no_store(resposta_anonimo)
        self.assertEqual(resposta_apenas_view.status_code, 403)
        self.assertEqual(resposta_apenas_view.json(), {"detail": "Permission denied."})
        self._assert_json_no_store(resposta_apenas_view)
        self._assert_django_404_padrao(resposta_inexistente)
        self._assert_django_404_padrao(resposta_nao_manual)

    def test_api_despesa_detalhe_put_erros_de_payload_preservam_contrato(self):
        usuario_change = self._usuario_com_permissoes_caixa(
            "api-despesa-detalhe-erros",
            "change_despesaoperacional",
        )
        client = Client()
        client.force_login(usuario_change)
        url = self._url()

        resposta_content_type = client.put(
            url,
            data="sem-json",
            content_type="text/plain",
        )
        resposta_json_invalido = client.put(
            url,
            data="{",
            content_type="application/json",
        )
        resposta_nao_dict = client.put(
            url,
            data=json.dumps(["lista"]),
            content_type="application/json",
        )

        self.assertEqual(resposta_content_type.status_code, 415)
        self.assertEqual(
            resposta_content_type.json(),
            {"detail": "Content-Type deve ser application/json."},
        )
        self._assert_json_no_store(resposta_content_type)
        self.assertEqual(resposta_json_invalido.status_code, 400)
        self.assertEqual(resposta_json_invalido.json(), {"detail": "JSON invalido."})
        self._assert_json_no_store(resposta_json_invalido)
        self.assertEqual(resposta_nao_dict.status_code, 400)
        self.assertEqual(resposta_nao_dict.json(), {"detail": "JSON invalido."})
        self._assert_json_no_store(resposta_nao_dict)

        casos = [
            ("valor_previsto_negativo", {"plannedAmount": "-1.00"}, "plannedAmount"),
            ("valor_previsto_invalido", {"plannedAmount": "abc"}, "plannedAmount"),
            (
                "valor_pago_negativo",
                {"paid": True, "paidAmount": "-1.00"},
                "paidAmount",
            ),
            ("paid_invalido", {"paid": "talvez"}, "paid"),
            (
                "data_pagamento_invalida",
                {"paid": True, "paymentDate": "nao-e-data"},
                "paymentDate",
            ),
        ]

        for nome, payload, campo in casos:
            with self.subTest(nome=nome):
                resposta = client.put(
                    url,
                    data=json.dumps(payload),
                    content_type="application/json",
                )

                self.assertEqual(resposta.status_code, 400, resposta.content[:200])
                self._assert_json_no_store(resposta)
                self.assertEqual(set(resposta.json()), {"errors"})
                self.assertIn(campo, resposta.json()["errors"])

