    def test_api_despesa_detalhe_put_preserva_aliases_campos_ignorados_shape_e_efeitos(self):
        usuario_change = self._usuario_com_permissoes_caixa(
            "api-despesa-detalhe-aliases",
            "change_despesaoperacional",
        )
        client, csrf_headers = self._csrf_client_for_user(usuario_change)
        url = self._url()

        response = client.put(
            url,
            data=json.dumps(
                {
                    "valor_previsto": "480.00",
                    "pago": True,
                    "valor_pago": "200.00",
                    "data_pagamento": "2026-05-27",
                    "observacao": "Atualizada por alias legado.",
                    "description": "Descricao ignorada",
                    "category": "material",
                    "dueDate": "2026-06-30",
                    "paymentMethod": "pix",
                    "status": "cancelado",
                    "manuallySettled": True,
                    "settlementReason": "Ignorado",
                    "eventId": self.evento.id + 999,
                    "clientId": self.cliente.id + 999,
                }
            ),
            content_type="application/json",
            **csrf_headers,
        )

        self.assertEqual(response.status_code, 200, response.content[:200])
        self._assert_json_no_store(response)
        data = response.json()["data"]
        self.assertEqual(set(data), {"expense", "message"})
        self.assertEqual(data["message"], "Despesa atualizada com sucesso.")
        self.despesa.refresh_from_db()
        self._assert_despesa_api_fields(data["expense"], self.despesa)
        self.assertEqual(self.despesa.descricao, "Despesa API Original")
        self.assertEqual(self.despesa.categoria, "outros")
        self.assertEqual(self.despesa.valor_previsto, Decimal("480.00"))
        self.assertEqual(self.despesa.valor_pago, Decimal("200.00"))
        self.assertEqual(self.despesa.data_vencimento, date(2026, 5, 25))
        self.assertEqual(self.despesa.data_pagamento, date(2026, 5, 27))
        self.assertEqual(self.despesa.status, "parcial")
        self.assertEqual(self.despesa.observacao, "Atualizada por alias legado.")
        self.assertEqual(self.despesa.forma_pagamento, "")
        self.assertFalse(self.despesa.baixado_manualmente)
        self.assertEqual(self.despesa.motivo_baixa, "")
        self.assertEqual(self.despesa.evento_id, self.evento.id)

        lancamento = LancamentoFinanceiro.objects.get(despesa_operacional=self.despesa)
        obrigacao = ObrigacaoFinanceira.objects.get(despesa_operacional=self.despesa)
        baixa = BaixaFinanceira.objects.get(despesa_operacional=self.despesa)
        self.assertEqual(lancamento.valor, Decimal("200.00"))
        self.assertEqual(lancamento.data_lancamento, date(2026, 5, 27))
        self.assertEqual(obrigacao.valor_previsto, Decimal("480.00"))
        self.assertEqual(obrigacao.valor_realizado, Decimal("200.00"))
        self.assertEqual(obrigacao.valor_pendente, Decimal("280.00"))
        self.assertEqual(baixa.valor_total, Decimal("200.00"))
        self.assertEqual(
            LancamentoFinanceiro.objects.filter(despesa_operacional=self.despesa).count(),
            1,
        )
        self.assertEqual(
            ObrigacaoFinanceira.objects.filter(despesa_operacional=self.despesa).count(),
            1,
        )
        self.assertEqual(
            BaixaFinanceira.objects.filter(despesa_operacional=self.despesa).count(),
            1,
        )

        resposta_limpeza = client.put(
            url,
            data=json.dumps({"paid": False}),
            content_type="application/json",
            **csrf_headers,
        )

        self.assertEqual(resposta_limpeza.status_code, 200, resposta_limpeza.content[:200])
        self.despesa.refresh_from_db()
        self.assertEqual(self.despesa.valor_pago, Decimal("0.00"))
        self.assertIsNone(self.despesa.data_pagamento)
        self.assertEqual(self.despesa.status, "pendente")
        self.assertFalse(
            LancamentoFinanceiro.objects.filter(despesa_operacional=self.despesa).exists()
        )
        obrigacao.refresh_from_db()
        self.assertEqual(obrigacao.valor_realizado, Decimal("0.00"))
        self.assertEqual(obrigacao.valor_pendente, Decimal("480.00"))
        self.assertFalse(
            BaixaFinanceira.objects.filter(despesa_operacional=self.despesa).exists()
        )

    def test_api_despesa_detalhe_metodos_nao_permitidos_preservam_405(self):
        url = self._url()

        for method_name in ("post", "patch", "delete"):
            with self.subTest(method=method_name):
                response = getattr(self.client, method_name)(url)

                self.assertEqual(response.status_code, 405)
                self.assertEqual(response["Allow"], "GET, PUT")
                self.assertTrue(response["Content-Type"].startswith("text/html"))

    def test_api_despesa_detalhe_edita_valor_e_marca_pago_com_permissao(self):
        self.usuario.user_permissions.add(
            Permission.objects.get(
                content_type__app_label="caixa",
                codename="change_despesaoperacional",
            )
        )
        self.client.force_login(self.usuario)

        response = self._put_json(
            reverse("caixa:api_despesa_detalhe", args=[self.despesa.id]),
            {
                "plannedAmount": "450.00",
                "paid": True,
                "paymentDate": "2026-05-26",
            },
        )
        payload = response.json()["data"]
        self.despesa.refresh_from_db()

        self.assertEqual(response.status_code, 200)
        self.assertEqual(self.despesa.valor_previsto, Decimal("450.00"))
        self.assertEqual(self.despesa.valor_pago, Decimal("450.00"))
        self.assertEqual(self.despesa.data_pagamento, date(2026, 5, 26))
        self.assertEqual(self.despesa.status, "pago")
        self.assertEqual(payload["expense"]["plannedAmount"], "450.00")
        self.assertEqual(payload["expense"]["paidAmount"], "450.00")
        self.assertEqual(payload["message"], "Despesa atualizada com sucesso.")

    def test_api_despesa_detalhe_marca_nao_pago_com_permissao(self):
        self.despesa.valor_pago = Decimal("300.00")
        self.despesa.data_pagamento = date(2026, 5, 26)
        self.despesa.status = "pago"
        self.despesa.save()
        self.usuario.user_permissions.add(
            Permission.objects.get(
                content_type__app_label="caixa",
                codename="change_despesaoperacional",
            )
        )
        self.client.force_login(self.usuario)

        response = self._put_json(
            reverse("caixa:api_despesa_detalhe", args=[self.despesa.id]),
            {
                "plannedAmount": "280.00",
                "paid": False,
            },
        )
        self.despesa.refresh_from_db()

        self.assertEqual(response.status_code, 200)
        self.assertEqual(self.despesa.valor_previsto, Decimal("280.00"))
        self.assertEqual(self.despesa.valor_pago, Decimal("0.00"))
        self.assertIsNone(self.despesa.data_pagamento)
        self.assertEqual(self.despesa.status, "pendente")

    def test_api_despesa_detalhe_bloqueia_edicao_sem_change(self):
        self.client.force_login(self.usuario)

        response = self._put_json(
            reverse("caixa:api_despesa_detalhe", args=[self.despesa.id]),
            {
                "plannedAmount": "600.00",
                "paid": True,
            },
        )
        self.despesa.refresh_from_db()

        self.assertEqual(response.status_code, 403)
        self.assertEqual(self.despesa.valor_previsto, Decimal("300.00"))
        self.assertEqual(self.despesa.valor_pago, Decimal("0.00"))
